const book: BibleBook = {
  id: 'judges',
  name: 'Juízes',
  englishName: 'Judges',
  testament: 'old',
  chapters: {
    1: [
      { v: 1, en: 'After the death of Joshua, the children of Israel asked of Yahweh, saying, “Who should go up for us first against the Canaanites, to fight against them?”', pt: 'Depois da morte de Josué os filhos de Israel consultaram ao Senhor, dizendo: Quem dentre nós subirá primeiro aos cananeus, para pelejar contra eles?' },
      { v: 2, en: 'Yahweh said, “Judah shall go up. Behold, I have delivered the land into his hand.”', pt: 'Respondeu o Senhor: Judá subirá; eis que entreguei a terra na sua mão.' },
      { v: 3, en: 'Judah said to Simeon his brother, “Come up with me into my lot, that we may fight against the Canaanites; and I likewise will go with you into your lot.” So Simeon went with him.', pt: 'Então disse Judá a Simeão, seu irmão: sobe comigo à sorte que me coube, e pelejemos contra os cananeus, e eu também subirei contigo à tua sorte. E Simeão foi com ele.' },
      { v: 4, en: 'Judah went up, and Yahweh delivered the Canaanites and the Perizzites into their hand. They struck ten thousand men in Bezek.', pt: 'Subiu, pois, Judá; e o Senhor lhes entregou nas mãos os cananeus e os perizeus; e bateram deles em Bezeque dez mil homens.' },
      { v: 5, en: 'They found Adoni-Bezek in Bezek, and they fought against him. They struck the Canaanites and the Perizzites.', pt: 'Acharam em Bezeque a Adoni-Bezeque, e pelejaram contra ele; e bateram os cananeus e os perizeus.' },
      { v: 6, en: 'But Adoni-Bezek fled. They pursued him, caught him, and cut off his thumbs and his big toes.', pt: 'Mas Adoni-Bezeque fugiu; porém eles o perseguiram e, prendendo-o, cortaram-lhe os dedos polegares das mãos e dos pés.' },
      { v: 7, en: 'Adoni-Bezek said, “Seventy kings, having their thumbs and their big toes cut off, scavenged under my table. As I have done, so God has done to me.” They brought him to Jerusalem, and he died there.', pt: 'Então disse Adoni-Bezeque: Setenta reis, com os dedos polegares das mãos e dos pés cortados, apanhavam as migalhas debaixo da minha mesa; assim como eu fiz, assim Deus me pagou. E o trouxeram a Jerusalém, e ali morreu.' },
      { v: 8, en: 'The children of Judah fought against Jerusalem, took it, struck it with the edge of the sword, and set the city on fire.', pt: 'Ora, os filhos de Judá pelejaram contra Jerusalém e, tomando-a, passaram-na ao fio da espada e puseram fogo à cidade.' },
      { v: 9, en: 'After that, the children of Judah went down to fight against the Canaanites who lived in the hill country, and in the South, and in the lowland.', pt: 'Depois os filhos de Judá desceram a pelejar contra os cananeus que habitavam na região montanhosa, e no Negebe, e na baixada.' },
      { v: 10, en: 'Judah went against the Canaanites who lived in Hebron. (The name of Hebron before that was Kiriath Arba.) They struck Sheshai, Ahiman, and Talmai.', pt: 'Então partiu Judá contra os cananeus que habitavam em Hebrom, cujo nome era outrora Quiriate-Arba; e bateu Sesai, Aimã e Talmai.' },
      { v: 11, en: 'From there he went against the inhabitants of Debir. (The name of Debir before that was Kiriath Sepher.)', pt: 'Dali partiu contra os moradores de Debir, que se chamava outrora Quiriate-Sefer.' },
      { v: 12, en: 'Caleb said, “I will give Achsah my daughter as wife to the man who strikes Kiriath Sepher, and takes it.”', pt: 'Disse então Calebe: A quem atacar Quiriate-Sefer e a tomar, darei a minha filha Acsa por mulher.' },
      { v: 13, en: 'Othniel the son of Kenaz, Caleb’s younger brother, took it, so he gave him Achsah his daughter as his wife.', pt: 'E tomou-a Otniel, filho de Quenaz, o irmão mais moço de Calebe; e este lhe deu sua filha Acsa por mulher.' },
      { v: 14, en: 'When she came, she got him to ask her father for a field. She got off her donkey; and Caleb said to her, “What would you like?”', pt: 'Estando ela em caminho para a casa de Otniel, persuadiu-o que pedisse um campo ao pai dela. E quando ela saltou do jumento, Calebe lhe perguntou: Que é que tens?' },
      { v: 15, en: 'She said to him, “Give me a blessing; because you have set me in the land of the South, give me also springs of water.” Then Caleb gave her the upper springs and the lower springs.', pt: 'Ela lhe respondeu: Dá-me um presente; porquanto me deste uma terra no Negebe, dá-me também fontes d\'água. Deu-lhe, pois, Calebe as fontes superiores e as fontes inferiores.' },
      { v: 16, en: 'The children of the Kenite, Moses’ brother-in-law, went up out of the city of palm trees with the children of Judah into the wilderness of Judah, which is in the south of Arad; and they went and lived with the people.', pt: 'Também os filhos do queneu, sogro de Moisés, subiram da cidade das palmeiras com os filhos de Judá ao deserto de Judá, que está ao sul de Arade; e foram habitar com o povo.' },
      { v: 17, en: 'Judah went with Simeon his brother, and they struck the Canaanites who inhabited Zephath, and utterly destroyed it. The name of the city was called Hormah.', pt: 'E Judá foi com Simeão, seu irmão, e derrotaram os cananeus que habitavam em Zefate, e a destruíram totalmente. E chamou-se o nome desta cidade Horma.' },
      { v: 18, en: 'Also Judah took Gaza with its border, and Ashkelon with its border, and Ekron with its border.', pt: 'Judá tomou também a Gaza, a Asquelom e a Ecrom, com os seus respectivos territórios.' },
      { v: 19, en: 'Yahweh was with Judah; and drove out the inhabitants of the hill country; for he could not drive out the inhabitants of the valley, because they had chariots of iron.', pt: 'Assim estava o Senhor com Judá, o qual se apoderou da região montanhosa; mas não pôde desapossar os habitantes do vale, porquanto tinham carros de ferro.' },
      { v: 20, en: 'They gave Hebron to Caleb, as Moses had said, and he drove the three sons of Anak out of there.', pt: 'E como Moisés dissera, deram Hebrom a Calebe, que dali expulsou os três filhos de Anaque.' },
      { v: 21, en: 'The children of Benjamin did not drive out the Jebusites who inhabited Jerusalem, but the Jebusites dwell with the children of Benjamin in Jerusalem to this day.', pt: 'Mas os filhos de Benjamim não expulsaram aos jebuseus que habitavam em Jerusalém; pelo que estes ficaram habitando com os filhos de Benjamim em Jerusalém até o dia de hoje.' },
      { v: 22, en: 'The house of Joseph also went up against Bethel, and Yahweh was with them.', pt: 'Também os da casa de José subiram contra Betel; e o Senhor estava com eles.' },
      { v: 23, en: 'The house of Joseph sent to spy out Bethel. (The name of the city before that was Luz.)', pt: 'E a casa de José fez espiar a Betel (e fora outrora o nome desta cidade Luz);' },
      { v: 24, en: 'The watchers saw a man come out of the city, and they said to him, “Please show us the entrance into the city, and we will deal kindly with you.”', pt: 'e, vendo os espias a um homem que saía da cidade, disseram-lhe: Mostra-nos a entrada da cidade, e usaremos de bondade para contigo.' },
      { v: 25, en: 'He showed them the entrance into the city, and they struck the city with the edge of the sword; but they let the man and all his family go.', pt: 'Mostrou-lhes, pois, a entrada da cidade, a qual eles feriram ao fio da espada; porém deixaram livre aquele homem e toda a sua família.' },
      { v: 26, en: 'The man went into the land of the Hittites, built a city, and called its name Luz, which is its name to this day.', pt: 'Então o homem se foi para a terra dos heteus, edificou uma cidade, e pôs-lhe o nome de Luz; este é o seu nome até o dia de hoje.' },
      { v: 27, en: 'Manasseh did not drive out the inhabitants of Beth Shean and its towns, nor Taanach and its towns, nor the inhabitants of Dor and its towns, nor the inhabitants of Ibleam and its towns, nor the inhabitants of Megiddo and its towns; but the Canaanites would dwell in that land.', pt: 'Manassés não expulsou os habitantes de Bete-Seã e suas vilas, nem os de Taanaque e suas virael aos levitas estas cidades e nem os de Ibleão e suas vilas, nem os de Megido e suas vilas; porém os cananeus persistiram em habitar naquela terra.' },
      { v: 28, en: 'When Israel had grown strong, they put the Canaanites to forced labor, and did not utterly drive them out.', pt: 'Mas quando Israel se tornou forte, sujeitou os cananeus a trabalhos forçados, porém não os expulsou de todo.' },
      { v: 29, en: 'Ephraim didn’t drive out the Canaanites who lived in Gezer, but the Canaanites lived in Gezer among them.', pt: 'Também Efraim não expulsou os cananeus que habitavam em Gezer; mas os cananeus ficaram habitando no meio dele, em Gezer.' },
      { v: 30, en: 'Zebulun didn’t drive out the inhabitants of Kitron, nor the inhabitants of Nahalol; but the Canaanites lived among them, and became subject to forced labor.', pt: 'Também Zebulom não expulsou os habitantes de Quitrom, nem os de Naalol; porém os cananeus ficaram habitando no meio dele, e foram sujeitos a trabalhos forçados.' },
      { v: 31, en: 'Asher didn’t drive out the inhabitants of Acco, nor the inhabitants of Sidon, nor of Ahlab, nor of Achzib, nor of Helbah, nor of Aphik, nor of Rehob;', pt: 'Também Aser não expulsou os habitantes de Aco, nem de Sidom, nem de Alabe, nem de Aczibe, nem de Helba, nem de Afeca, nem de Reobe;' },
      { v: 32, en: 'but the Asherites lived among the Canaanites, the inhabitants of the land; for they did not drive them out.', pt: 'porém os aseritas ficaram habitando no meio dos cananeus, os habitantes da terra, porquanto não os expulsaram.' },
      { v: 33, en: 'Naphtali didn’t drive out the inhabitants of Beth Shemesh, nor the inhabitants of Beth Anath; but he lived among the Canaanites, the inhabitants of the land. Nevertheless the inhabitants of Beth Shemesh and of Beth Anath became subject to forced labor.', pt: 'Também Naftali não expulsou os habitantes de Bete-Semes, nem os de Bete-Anate; mas, habitou no meio dos cananeus, os habitantes da terra; todavia os habitantes de Bete-Semes e os de Bete-Anate foram sujeitos a trabalhos forçados.' },
      { v: 34, en: 'The Amorites forced the children of Dan into the hill country, for they would not allow them to come down to the valley;', pt: 'Os amorreus impeliram os filhos de Dã até a região montanhosa; pois não lhes permitiram descer ao vale.' },
      { v: 35, en: 'but the Amorites would dwell in Mount Heres, in Aijalon, and in Shaalbim. Yet the hand of the house of Joseph prevailed, so that they became subject to forced labor.', pt: 'Os amorreus quiseram também habitar no monte Heres, em Aijalom e em Saalabim; contudo prevaleceu a mão da casa de José, de modo que eles ficaram sujeitos a trabalhos forçados.' },
      { v: 36, en: 'The border of the Amorites was from the ascent of Akrabbim, from the rock, and upward.', pt: 'E foi o termo dos amorreus desde a subida de Acrabim, desde Sela, e dali para cima.' },
    ],
    2: [
      { v: 1, en: 'Yahweh’s angel came up from Gilgal to Bochim. He said, “I brought you out of Egypt, and have brought you to the land which I swore to give your fathers. I said, ‘I will never break my covenant with you.', pt: 'O anjo do Senhor subiu de Gilgal a Boquim, e disse: Do Egito vos fiz subir, e vos trouxe para a terra que, com juramento, prometi a vossos pais, e vos disse: Nunca violarei e meu pacto convosco;' },
      { v: 2, en: 'You shall make no covenant with the inhabitants of this land. You shall break down their altars.’ But you have not listened to my voice. Why have you done this?', pt: 'e, quanto a vós, não fareis pacto com os habitantes desta terra, antes derrubareis os seus altares. Mas vós não obedecestes à minha voz. Por que fizestes isso?' },
      { v: 3, en: 'Therefore I also said, ‘I will not drive them out from before you; but they shall be in your sides, and their gods will be a snare to you.’”', pt: 'Pelo que também eu disse: Não os expulsarei de diante de vós; antes estarão quais espinhos nas vossas ilhargas, e os seus deuses vos serão por laço.' },
      { v: 4, en: 'When Yahweh’s angel spoke these words to all the children of Israel, the people lifted up their voice, and wept.', pt: 'Tendo o anjo do Senhor falado estas palavras a todos os filhos de Israel, o povo levantou a sua voz e chorou.' },
      { v: 5, en: 'They called the name of that place Bochim, and they sacrificed there to Yahweh.', pt: 'Pelo que chamaram àquele lugar Boquim; e ali sacrificaram ao Senhor.' },
      { v: 6, en: 'Now when Joshua had sent the people away, the children of Israel each went to his inheritance to possess the land.', pt: 'Havendo Josué despedido o povo, foram-se os filhos de Israel, cada um para a sua herança, a fim de possuírem a terra.' },
      { v: 7, en: 'The people served Yahweh all the days of Joshua, and all the days of the elders who outlived Joshua, who had seen all the great work of Yahweh that he had worked for Israel.', pt: 'O povo serviu ao Senhor todos os dias de Josué, e todos os dias dos anciãos que sobreviveram a Josué e que tinham visto toda aquela grande obra do Senhor, a qual ele fizera a favor de Israel.' },
      { v: 8, en: 'Joshua the son of Nun, the servant of Yahweh, died, being one hundred ten years old.', pt: 'Morreu, porém, Josué, filho de Num, servo do Senhor, com a idade de cento e dez anos;' },
      { v: 9, en: 'They buried him in the border of his inheritance in Timnath Heres, in the hill country of Ephraim, on the north of the mountain of Gaash.', pt: 'e o sepultaram no território da sua herança, em Timnate-Heres, na região montanhosa de Efraim, para o norte do monte Gaás.' },
      { v: 10, en: 'After all that generation were gathered to their fathers, another generation arose after them, who didn’t know Yahweh, nor the work which he had done for Israel.', pt: 'E foi também congregada toda aquela geração a seus pais, e após ela levantou-se outra geração que não conhecia ao Senhor, nem tampouco a obra que ele fizera a Israel.' },
      { v: 11, en: 'The children of Israel did that which was evil in Yahweh’s sight, and served the Baals.', pt: 'Então os filhos de Israel fizeram o que era mau aos olhos do Senhor, servindo aos baalins;' },
      { v: 12, en: 'They abandoned Yahweh, the God of their fathers, who brought them out of the land of Egypt, and followed other gods, of the gods of the peoples who were around them, and bowed themselves down to them; and they provoked Yahweh to anger.', pt: 'abandonaram o Senhor Deus de seus pais, que os tirara da terra do Egito, e foram-se após outros deuses, dentre os deuses dos povos que havia ao redor deles, e os adoraram; e provocaram o Senhor à ira,' },
      { v: 13, en: 'They abandoned Yahweh, and served Baal and the Ashtaroth.', pt: 'abandonando-o, e servindo a baalins e astarotes.' },
      { v: 14, en: 'Yahweh’s anger burned against Israel, and he delivered them into the hands of raiders who plundered them. He sold them into the hands of their enemies all around, so that they could no longer stand before their enemies.', pt: 'Pelo que a ira do Senhor se acendeu contra Israel, e ele os entregou na mão dos espoliadores, que os despojaram; e os vendeu na mão dos seus inimigos ao redor, de modo que não puderam mais resistir diante deles.' },
      { v: 15, en: 'Wherever they went out, Yahweh’s hand was against them for evil, as Yahweh had spoken, and as Yahweh had sworn to them; and they were very distressed.', pt: 'Por onde quer que saíam, a mão do Senhor era contra eles para o mal, como o Senhor tinha dito, e como lho tinha jurado; e estavam em grande aflição.' },
      { v: 16, en: 'Yahweh raised up judges, who saved them out of the hand of those who plundered them.', pt: 'Mas o Senhor suscitou juízes, que os livraram da mão dos que os espojavam.' },
      { v: 17, en: 'Yet they didn’t listen to their judges; for they prostituted themselves to other gods, and bowed themselves down to them. They quickly turned away from the way in which their fathers walked, obeying Yahweh’s commandments. They didn’t do so.', pt: 'Contudo, não deram ouvidos nem aos seus juízes, pois se prostituíram após outros deuses, e os adoraram; depressa se desviaram do caminho, por onde andaram seus pais em obediência aos mandamentos do Senhor; não fizeram como eles.' },
      { v: 18, en: 'When Yahweh raised up judges for them, then Yahweh was with the judge, and saved them out of the hand of their enemies all the days of the judge; for it grieved Yahweh because of their groaning by reason of those who oppressed them and troubled them.', pt: 'Quando o Senhor lhes suscitava juízes, ele era com o juiz, e os livrava da mão dos seus inimigos todos os dias daquele juiz; porquanto o Senhor se compadecia deles em razão do seu gemido por causa dos que os oprimiam e afligiam.' },
      { v: 19, en: 'But when the judge was dead, they turned back, and dealt more corruptly than their fathers in following other gods to serve them, and to bow down to them. They didn’t cease what they were doing, or give up their stubborn ways.', pt: 'Mas depois da morte do juiz, reincidiam e se corrompiam mais do que seus pais, andando após outros deuses, servindo-os e adorando-os; não abandonavam nenhuma das suas práticas, nem a sua obstinação.' },
      { v: 20, en: 'Yahweh’s anger burned against Israel; and he said, “Because this nation transgressed my covenant which I commanded their fathers, and has not listened to my voice,', pt: 'Pelo que se acendeu contra Israel a ira do Senhor, e ele disse: Porquanto esta nação violou o meu pacto, que estabeleci com seus pais, não dando ouvidos à minha voz,' },
      { v: 21, en: 'I also will no longer drive out any of the nations that Joshua left when he died from before them;', pt: 'eu não expulsarei mais de diante deles nenhuma das nações que Josué deixou quando morreu;' },
      { v: 22, en: 'that by them I may test Israel, to see if they will keep Yahweh’s way to walk therein, as their fathers kept it, or not.”', pt: 'a fim de que, por elas, ponha a prova Israel, se há de guardar, ou não, o caminho do Senhor, como seus pais o guardaram, para nele andar.' },
      { v: 23, en: 'So Yahweh left those nations, without driving them out hastily. He didn’t deliver them into Joshua’s hand.', pt: 'Assim o Senhor deixou ficar aquelas nações, e não as desterrou logo, nem as entregou na mão de Josué.' },
    ],
    3: [
      { v: 1, en: 'Now these are the nations which Yahweh left, to test Israel by them, even as many as had not known all the wars of Canaan;', pt: 'Estas são as nações que o Senhor deixou ficar para, por meio delas, provar a Israel, a todos os que não haviam experimentado nenhuma das guerras de Canaã;' },
      { v: 2, en: 'only that the generations of the children of Israel might know, to teach them war, at least those who knew nothing of it before:', pt: 'tão-somente para que as gerações dos filhos de Israel delas aprendessem a guerra, pelo menos os que dantes não tinham aprendido.' },
      { v: 3, en: 'the five lords of the Philistines, all the Canaanites, the Sidonians, and the Hivites who lived on Mount Lebanon, from Mount Baal Hermon to the entrance of Hamath.', pt: 'Estas nações eram: cinco chefes dos filisteus, todos os cananeus, os sidônios, e os heveus que habitavam no monte Líbano, desde o monte Baal-Hermom até a entrada de Hamate.' },
      { v: 4, en: 'They were left to test Israel by them, to know whether they would listen to Yahweh’s commandments, which he commanded their fathers by Moses.', pt: 'Estes, pois, deixou ficar, a fim de de por eles provar os filhos de Israel, para saber se dariam ouvidos aos mandamentos do Senhor, que ele tinha ordenado a seus pais por intermédio de Moisés.' },
      { v: 5, en: 'The children of Israel lived among the Canaanites, the Hittites, the Amorites, the Perizzites, the Hivites, and the Jebusites.', pt: 'Habitando, pois, os filhos de Israel entre os cananeus, os heteus, os amorreus, os perizeus, os heveus e os jebuseus.' },
      { v: 6, en: 'They took their daughters to be their wives, and gave their own daughters to their sons and served their gods.', pt: 'tomaram por mulheres as filhas deles, e deram as suas filhas aos filhos dos mesmos, e serviram aos seus deuses.' },
      { v: 7, en: 'The children of Israel did that which was evil in Yahweh’s sight, and forgot Yahweh their God, and served the Baals and the Asheroth.', pt: 'Assim os filhos de Israel fizeram o que era mau aos olhos do Senhor, esquecendo-se do Senhor seu Deus e servindo aos baalins e às aserotes.' },
      { v: 8, en: 'Therefore Yahweh’s anger burned against Israel, and he sold them into the hand of Cushan Rishathaim king of Mesopotamia; and the children of Israel served Cushan Rishathaim eight years.', pt: 'Pelo que a ira do Senhor se acendeu contra Israel, e ele os vendeu na mão de cusã-Risataim, rei da Mesopotâmia; e os filhos de Israel serviram a Cusã-Risataim oito anos.' },
      { v: 9, en: 'When the children of Israel cried to Yahweh, Yahweh raised up a savior to the children of Israel, who saved them, even Othniel the son of Kenaz, Caleb’s younger brother.', pt: 'Mas quando os filhos de Israel clamaram ao Senhor, o Senhor suscitou-lhes um libertador, que os livrou: Otniel, filho de Quenaz, o irmão mais moço de Calebe.' },
      { v: 10, en: 'Yahweh’s Spirit came on him, and he judged Israel; and he went out to war, and Yahweh delivered Cushan Rishathaim king of Mesopotamia into his hand. His hand prevailed against Cushan Rishathaim.', pt: 'Veio sobre ele o Espírito do Senhor, e ele julgou a Israel; saiu à peleja, e o Senhor lhe entregou Cusã-Risataim, rei da Mesopotâmia, contra o qual prevaleceu a sua mao:' },
      { v: 11, en: 'The land had rest forty years, then Othniel the son of Kenaz died.', pt: 'Então a terra teve sossego por quarenta anos; e Otniel, filho de Quenaz, morreu.' },
      { v: 12, en: 'The children of Israel again did that which was evil in Yahweh’s sight, and Yahweh strengthened Eglon the king of Moab against Israel, because they had done that which was evil in Yahweh’s sight.', pt: 'Os filhos de Israel tornaram a fazer o que era mau aos olhos do Senhor; então o Senhor fortaleceu a Eglom, rei de Moabe, contra Israel, por terem feito o que era mau aos seus olhos.' },
      { v: 13, en: 'He gathered the children of Ammon and Amalek to himself; and he went and struck Israel, and they possessed the city of palm trees.', pt: 'Eglom, unindo a si os amonitas e os amalequitas, foi e feriu a Israel, tomando a cidade das palmeiras.' },
      { v: 14, en: 'The children of Israel served Eglon the king of Moab eighteen years.', pt: 'E os filhos de Israel serviram a Eglom, rei de Moabe, dezoito anos.' },
      { v: 15, en: 'But when the children of Israel cried to Yahweh, Yahweh raised up a savior for them, Ehud the son of Gera, the Benjamite, a left-handed man. The children of Israel sent tribute by him to Eglon the king of Moab.', pt: 'Mas quando os filhos de Israel clamaram ao Senhor, o Senhor suscitou-lhes um libertador, Eúde, filho de Gêra, benjamita, homem canhoto. E, por seu intermédio, os filhos de Israel enviaram tributo a Eglom, rei de Moabe.' },
      { v: 16, en: 'Ehud made himself a sword which had two edges, a cubit in length; and he wore it under his clothing on his right thigh.', pt: 'E Eúde fez para si uma espada de dois gumes, de um côvado de comprimento, e cingiu-a à coxa direita, por baixo das vestes.' },
      { v: 17, en: 'He offered the tribute to Eglon king of Moab. Now Eglon was a very fat man.', pt: 'E levou aquele tributo a Eglom, rei de Moabe. Ora, Eglom era muito gordo:' },
      { v: 18, en: 'When he had finished offering the tribute, he sent away the people who carried the tribute.', pt: 'Quando Eúde acabou de entregar o tributo, despediu a gente que o trouxera.' },
      { v: 19, en: 'But he himself turned back from the stone idols that were by Gilgal, and said, “I have a secret message for you, O king.” The king said, “Keep silence!” All who stood by him left him.', pt: 'Ele mesmo, porém, voltou das imagens de escultura que estavam ao pé de Gilgal, e disse: Tenho uma palavra para dizer-te em segredo, ó rei. Disse o rei: Silêncio! E todos os que lhe assistiam saíram da sua presença.' },
      { v: 20, en: 'Ehud came to him; and he was sitting by himself alone in the cool upper room. Ehud said, “I have a message from God to you.” He arose out of his seat.', pt: 'Eúde aproximou-se do rei, que estava sentado a sós no seu quarto de verão, e lhe disse: Tenho uma palavra da parte de Deus para dizer-te. Ao que o rei se levantou da sua cadeira.' },
      { v: 21, en: 'Ehud put out his left hand, and took the sword from his right thigh, and thrust it into his body:', pt: 'Então Eúde, estendendo a mão esquerda, tirou a espada de sobre a coxa direita, e lha cravou no ventre.' },
      { v: 22, en: 'and the handle also went in after the blade; and the fat closed on the blade, for he didn’t draw the sword out of his body; and it came out behind.', pt: 'O cabo também entrou após a lâmina, e a gordura encerrou a lâmina, pois ele não tirou a espada do ventre:' },
      { v: 23, en: 'Then Ehud went out onto the porch, and shut the doors of the upper room on him, and locked them.', pt: 'Então Eúde, saindo ao pórtico, cerrou as portas do quarto e as trancou.' },
      { v: 24, en: 'After he had gone, his servants came and saw that the doors of the upper room were locked. They said, “Surely he is covering his feet in the upper room.”', pt: 'Tendo ele saído vieram os servos do rei; e olharam, e eis que as portas do quarto estavam trancadas. Disseram: Sem dúvida ele está aliviando o ventre na privada do seu quarto.' },
      { v: 25, en: 'They waited until they were ashamed; and behold, he didn’t open the doors of the upper room. Therefore they took the key and opened them, and behold, their lord had fallen down dead on the floor.', pt: 'Assim esperaram até ficarem alarmados, mas ainda não abria as portas do quarto. Então, tomando a chave, abriram-nas, e eis seu senhor estendido morto por terra.' },
      { v: 26, en: 'Ehud escaped while they waited, passed beyond the stone idols, and escaped to Seirah.', pt: 'Eúde escapou enquanto eles se demoravam e, tendo passado pelas imagens de escultura, chegou a Seirá.' },
      { v: 27, en: 'When he had come, he blew a trumpet in the hill country of Ephraim; and the children of Israel went down with him from the hill country, and he led them.', pt: 'E assim que chegou, tocou a trombeta na região montanhosa de Efraim; e os filhos de Israel, com ele à frente, desceram das montanhas.' },
      { v: 28, en: 'He said to them, “Follow me; for Yahweh has delivered your enemies the Moabites into your hand.” They followed him, and took the fords of the Jordan against the Moabites, and didn’t allow any man to pass over.', pt: 'E disse-lhes: Segui-me, porque o Senhor vos entregou nas mãos os vossos inimigos, os moabitas. E desceram após ele, tomaram os vaus do Jordão contra os moabitas, e não deixaram passar a nenhum deles.' },
      { v: 29, en: 'They struck at that time about ten thousand men of Moab, every strong man, and every man of valor. No man escaped.', pt: 'E naquela ocasião mataram dos moabitas cerca de dez mil homens, todos robustos e valentes; e não escapou nenhum.' },
      { v: 30, en: 'So Moab was subdued that day under the hand of Israel. Then the land had rest eighty years.', pt: 'Assim foi subjugado Moabe naquele dia debaixo da mão de Israel; e a terra teve sossego por oitenta anos.' },
      { v: 31, en: 'After him was Shamgar the son of Anath, who struck six hundred men of the Philistines with an ox goad. He also saved Israel.', pt: 'Depois dele levantou-se Sangar, filho de Anate, que matou seiscentos homens dos filisteus com uma aguilhada de bois; ele também libertou a Israel.' },
    ],
    4: [
      { v: 1, en: 'The children of Israel again did that which was evil in Yahweh’s sight, when Ehud was dead.', pt: 'Mas os filhos de Israel tornaram a fazer o que era mau aos olhos do Senhor, depois da morte de Eúde.' },
      { v: 2, en: 'Yahweh sold them into the hand of Jabin king of Canaan, who reigned in Hazor; the captain of whose army was Sisera, who lived in Harosheth of the Gentiles.', pt: 'E o Senhor os vendeu na mão de Jabim, rei de Canaã, que reinava em Hazor; o chefe do seu exército era Sísera, o qual habitava em Harosete dos Gentios.' },
      { v: 3, en: 'The children of Israel cried to Yahweh, for he had nine hundred chariots of iron; and he mightily oppressed the children of Israel for twenty years.', pt: 'Então os filhos de Israel clamaram ao Senhor, porquanto Jabim tinha novecentos carros de ferro, e por vinte anos oprimia cruelmente os filhos de Israel.' },
      { v: 4, en: 'Now Deborah, a prophetess, the wife of Lappidoth, judged Israel at that time.', pt: 'Ora, Débora, profetisa, mulher de Lapidote, julgava a Israel naquele tempo.' },
      { v: 5, en: 'She lived under Deborah’s palm tree between Ramah and Bethel in the hill country of Ephraim; and the children of Israel came up to her for judgment.', pt: 'Ela se assentava debaixo da palmeira de Débora, entre Ramá e Betel, na região montanhosa de Efraim; e os filhos de Israel subiam a ter com ela para julgamento.' },
      { v: 6, en: 'She sent and called Barak the son of Abinoam out of Kedesh Naphtali, and said to him, “Hasn’t Yahweh, the God of Israel, commanded, ‘Go and lead the way to Mount Tabor, and take with you ten thousand men of the children of Naphtali and of the children of Zebulun?', pt: 'Mandou ela chamar a Baraque, filho de Abinoão, de Quedes-Naftali, e disse-lhe: Porventura o Senhor Deus de Israel não te ordena, dizendo: Vai, e atrai gente ao monte Tabor, e toma contigo dez mil homens dos filhos de Naftali e dos filhos de Zebulom;' },
      { v: 7, en: 'I will draw to you, to the river Kishon, Sisera, the captain of Jabin’s army, with his chariots and his multitude; and I will deliver him into your hand.’”', pt: 'e atrairei a ti, para o ribeiro de Quisom, Sísera, chefe do exército de Jabim; juntamente com os seus carros e com as suas tropas, e to entregarei na mão?' },
      { v: 8, en: 'Barak said to her, “If you will go with me, then I will go; but if you will not go with me, I will not go.”', pt: 'Disse-lhe Baraque: Se fores comigo, irei; porém se não fores, não irei.' },
      { v: 9, en: 'She said, “I will surely go with you. Nevertheless, the journey that you take won’t be for your honor; for Yahweh will sell Sisera into a woman’s hand.” Deborah arose, and went with Barak to Kedesh.', pt: 'Respondeu ela: Certamente irei contigo; porém não será tua a honra desta expedição, pois à mão de uma mulher o Senhor venderá a Sísera. Levantou-se, pois, Débora, e foi com Baraque a Quedes.' },
      { v: 10, en: 'Barak called Zebulun and Naphtali together to Kedesh; and ten thousand men followed him; and Deborah went up with him.', pt: 'Então Baraque convocou a Zebulom e a Naftali em Quedes, e subiram dez mil homens após ele; também Débora subiu com ele.' },
      { v: 11, en: 'Now Heber the Kenite had separated himself from the Kenites, even from the children of Hobab, Moses’ brother-in-law, and had pitched his tent as far as the oak in Zaanannim, which is by Kedesh.', pt: 'Ora, Heber, um queneu, se tinha apartado dos queneus, dos filhos de Hobabe, sogro de Moisés, e tinha estendido as suas tendas até o carvalho de Zaananim, que está junto a Quedes.' },
      { v: 12, en: 'They told Sisera that Barak the son of Abinoam was gone up to Mount Tabor.', pt: 'Anunciaram a Sísera que Baraque, filho de Abinoão, tinha subido ao monte Tabor.' },
      { v: 13, en: 'Sisera gathered together all his chariots, even nine hundred chariots of iron, and all the people who were with him, from Harosheth of the Gentiles, to the river Kishon.', pt: 'Sísera, pois, ajuntou todos os seus carros, novecentos carros de ferro, e todo o povo que estava com ele, desde Harosete dos Gentios até o ribeiro de Quisom.' },
      { v: 14, en: 'Deborah said to Barak, “Go; for this is the day in which Yahweh has delivered Sisera into your hand. Hasn’t Yahweh gone out before you?” So Barak went down from Mount Tabor, and ten thousand men after him.', pt: 'Então disse Débora a Baraque: Levanta-te, porque este é o dia em que o Senhor entregou Sísera na tua mão; porventura o Senhor não saiu adiante de ti? Baraque, pois, desceu do monte Tabor, e dez mil homens após ele.' },
      { v: 15, en: 'Yahweh confused Sisera, all his chariots, and all his army, with the edge of the sword before Barak. Sisera abandoned his chariot and fled away on his feet.', pt: 'E o Senhor desbaratou a Sísera, com todos os seus carros e todo o seu exército, ao fio da espada, diante de Baraque; e Sísera, descendo do seu carro, fugiu a pé.' },
      { v: 16, en: 'But Barak pursued the chariots and the army to Harosheth of the Gentiles; and all the army of Sisera fell by the edge of the sword. There was not a man left.', pt: 'Mas Baraque perseguiu os carros e o exército, até Harosete dos Gentios; e todo o exército de Sísera caiu ao fio da espada; não restou um só homem.' },
      { v: 17, en: 'However Sisera fled away on his feet to the tent of Jael the wife of Heber the Kenite; for there was peace between Jabin the king of Hazor and the house of Heber the Kenite.', pt: 'Entretanto Sísera fugiu a pé para a tenda de Jael, mulher de Heber, o queneu, porquanto havia paz entre Jabim, rei de Hazor, e a casa de Heber, o queneu.' },
      { v: 18, en: 'Jael went out to meet Sisera, and said to him, “Turn in, my lord, turn in to me; don’t be afraid.” He came in to her into the tent, and she covered him with a rug.', pt: 'Saindo Jael ao encontro de Sísera, disse-lhe: Entra, senhor meu, entra aqui; não temas. Ele entrou na sua tenda; e ela o cobriu com uma coberta.' },
      { v: 19, en: 'He said to her, “Please give me a little water to drink; for I am thirsty.” She opened a bottle of milk, and gave him a drink, and covered him.', pt: 'Então ele lhe disse: Peço-te que me dês a beber um pouco d\'água, porque tenho sede. Então ela abriu um odre de leite, e deu-lhe de beber, e o cobriu.' },
      { v: 20, en: 'He said to her, “Stand in the door of the tent, and if any man comes and inquires of you, and says, ‘Is there any man here?’ you shall say, ‘No.’”', pt: 'Disse-lhe ele mais: Põe-te à porta da tenda; e se alguém vier e te perguntar: Está aqui algum homem? responderás: Não.' },
      { v: 21, en: 'Then Jael Heber’s wife took a tent peg, and took a hammer in her hand, and went softly to him, and struck the pin into his temples, and it pierced through into the ground; for he was in a deep sleep; so he fainted and died.', pt: 'Então Jael, mulher de Heber, tomou uma estaca da tenda e, levando um martelo, chegou-se de mansinho a ele e lhe cravou a estaca na fonte, de sorte que penetrou na terra; pois ele estava num profundo sono e mui cansado. E assim morreu.' },
      { v: 22, en: 'Behold, as Barak pursued Sisera, Jael came out to meet him, and said to him, “Come, and I will show you the man whom you seek.” He came to her; and behold, Sisera lay dead, and the tent peg was in his temples.', pt: 'E eis que, seguindo Baraque a Sísera, Jael lhe saiu ao encontro e disse-lhe: Vem, e mostrar-te-ei o homem a quem procuras. Entrou ele na tenda; e eis que Sísera jazia morto, com a estaca na fonte.' },
      { v: 23, en: 'So God subdued Jabin the king of Canaan before the children of Israel on that day.', pt: 'Assim Deus naquele dia humilhou a Jabim, rei de Canaã, diante dos filhos de Israel.' },
      { v: 24, en: 'The hand of the children of Israel prevailed more and more against Jabin the king of Canaan, until they had destroyed Jabin king of Canaan.', pt: 'E a mão dos filhos de Israel prevalecia cada vez mais contra Jabim, rei de Canaã, até que o destruíram.' },
    ],
    5: [
      { v: 1, en: 'Then Deborah and Barak the son of Abinoam sang on that day, saying,', pt: 'Então cantaram Débora e Baraque, filho de Abinoão, naquele dia, dizendo:' },
      { v: 2, en: '“Because the leaders took the lead in Israel, because the people offered themselves willingly, be blessed, Yahweh!', pt: 'Porquanto os chefes se puseram à frente em Israel, porquanto o povo se ofereceu voluntariamente, louvai ao Senhor.' },
      { v: 3, en: '“Hear, you kings! Give ear, you princes! I, even I, will sing to Yahweh. I will sing praise to Yahweh, the God of Israel.', pt: 'Ouvi, ó reis; dai ouvidos, ó príncipes! eu cantarei ao Senhor, salmodiarei ao Senhor Deus de Israel.' },
      { v: 4, en: '“Yahweh, when you went out of Seir, when you marched out of the field of Edom, the earth trembled, the sky also dropped. Yes, the clouds dropped water.', pt: 'ç Senhor, quando saíste de Seir, quando caminhaste desde o campo de Edom, a terra estremeceu, os céus gotejaram, sim, as nuvens gotejaram águas.' },
      { v: 5, en: 'The mountains quaked Yahweh’s presence, even Sinai at the presence of Yahweh, the God of Israel.', pt: 'Os montes se abalaram diante do Senhor, e até Sinai, diante do Senhor Deus de Israel.' },
      { v: 6, en: '“In the days of Shamgar the son of Anath, in the days of Jael, the highways were unoccupied. The travelers walked through byways.', pt: 'Nos dias de Sangar, filho de Anate, nos dias de Jael, cessaram as caravanas; e os que viajavam iam por atalhos desviados.' },
      { v: 7, en: 'The rulers ceased in Israel. They ceased until I, Deborah, arose; Until I arose a mother in Israel.', pt: 'Cessaram as aldeias em Israel, cessaram; até que eu Débora, me levantei, até que eu me levantei por mãe em Israel.' },
      { v: 8, en: 'They chose new gods. Then war was in the gates. Was there a shield or spear seen among forty thousand in Israel?', pt: 'Escolheram deuses novos; logo a guerra estava às portas; via-se porventura escudo ou lança entre quarenta mil em Israel?' },
      { v: 9, en: 'My heart is toward the governors of Israel, who offered themselves willingly among the people. Bless Yahweh!', pt: 'Meu coração inclina-se para os guias de Israel, que voluntariamente se ofereceram entre o povo. Bendizei ao Senhor.' },
      { v: 10, en: '“Speak, you who ride on white donkeys, you who sit on rich carpets, and you who walk by the way.', pt: 'Louvai-o vós, os que cavalgais sobre jumentas brancas, que vos assentais sobre ricos tapetes; e vós, que andais pelo caminho.' },
      { v: 11, en: 'Far from the noise of archers, in the places of drawing water, there they will rehearse Yahweh’s righteous acts, the righteous acts of his rule in Israel. “Then Yahweh’s people went down to the gates.', pt: 'Onde se ouve o estrondo dos flecheiros, entre os lugares onde se tiram águas, ali falarão das justiças do Senhor, das justiças que fez às suas aldeias em Israel; então o povo do Senhor descia às portas.' },
      { v: 12, en: '‘Awake, awake, Deborah! Awake, awake, utter a song! Arise, Barak, and lead away your captives, you son of Abinoam.’', pt: 'Desperta, desperta, Débora; desperta, desperta, entoa um cântico; levanta-te, Baraque, e leva em cativeiro os teus prisioneiros, tu, filho de Abinoão.' },
      { v: 13, en: '“Then a remnant of the nobles and the people came down. Yahweh came down for me against the mighty.', pt: 'Então desceu o restante dos nobres e do povo; desceu o Senhor por mim contra os poderosos.' },
      { v: 14, en: 'Those whose root is in Amalek came out of Ephraim, after you, Benjamin, among your peoples. Governors come down out of Machir. Those who handle the marshal’s staff came out of Zebulun.', pt: 'De Efraim desceram os que tinham a sua raiz em Amaleque, após ti, Benjamim, entre os teus povos; de Maquir desceram os guias, e de Zebulom os que levam o báculo do inspetor de tropas.' },
      { v: 15, en: 'The princes of Issachar were with Deborah. As was Issachar, so was Barak. They rushed into the valley at his feet. By the watercourses of Reuben, there were great resolves of heart.', pt: 'Também os príncipes de Issacar estavam com Débora; e como Issacar, assim também Baraque; ao vale precipitaram-se em suas pegadas. Junto aos ribeiros de Rúben grandes foram as resoluções do coração.' },
      { v: 16, en: 'Why did you sit among the sheepfolds? To hear the whistling for the flocks? At the watercourses of Reuben, there were great searchings of heart.', pt: 'Por que ficastes entre os currais a escutar os balidos dos rebanhos? Junto aos ribeiros de Rúben grandes foram as resoluções do coração.' },
      { v: 17, en: 'Gilead lived beyond the Jordan. Why did Dan remain in ships? Asher sat still at the haven of the sea, and lived by his creeks.', pt: 'Gileade ficou da banda dalém do Jordão; e Dã, por que se deteve com seus navios? Aser se assentou na costa do mar e ficou junto aos seus portos.' },
      { v: 18, en: 'Zebulun was a people that jeopardized their lives to the death; Naphtali also, on the high places of the field.', pt: 'Zebulom é um povo que se expôs à morte, como também Naftali, nas alturas do campo.' },
      { v: 19, en: '“The kings came and fought, then the kings of Canaan fought at Taanach by the waters of Megiddo. They took no plunder of silver.', pt: 'Vieram reis e pelejaram; pelejaram os reis de Canaã, em Taanaque junto às águas de Megido; não tomaram despojo de prata.' },
      { v: 20, en: 'From the sky the stars fought. From their courses, they fought against Sisera.', pt: 'Desde os céus pelejaram as estrelas; desde as suas órbitas pelejaram contra Sísera.' },
      { v: 21, en: 'The river Kishon swept them away, that ancient river, the river Kishon. My soul, march on with strength.', pt: 'O ribeiro de Quisom os arrastou, aquele antigo ribeiro, o ribeiro de Quisom. Ó minha alma, calcaste aos pés a força.' },
      { v: 22, en: 'Then the horse hoofs stamped because of the prancing, the prancing of their strong ones.', pt: 'Então os cascos dos cavalos feriram a terra na fuga precipitada dos seus valentes.' },
      { v: 23, en: '‘Curse Meroz,’ said Yahweh’s angel. ‘Curse bitterly its inhabitants, because they didn’t come to help Yahweh, to help Yahweh against the mighty.’', pt: 'Amaldiçoai a Meroz, diz o anjo do Senhor, amaldiçoai acremente aos seus habitantes; porquanto não vieram em socorro do Senhor, em socorro do Senhor, entre os valentes.' },
      { v: 24, en: '“Jael shall be blessed above women, the wife of Heber the Kenite; blessed shall she be above women in the tent.', pt: 'Bendita entre todas as mulheres será Jael, mulher de Heber, o queneu; bendita será entre as mulheres nômades.' },
      { v: 25, en: 'He asked for water. She gave him milk. She brought him butter in a lordly dish.', pt: 'Água pediu ele, leite lhe deu ela; em taça de príncipes lhe ofereceu coalhada.' },
      { v: 26, en: 'She put her hand to the tent peg, and her right hand to the workmen’s hammer. With the hammer she struck Sisera. She struck through his head. Yes, she pierced and struck through his temples.', pt: 'Â estaca estendeu a mão esquerda, e ao martelo dos trabalhadores a direita, e matou a Sísera, rachando-lhe a cabeça; furou e traspassou-lhe as fontes.' },
      { v: 27, en: 'At her feet he bowed, he fell, he lay. At her feet he bowed, he fell. Where he bowed, there he fell down dead.', pt: 'Aos pés dela ele se encurvou, caiu, ficou estirado; aos pés dela se encurvou, caiu; onde se encurvou, ali caiu morto.' },
      { v: 28, en: '“Through the window she looked out, and cried: Sisera’s mother looked through the lattice. ‘Why is his chariot so long in coming? Why do the wheels of his chariots wait?’', pt: 'A mãe de Sísera olhando pela janela, através da grade exclamava: Por que tarda em vir o seu carro? por que se demora o rumor das suas carruagens?' },
      { v: 29, en: 'Her wise ladies answered her, Yes, she returned answer to herself,', pt: 'As mais sábias das suas damas responderam, e ela respondia a si mesma:' },
      { v: 30, en: '‘Have they not found, have they not divided the plunder? A lady, two ladies to every man; to Sisera a plunder of dyed garments, a plunder of dyed garments embroidered, of dyed garments embroidered on both sides, on the necks of the plunder?’', pt: 'Não estão, porventura, achando e repartindo os despojos? uma ou duas donzelas a cada homem? para Sísera despojos de estofos tintos, despojos de estofos tintos bordados, bordados de várias cores, para o meu pescoço?' },
      { v: 31, en: '“So let all your enemies perish, Yahweh, but let those who love him be as the sun when it rises in its strength.” Then the land had rest forty years.', pt: 'Assim ó Senhor, pereçam todos os teus inimigos! Sejam, porém, os que te amam, como o sol quando se levanta na sua força.' },
      { v: 32, en: 'E a terra teve sossego por quarenta anos.', pt: 'E a terra teve sossego por quarenta anos.' },
    ],
    6: [
      { v: 1, en: 'The children of Israel did that which was evil in Yahweh’s sight: and Yahweh delivered them into the hand of Midian seven years.', pt: 'Mas os filhos de Israel fizeram o que era mau aos olhos do Senhor, e o Senhor os entregou na mão de Midiã por sete anos.' },
      { v: 2, en: 'The hand of Midian prevailed against Israel; and because of Midian the children of Israel made themselves the dens which are in the mountains, and the caves, and the strongholds.', pt: 'Prevalecia, pois, a mão de Midiã sobre Israel e, por causa de Midiã, fizeram os filhos de Israel para si as covas que estão nos montes, as cavernas e as fortalezas.' },
      { v: 3, en: 'So it was, when Israel had sown, that the Midianites, the Amalekites, and the children of the east came up against them.', pt: 'Porque sucedia que, havendo Israel semeado, subiam contra ele os midianitas, os amalequitas e os filhos do oriente;' },
      { v: 4, en: 'They encamped against them, and destroyed the increase of the earth, until you come to Gaza. They left no sustenance in Israel, and no sheep, ox, or donkey.', pt: 'e, acampando-se contra ele, destruíam o produto da terra até chegarem a Gaza, e não deixavam mantimento em Israel, nem ovelhas, nem bois, nem jumentos.' },
      { v: 5, en: 'For they came up with their livestock and their tents. They came in as locusts for multitude. Both they and their camels were without number; and they came into the land to destroy it.', pt: 'Porque subiam com os seus rebanhos e tendas; vinham em multidão, como gafanhotos; tanto eles como os seus camelos eram inumeráveis; e entravam na terra, para a destruir.' },
      { v: 6, en: 'Israel was brought very low because of Midian; and the children of Israel cried to Yahweh.', pt: 'Assim Israel se enfraqueceu muito por causa dos midianitas; então os filhos de Israel clamaram ao Senhor.' },
      { v: 7, en: 'When the children of Israel cried to Yahweh because of Midian,', pt: 'E sucedeu que, clamando eles ao Senhor por causa dos midianitas,' },
      { v: 8, en: 'Yahweh sent a prophet to the children of Israel; and he said to them, “Yahweh says, the God of Israel, ‘I brought you up from Egypt, and brought you out of the house of bondage.', pt: 'enviou-lhes o Senhor um profeta, que lhes disse: Assim diz o Senhor, Deus de Israel: Do Egito eu vos fiz subir, e vos tirei da casa da servidão;' },
      { v: 9, en: 'I delivered you out of the hand of the Egyptians, and out of the hand of all who oppressed you, and drove them out from before you, and gave you their land.', pt: 'livrei-vos da mão dos egípcios, e da mão de todos quantos vos oprimiam, e os expulsei de diante de vós, e a vós vos dei a sua terra.' },
      { v: 10, en: 'I said to you, “I am Yahweh your God. You shall not fear the gods of the Amorites, in whose land you dwell.” But you have not listened to my voice.’”', pt: 'Também eu vos disse: Eu sou o Senhor vosso Deus; não temais aos deuses dos amorreus, em cuja terra habitais. Mas não destes ouvidos à minha voz.' },
      { v: 11, en: 'Yahweh’s angel came, and sat under the oak which was in Ophrah, that belonged to Joash the Abiezrite. His son Gideon was beating out wheat in the wine press, to hide it from the Midianites.', pt: 'Então o anjo do Senhor veio, e sentou-se debaixo do carvalho que estava em Ofra e que pertencia a Joás, abiezrita, cujo filho Gideão estava malhando o trigo no lagar para o esconder dos midianitas.' },
      { v: 12, en: 'Yahweh’s angel appeared to him, and said to him, “Yahweh is with you, you mighty man of valor!”', pt: 'Apareceu-lhe então o anjo do Senhor e lhe disse: O Senhor é contigo, ó homem valoroso.' },
      { v: 13, en: 'Gideon said to him, “Oh, my lord, if Yahweh is with us, why then has all this happened to us? Where are all his wondrous works which our fathers told us of, saying, ‘Didn’t Yahweh bring us up from Egypt?’ But now Yahweh has cast us off, and delivered us into the hand of Midian.”', pt: 'Gideão lhe respondeu: Ai, senhor meu, se o Senhor é conosco, por que tudo nos sobreveio? e onde estão todas as suas maravilhas que nossos pais nos contaram, dizendo: Não nos fez o Senhor subir do Egito? Agora, porém, o Senhor nos desamparou, e nos entregou na mão de Midiã.' },
      { v: 14, en: 'Yahweh looked at him, and said, “Go in this your might, and save Israel from the hand of Midian. Haven’t I sent you?”', pt: 'Virou-se o Senhor para ele e lhe disse: Vai nesta tua força, e livra a Israel da mão de Midiã; porventura não te envio eu?' },
      { v: 15, en: 'He said to him, “O Lord, how shall I save Israel? Behold, my family is the poorest in Manasseh, and I am the least in my father’s house.”', pt: 'Replicou-lhe Gideão: Ai, senhor meu, com que livrarei a Israel? eis que a minha família é a mais pobre em Manassés, e eu o menor na casa de meu pai.' },
      { v: 16, en: 'Yahweh said to him, “Surely I will be with you, and you shall strike the Midianites as one man.”', pt: 'Tornou-lhe o Senhor: Porquanto eu hei de ser contigo, tu ferirás aos midianitas como a um só homem.' },
      { v: 17, en: 'He said to him, “If now I have found favor in your sight, then show me a sign that it is you who talk with me.', pt: 'Prosseguiu Gideão: Se agora tenho achado graça aos teus olhos, dá-me um sinal de que és tu que falas comigo.' },
      { v: 18, en: 'Please don’t go away, until I come to you, and bring out my present, and lay it before you.” He said, “I will wait until you come back.”', pt: 'Rogo-te que não te apartes daqui até que eu volte trazendo do meu presente e o ponha diante de ti. Respondeu ele: Esperarei até que voltes.' },
      { v: 19, en: 'Gideon went in and prepared a young goat and unleavened cakes of an ephah of meal. He put the meat in a basket and he put the broth in a pot, and brought it out to him under the oak, and presented it.', pt: 'Entrou, pois, Gideão, preparou um cabrito e fez, com uma e efa de farinha, bolos ázimos; pôs a carne num cesto e o caldo numa panela e, trazendo para debaixo do carvalho, lho apresentou.' },
      { v: 20, en: 'The angel of God said to him, “Take the meat and the unleavened cakes, and lay them on this rock, and pour out the broth.” He did so.', pt: 'Mas o anjo de Deus lhe disse: Toma a carne e os bolos ázimos, e põe-nos sobre esta rocha e derrama-lhes por cima o caldo. E ele assim fez.' },
      { v: 21, en: 'Then Yahweh’s angel stretched out the end of the staff that was in his hand, and touched the meat and the unleavened cakes; and fire went up out of the rock, and consumed the meat and the unleavened cakes. Then Yahweh’s angel departed out of his sight.', pt: 'E o anjo do Senhor estendeu a ponta do cajado que tinha na mão, e tocou a carne e os bolos ázimos; então subiu fogo da rocha, e consumiu a carne e os bolos ázimos; e o anjo do Senhor desapareceu-lhe da vista.' },
      { v: 22, en: 'Gideon saw that he was Yahweh’s angel; and Gideon said, “Alas, Lord Yahweh! Because I have seen Yahweh’s angel face to face!”', pt: 'Vendo Gideão que era o anjo do Senhor, disse: Ai de mim, Senhor Deus! pois eu vi o anjo do Senhor face a face.' },
      { v: 23, en: 'Yahweh said to him, “Peace be to you! Don’t be afraid. You shall not die.”', pt: 'Porém o Senhor lhe disse: Paz seja contigo, não temas; não morrerás.' },
      { v: 24, en: 'Then Gideon built an altar there to Yahweh, and called it “Yahweh is Peace.” To this day it is still in Ophrah of the Abiezrites.', pt: 'Então Gideão edificou ali um altar ao Senhor, e lhe chamou Jeová-Salom; e ainda até o dia de hoje está o altar em Ofra dos abiezritas.' },
      { v: 25, en: 'That same night, Yahweh said to him, “Take your father’s bull, even the second bull seven years old, and throw down the altar of Baal that your father has, and cut down the Asherah that is by it.', pt: 'Naquela mesma noite, disse o Senhor a Gidão: Toma um dos bois de teu pai, a saber, o segundo boi de sete anos, e derriba o altar de Baal, que é de teu pai, e corta a asera que está ao pé dele.' },
      { v: 26, en: 'Then build an altar to Yahweh your God on the top of this stronghold, in an orderly way, and take the second bull, and offer a burnt offering with the wood of the Asherah which you shall cut down.”', pt: 'Edifica ao Senhor teu Deus um altar no cume deste lugar forte, na forma devida; toma o segundo boi, e o oferece em holocausto, com a lenha da asera que cortares' },
      { v: 27, en: 'Then Gideon took ten men of his servants, and did as Yahweh had spoken to him. Because he feared his father’s household and the men of the city, he could not do it by day, but he did it by night.', pt: 'Então Gideão tomou dez homens dentre os seus servos, e fez como o Senhor lhe dissera; porém, temendo ele a casa de seu pai e os homens daquela cidade, não o fez de dia, mas de noite.' },
      { v: 28, en: 'When the men of the city arose early in the morning, behold, the altar of Baal was broken down, and the Asherah was cut down that was by it, and the second bull was offered on the altar that was built.', pt: 'Levantando-se, pois, os homens daquela cidade, de madrugada, eis que estava o altar de Baal derribado, cortada a asera que estivera ao pé dele, e o segundo boi oferecido no altar que fora edificado.' },
      { v: 29, en: 'They said to one another, “Who has done this thing?” When they inquired and asked, they said, “Gideon the son of Joash has done this thing.”', pt: 'Pelo que disseram uns aos outros: Quem fez isto? E, depois de investigarem e inquirirem, disseram: Gideão, filho de Joás, é quem fez isto.' },
      { v: 30, en: 'Then the men of the city said to Joash, “Bring out your son, that he may die, because he has broken down the altar of Baal, and because he has cut down the Asherah that was by it.”', pt: 'Então os homens daquela cidade disseram a Joás: Tira para fora teu filho, para que morra, porque derribou o altar de Baal e cortou a asera que estava ao pé dele.' },
      { v: 31, en: 'Joash said to all who stood against him, “Will you contend for Baal? Or will you save him? He who will contend for him, let him be put to death by morning! If he is a god, let him contend for himself, because someone has broken down his altar!”', pt: 'Joás, porém, disse a todos os que se puseram contra ele: Contendereis vós por Baal? livrá-lo-eis vós? Qualquer que por ele contender, ainda esta manhã será morto; se ele é deus, por si mesmo contenda, pois foi derribado o seu altar.' },
      { v: 32, en: 'Therefore on that day he named him Jerub-Baal, saying, “Let Baal contend against him, because he has broken down his altar.”', pt: 'Pelo que naquele dia chamaram a Gidão Jerubaal, dizendo: Baal contenda contra ele, pois derribou o seu altar.' },
      { v: 33, en: 'Then all the Midianites and the Amalekites and the children of the east assembled themselves together; and they passed over, and encamped in the valley of Jezreel.', pt: 'Então todos os midianitas, os amalequitas e os filhos do oriente se ajuntaram e, passando o Jordão, acamparam no vale de Jizreel.' },
      { v: 34, en: 'But Yahweh’s Spirit came on Gideon, and he blew a trumpet; and Abiezer was gathered together to follow him.', pt: 'Mas o Espírito do Senhor apoderou-se de Gideão; e tocando ele a trombeta, os abiezritas se ajuntaram após ele.' },
      { v: 35, en: 'He sent messengers throughout all Manasseh; and they also were gathered together to follow him. He sent messengers to Asher, and to Zebulun, and to Naphtali; and they came up to meet them.', pt: 'E enviou mensageiros por toda a tribo de Manassés, que também se ajuntou após ele; e ainda enviou mensageiros a Aser, a Zebulom e a Naftali, que lhe saíram ao encontro.' },
      { v: 36, en: 'Gideon said to God, “If you will save Israel by my hand, as you have spoken,', pt: 'Disse Gideão a Deus: Se hás de livrar a Israel por minha mão, como disseste,' },
      { v: 37, en: 'behold, I will put a fleece of wool on the threshing floor; if there is dew on the fleece only, and it is dry on all the ground, then shall I know that you will save Israel by my hand, as you have spoken.”', pt: 'eis que eu porei um velo de lã na eira; se o orvalho estiver somente no velo, e toda a terra ficar enxuta, então conhecerei que hás de livrar a Israel por minha mão, como disseste.' },
      { v: 38, en: 'It was so; for he rose up early on the next day, and pressed the fleece together, and wrung the dew out of the fleece, a bowl full of water.', pt: 'E assim foi; pois, levantando-se de madrugada no dia seguinte, apertou o velo, e espremeu dele o orvalho, que encheu uma taça.' },
      { v: 39, en: 'Gideon said to God, “Don’t let your anger be kindled against me, and I will speak but this once. Please let me make a trial just this once with the fleece. Let it now be dry only on the fleece, and on all the ground let there be dew.”', pt: 'Disse mais Gideão a Deus: Não se acenda contra mim a tua ira se ainda falar só esta vez. Permite que só mais esta vez eu faça prova com o velo; rogo-te que só o velo fique enxuto, e em toda a terra haja orvalho.' },
      { v: 40, en: 'God did so that night; for it was dry on the fleece only, and there was dew on all the ground.', pt: 'E Deus assim fez naquela noite; pois só o velo estava enxuto, e sobre toda a terra havia orvalho.' },
    ],
    7: [
      { v: 1, en: 'Then Jerubbaal, who is Gideon, and all the people who were with him, rose up early, and encamped beside the spring of Harod. Midian’s camp was on the north side of them, by the hill of Moreh, in the valley.', pt: 'Então Jerubaal, que é Gideão, e todo o povo que estava com ele, levantando-se de madrugada acamparam junto à fonte de Harode; e o arraial de Midiã estava da banda do norte, perto do outeiro de Moré, no vale.' },
      { v: 2, en: 'Yahweh said to Gideon, “The people who are with you are too many for me to give the Midianites into their hand, lest Israel brag against me, saying, ‘My own hand has saved me.’', pt: 'Disse o Senhor a Gideão: O povo que está contigo é demais para eu entregar os midianitas em sua mão; não seja caso que Israel se glorie contra mim, dizendo: Foi a minha própria mão que me livrou.' },
      { v: 3, en: 'Now therefore proclaim in the ears of the people, saying, ‘Whoever is fearful and trembling, let him return and depart from Mount Gilead.’” So twenty-two thousand of the people returned, and ten thousand remained.', pt: 'Agora, pois, apregoa aos ouvidos do povo, dizendo: Quem for medroso e tímido volte, e retire-se do monte Gileade. Então voltaram do povo vinte e dois mil, e dez mil ficaram.' },
      { v: 4, en: 'Yahweh said to Gideon, “There are still too many people. Bring them down to the water, and I will test them for you there. It shall be, that those whom I tell you, ‘This shall go with you,’ the same shall go with you; and whoever I tell you, ‘This shall not go with you,’ the same shall not go.”', pt: 'Disse mais o Senhor a Gideão: Ainda são muitos. Faze-os descer às águas, e ali os provarei; e será que, aquele de que eu te disser: Este irá contigo, esse contigo irá; porém todo aquele de que eu te disser: Este não irá contigo, esse não irá.' },
      { v: 5, en: 'So he brought down the people to the water; and Yahweh said to Gideon, “Everyone who laps of the water with his tongue, like a dog laps, you shall set him by himself; likewise everyone who bows down on his knees to drink.”', pt: 'E Gideão fez descer o povo às águas. Então o Senhor lhe disse: Qualquer que lamber as águas com a língua, como faz o cão, a esse porás de um lado; e a todo aquele que se ajoelhar para beber, porás do outro.' },
      { v: 6, en: 'The number of those who lapped, putting their hand to their mouth, was three hundred men; but all the rest of the people bowed down on their knees to drink water.', pt: 'E foi o número dos que lamberam a água, levando a mão à boca, trezentos homens; mas todo o resto do povo se ajoelhou para beber.' },
      { v: 7, en: 'Yahweh said to Gideon, “By the three hundred men who lapped will I save you, and deliver the Midianites into your hand. Let all the other people go, each to his own place.”', pt: 'Disse ainda o Senhor a Gideão: Com estes trezentos homens que lamberam a água vos livrarei, e entregarei os midianitas na tua mão; mas, quanto ao resto do povo, volte cada um ao seu lugar.' },
      { v: 8, en: 'So the people took food in their hand, and their trumpets; and he sent all the men of Israel every man to his tent, but retained the three hundred men; and the camp of Midian was beneath him in the valley.', pt: 'E o povo tomou na sua mão as provisões e as suas trombetas, e Gideão enviou todos os outros homens de Israel cada um à sua tenda, porém reteve os trezentos. O arraial de Midiã estava embaixo no vale.' },
      { v: 9, en: 'That same night, Yahweh said to him, “Arise, go down into the camp; for I have delivered it into your hand.', pt: 'Naquela mesma noite disse o Senhor a Gideão: Levanta-te, e desce contra o arraial, porque eu o entreguei na tua mão.' },
      { v: 10, en: 'But if you are afraid to go down, go with Purah your servant down to the camp.', pt: 'Mas se tens medo de descer, vai com o teu moço, Purá, ao arraial;' },
      { v: 11, en: 'You will hear what they say; and afterward your hands will be strengthened to go down into the camp.” Then went he down with Purah his servant to the outermost part of the armed men who were in the camp.', pt: 'ouvirás o que dizem, e serão fortalecidas as tuas mãos para desceres contra o arraial. Então desceu ele com e seu moço, Purá, até o posto avançado das sentinelas do arraial.' },
      { v: 12, en: 'The Midianites and the Amalekites and all the children of the east lay along in the valley like locusts for multitude; and their camels were without number, as the sand which is on the seashore for multitude.', pt: 'Os midianitas, os amalequitas, e todos os filhos do oriente jaziam no vale, como gafanhotos em multidão; e os seus camelos eram inumeráveis, como a areia na praia do mar.' },
      { v: 13, en: 'When Gideon had come, behold, there was a man telling a dream to his fellow. He said, “Behold, I dreamed a dream; and behold, a cake of barley bread tumbled into the camp of Midian, and came to the tent, and struck it so that it fell, and turned it upside down, so that the tent lay flat.”', pt: 'No momento em que Gideão chegou, um homem estava contando ao seu companheiro um sonho, e dizia: Eu tive um sonho; eis que um pão de cevada vinha rolando sobre o arraial dos midianitas e, chegando a uma tenda, bateu nela de sorte a fazê-la cair, e a virou de cima para baixo, e ela ficou estendida por terra.' },
      { v: 14, en: 'His fellow answered, “This is nothing other than the sword of Gideon the son of Joash, a man of Israel. God has delivered Midian into his hand, with all the army.”', pt: 'Ao que respondeu o seu companheiro, dizendo: Isso não é outra coisa senão a espada de Gideão, filho de Joás, varão israelita. Na sua mão Deus entregou Midiã e todo este arraial.' },
      { v: 15, en: 'It was so, when Gideon heard the telling of the dream, and its interpretation, that he worshiped. Then he returned into the camp of Israel, and said, “Arise; for Yahweh has delivered the army of Midian into your hand!”', pt: 'Quando Gideão ouviu a narração do sonho e a sua interpretação, adorou a Deus; e voltando ao arraial de Israel, disse: Levantai-vos, porque o Senhor entregou nas vossas mãos o arraial de Midiã.' },
      { v: 16, en: 'He divided the three hundred men into three companies, and he put into the hands of all them trumpets, and empty pitchers, with torches within the pitchers.', pt: 'Então dividiu os trezentos homens em três companhias, pôs nas mãos de cada um deles trombetas, e cântaros vazios contendo tochas acesas,' },
      { v: 17, en: 'He said to them, “Watch me, and do likewise. Behold, when I come to the outermost part of the camp, it shall be that, as I do, so you shall do.', pt: 'e disse-lhes: Olhai para mim, e fazei como eu fizer; e eis que chegando eu à extremidade do arraial, como eu fizer, assim fareis vós.' },
      { v: 18, en: 'When I blow the trumpet, I and all who are with me, then blow the trumpets also on every side of all the camp, and shout, ‘For Yahweh and for Gideon!’”', pt: 'Quando eu tocar a trombeta, eu e todos os que comigo estiverem, tocai também vós as trombetas ao redor de todo o arraial, e dizei: Pelo Senhor e por Gideão!' },
      { v: 19, en: 'So Gideon, and the hundred men who were with him, came to the outermost part of the camp in the beginning of the middle watch, when they had but newly set the watch. Then they blew the trumpets, and broke in pieces the pitchers that were in their hands.', pt: 'Gideão, pois, e os cem homens que estavam com ele chegaram à extremidade do arraial, ao princípio da vigília do meio, havendo sido de pouco colocadas as guardas; então tocaram as trombetas e despedaçaram os cântaros que tinham nas mãos.' },
      { v: 20, en: 'The three companies blew the trumpets, broke the pitchers, and held the torches in their left hands, and the trumpets in their right hands with which to blow; and they shouted, “The sword of Yahweh and of Gideon!”', pt: 'Assim tocaram as três companhias as trombetas, despedaçaram os cântaros, segurando com as mãos esquerdas as tochas e com as direitas as trombetas para as tocarem, e clamaram: A espada do Senhor e de Gideão!' },
      { v: 21, en: 'They each stood in his place around the camp; and all the army ran; and they shouted, and put them to flight.', pt: 'E conservou-se cada um no seu lugar ao redor do arraial; então todo o exército deitou a correr e, gritando, fugiu.' },
      { v: 22, en: 'They blew the three hundred trumpets, and Yahweh set every man’s sword against his fellow, and against all the army; and the army fled as far as Beth Shittah toward Zererah, as far as the border of Abel Meholah, by Tabbath.', pt: 'Pois, ao tocarem os trezentos as trombetas, o Senhor tornou a espada de um contra o outro, e isto em todo o arraial, e fugiram até Bete-Sita, em direção de Zererá, até os limites de Abel-Meolá, junto a Tabate.' },
      { v: 23, en: 'The men of Israel were gathered together out of Naphtali, and out of Asher, and out of all Manasseh, and pursued Midian.', pt: 'Então os homens de Israel, das tribos de Naftali, de Aser e de todo o Manassés, foram convocados e perseguiram a Midiã.' },
      { v: 24, en: 'Gideon sent messengers throughout all the hill country of Ephraim, saying, “Come down against Midian, and take before them the waters, as far as Beth Barah, even the Jordan!” So all the men of Ephraim were gathered together, and took the waters as far as Beth Barah, even the Jordan.', pt: 'Também Gideão enviou mensageiros por toda a região montanhosa de Efraim, dizendo: Descei ao encontro de Midiã, e ocupai-lhe as águas até Bete-Bara, e também o Jordão. Convocados, pois todos os homens de Efraim, tomaram-lhe as águas até Bete-Bara, e também o Jordão;' },
      { v: 25, en: 'They took the two princes of Midian, Oreb and Zeeb. They killed Oreb at Oreb’s rock, and Zeeb they killed at Zeeb’s wine press; and pursued Midian. Then they brought the heads of Oreb and Zeeb to Gideon beyond the Jordan.', pt: 'e prenderam dois príncipes de Midiã, Orebe e Zeebe; e mataram Orebe na penha de Orebe, e Zeebe mataram no lagar de Zeebe, e perseguiram a Midiã; e trouxeram as cabeças de Orebe e de Zeebe a Gideão, além do Jordão.' },
    ],
    8: [
      { v: 1, en: 'The men of Ephraim said to him, “Why have you treated us this way, that you didn’t call us when you went to fight with Midian?” They rebuked him sharply.', pt: 'Então os homens de Efraim lhe disseram: Que é isto que nos fizeste, não nos chamando quando foste pelejar contra Midiã? E repreenderam-no asperamente.' },
      { v: 2, en: 'He said to them, “What have I now done in comparison with you? Isn’t the gleaning of the grapes of Ephraim better than the vintage of Abiezer?', pt: 'Ele, porém, lhes respondeu: Que fiz eu agora em comparação ao que vós fizestes? Não são porventura os rabiscos de Efraim melhores do que a vindima de Abiezer?' },
      { v: 3, en: 'God has delivered into your hand the princes of Midian, Oreb and Zeeb! What was I able to do in comparison with you?” Then their anger was abated toward him, when he had said that.', pt: 'Deus entregou na vossa mão os príncipes de Midiã, Orebe e Zeebe; que, pois, pude eu fazer em comparação ao que vós fizestes? Então a sua ira se abrandou para com ele, quando falou esta palavra.' },
      { v: 4, en: 'Gideon came to the Jordan, and passed over, he, and the three hundred men who were with him, faint, yet pursuing.', pt: 'E Gideão veio ao Jordão e o atravessou, ele e os trezentos homens que estavam com ele, fatigados, mas ainda perseguindo.' },
      { v: 5, en: 'He said to the men of Succoth, “Please give loaves of bread to the people who follow me; for they are faint, and I am pursuing after Zebah and Zalmunna, the kings of Midian.”', pt: 'Disse, pois, aos homens de Sucote: Dai, peço-vos, uns pães ao povo que me segue, porquanto está fatigado, e eu vou perseguindo a Zeba e Zalmuna, reis os midianitas.' },
      { v: 6, en: 'The princes of Succoth said, “Are the hands of Zebah and Zalmunna now in your hand, that we should give bread to your army?”', pt: 'Mas os príncipes de Sucote responderam: Já estão em teu poder as mãos de Zebá e Zalmuna, para que demos pão ao teu exército?' },
      { v: 7, en: 'Gideon said, “Therefore when Yahweh has delivered Zebah and Zalmunna into my hand, then I will tear your flesh with the thorns of the wilderness and with briers.”', pt: 'Replicou-lhes Gideão: Pois quando o Senhor entregar na minha mão a Zebá e a Zalmuna, trilharei a vossa carne com os espinhos do deserto e com os abrolhos.' },
      { v: 8, en: 'He went up there to Penuel, and spoke to them in the same way; and the men of Penuel answered him as the men of Succoth had answered.', pt: 'Dali subiu a Penuel, e falou da mesma maneira aos homens desse lugar, que lhe responderam como os homens de Sucote lhe haviam respondido.' },
      { v: 9, en: 'He spoke also to the men of Penuel, saying, “When I come again in peace, I will break down this tower.”', pt: 'Por isso falou também aos homens de Penuel, dizendo: Quando eu voltar em paz, derribarei esta torre.' },
      { v: 10, en: 'Now Zebah and Zalmunna were in Karkor, and their armies with them, about fifteen thousand men, all who were left of all the army of the children of the east; for there fell one hundred twenty thousand men who drew sword.', pt: 'Zebá e Zalmuna estavam em Carcor com o seu exército, cerca de quinze mil homens, os restantes de todo o exército dos filhos do oriente; pois haviam caído cento e vinte mil homens que puxavam da espada.' },
      { v: 11, en: 'Gideon went up by the way of those who lived in tents on the east of Nobah and Jogbehah, and struck the army; for the army was secure.', pt: 'subiu Gideão pelo caminho dos que habitavam em tendas, ao oriente de Nobá e Jogbeá, e feriu aquele exército, porquanto se dava por seguro.' },
      { v: 12, en: 'Zebah and Zalmunna fled; and he pursued them. He took the two kings of Midian, Zebah and Zalmunna, and confused all the army.', pt: 'E, fugindo Zebá e Zalmuna, Gideão os perseguiu, tomou presos esses dois reis dos midianitas e desbaratou todo o exército.' },
      { v: 13, en: 'Gideon the son of Joash returned from the battle from the ascent of Heres.', pt: 'Voltando, pois, Gideão, filho de Joás, da peleja pela subida de Heres,' },
      { v: 14, en: 'He caught a young man of the men of Succoth, and inquired of him: and he described for him the princes of Succoth, and its elders, seventy-seven men.', pt: 'tomou preso a um moço dos homens de Sucote, e o inquiriu; este lhe deu por escrito os nomes dos príncipes de Sucote, e dos seus anciãos, setenta e sete homens.' },
      { v: 15, en: 'He came to the men of Succoth, and said, “See Zebah and Zalmunna, concerning whom you taunted me, saying, ‘Are the hands of Zebah and Zalmunna now in your hand, that we should give bread to your men who are weary?’”', pt: 'Então veio aos homens de Sucote, e disse: Eis aqui Zebá e Zalmuna, a respeito dos quais me escarnecestes, dizendo: Porventura já estão em teu poder as mãos de Zebá e Zalmuna, para que demos pão aos teus homens fatigados?' },
      { v: 16, en: 'He took the elders of the city, and thorns of the wilderness and briers, and with them he taught the men of Succoth.', pt: 'Nisso tomou os anciãos da cidade, e espinhos e abrolhos do deserto, e com eles ensinou aos homens de Sucote.' },
      { v: 17, en: 'He broke down the tower of Penuel, and killed the men of the city.', pt: 'Também derrubou a torre de Penuel, e matou os homens da cidade.' },
      { v: 18, en: 'Then he said to Zebah and Zalmunna, “What kind of men were they whom you killed at Tabor?” They answered, “They were like you. Each one resembled the children of a king.”', pt: 'Depois perguntou a Zebá e a Zalmuna: Como eram os homens que matastes em Tabor? E responderam eles: Qual és tu, tais eram eles; cada um parecia filho de rei.' },
      { v: 19, en: 'He said, “They were my brothers, the sons of my mother. As Yahweh lives, if you had saved them alive, I would not kill you.”', pt: 'Então disse ele: Eram meus irmãos, filhos de minha mãe; vive o Senhor, que se lhes tivésseis poupado a vida, eu não vos mataria.' },
      { v: 20, en: 'He said to Jether his firstborn, “Get up, and kill them!” But the youth didn’t draw his sword; for he was afraid, because he was yet a youth.', pt: 'E disse a Jeter, seu primogênito: Levanta-te, mata-os. O mancebo, porém, não puxou da espada, porque temia, porquanto ainda era muito moço.' },
      { v: 21, en: 'Then Zebah and Zalmunna said, “Rise and fall on us; for as the man is, so is his strength.” Gideon arose, and killed Zebah and Zalmunna, and took the crescents that were on their camels’ necks.', pt: 'Então disseram Zebá e Zalmuna: Levanta-te tu mesmo, e acomete-nos; porque, qual o homem, tal a sua força. Levantando-se, pois, Gideão, matou Zebá e Zalmuna, e tomou os crescentes que estavam aos pescoços dos seus camelos.' },
      { v: 22, en: 'Then the men of Israel said to Gideon, “Rule over us, both you, and your son, and your son’s son also; for you have saved us out of the hand of Midian.”', pt: 'Então os homens de Israel disseram a Gideão: Domina sobre nós, assim tu, como teu filho, e o filho de teu filho; porquanto nos livraste da mão de Midiã.' },
      { v: 23, en: 'Gideon said to them, “I will not rule over you, neither shall my son rule over you. Yahweh shall rule over you.”', pt: 'Gideão, porém, lhes respondeu: Nem eu dominarei sobre vós, nem meu filho, mas o Senhor sobre vós dominará.' },
      { v: 24, en: 'Gideon said to them, “I do have a request, that you would each give me the earrings of his plunder.” (For they had golden earrings, because they were Ishmaelites.)', pt: 'Disse-lhes mais Gideão: uma petição vos farei: dá-me, cada um de vós, as arrecadas do despojo. (Porque os inimigos tinham arrecadas de ouro, porquanto eram ismaelitas) .' },
      { v: 25, en: 'They answered, “We will willingly give them.” They spread a garment, and every man threw the earrings of his plunder into it.', pt: 'Ao que disseram eles: De boa vontade as daremos. E estenderam uma capa, na qual cada um deles deitou as arrecadas do seu despojo.' },
      { v: 26, en: 'The weight of the golden earrings that he requested was one thousand and seven hundred shekels of gold, besides the crescents, and the pendants, and the purple clothing that was on the kings of Midian, and besides the chains that were about their camels’ necks.', pt: 'E foi o peso das arrecadas de ouro que ele pediu, mil e setecentos siclos de ouro, afora os crescentes, as cadeias e as vestes de púrpura que os reis de Midiã trajavam, afora as correntes que os camelos traziam ao pescoço.' },
      { v: 27, en: 'Gideon made an ephod out of it, and put it in Ophrah, his city. Then all Israel played the prostitute with it there; and it became a snare to Gideon, and to his house.', pt: 'Disso fez Gideão um éfode, e o pôs na sua cidade, em Ofra; e todo o Israel se prostituiu ali após ele; e foi um laço para Gideão e para sua casa.' },
      { v: 28, en: 'So Midian was subdued before the children of Israel, and they lifted up their heads no more. The land had rest forty years in the days of Gideon.', pt: 'Assim foram abatidos os midianitas diante dos filhos de Israel, e nunca mais levantaram a cabeça. E a terra teve sossego, por quarenta anos nos dias de Gideão.' },
      { v: 29, en: 'Jerubbaal the son of Joash went and lived in his own house.', pt: 'Então foi Jerubaal, filho de Joás, e habitou em sua casa.' },
      { v: 30, en: 'Gideon had seventy sons conceived from his body, for he had many wives.', pt: 'Gideão teve setenta filhos, que procederam da sua coxa, porque tinha muitas mulheres.' },
      { v: 31, en: 'His concubine who was in Shechem also bore him a son, and he named him Abimelech.', pt: 'A sua concubina que estava em Siquém deu-lhe também um filho; e pôs-lhe por nome Abimeleque.' },
      { v: 32, en: 'Gideon the son of Joash died in a good old age, and was buried in the tomb of Joash his father, in Ophrah of the Abiezrites.', pt: 'Morreu Gideão, filho de Joás, numa boa velhice, e foi sepultado no sepulcro de seu pai Joás, em Ofra dos abiezritas.' },
      { v: 33, en: 'As soon as Gideon was dead, the children of Israel turned again, and played the prostitute following the Baals, and made Baal Berith their god.', pt: 'Depois da morte de Gideão os filhos de Israel tornaram a se prostituir após os baalins, e puseram a Baal-Berite por deus.' },
      { v: 34, en: 'The children of Israel didn’t remember Yahweh their God, who had delivered them out of the hand of all their enemies on every side;', pt: 'Assim os filhos de Israel não se lembraram do Senhor seu Deus, que os livrara da mão de todos os seus inimigos ao redor;' },
      { v: 35, en: 'neither did they show kindness to the house of Jerubbaal, that is, Gideon, according to all the goodness which he had shown to Israel.', pt: 'nem usaram de beneficência para com a casa de Jerubaal, a saber, de Gideão, segundo todo o bem que ele havia feito a Israel.' },
    ],
    9: [
      { v: 1, en: 'Abimelech the son of Jerubbaal went to Shechem to his mother’s brothers, and spoke with them, and with all the family of the house of his mother’s father, saying,', pt: 'Abimeleque, filho de Jerubaal, foi a Siquém, aos irmãos de sua mãe, e falou-lhes, e a toda a parentela da casa de pai de sua mãe, dizendo:' },
      { v: 2, en: '“Please speak in the ears of all the men of Shechem, ‘Is it better for you that all the sons of Jerubbaal, who are seventy persons, rule over you, or that one rule over you?’ Remember also that I am your bone and your flesh.”', pt: 'Falai, peço-vos, aos ouvidos de todos os cidadãos de Siquém: Que é melhor para vós? que setenta homens, todos os filhos de Jerubaal, dominem sobre vós, ou que um só domine sobre vós? Lembrai-vos também de que sou vosso osso e vossa carne.' },
      { v: 3, en: 'His mother’s brothers spoke of him in the ears of all the men of Shechem all these words. Their hearts inclined to follow Abimelech; for they said, “He is our brother.”', pt: 'Então os irmãos de sua mãe falaram todas essas palavras a respeito dele aos ouvidos de todos os cidadãos de Siquém; e o coração deles se inclinou a seguir Abimeleque; pois disseram: E nosso irmão.' },
      { v: 4, en: 'They gave him seventy pieces of silver out of the house of Baal Berith, with which Abimelech hired vain and light fellows, who followed him.', pt: 'E deram-lhe setenta siclos de prata, da casa de Baal-Berite, com os quais alugou Abimeleque alguns homens ociosos e le9' },
      { v: 5, en: 'He went to his father’s house at Ophrah, and killed his brothers the sons of Jerubbaal, being seventy persons, on one stone: but Jotham the youngest son of Jerubbaal was left; for he hid himself.', pt: 'e foi à casa de seu pai, a Ofra, e matou a seus irmãos, os filhos de Jerubaal, setenta homens, sobre uma só pedra. Mas Jotão, filho menor de Jerubaal, ficou, porquanto se tinha escondido.' },
      { v: 6, en: 'All the men of Shechem assembled themselves together, and all the house of Millo, and went and made Abimelech king, by the oak of the pillar that was in Shechem.', pt: 'Então se ajuntaram todos os cidadãos de Siquém e toda a Bete-Milo, e foram, e constituíram rei a Abimeleque, junto ao carvalho da coluna que havia em Siquém.' },
      { v: 7, en: 'When they told it to Jotham, he went and stood on the top of Mount Gerizim, and lifted up his voice, cried out, and said to them, “Listen to me, you men of Shechem, that God may listen to you.', pt: 'Jotão, tendo sido avisado disso, foi e, pondo-se no cume do monte Gerizim, levantou a voz e clamou, dizendo: Ouvi-me a mim, cidadãos de Siquém, para que Deus: vos ouça a vos.' },
      { v: 8, en: 'The trees set out to anoint a king over themselves. They said to the olive tree, ‘Reign over us.’', pt: 'Foram uma vez as árvores a ungir para si um rei; e disseram à oliveira: Reina tu sobre nós.' },
      { v: 9, en: '“But the olive tree said to them, ‘Should I stop producing my oil, with which they honor God and man by me, and go to wave back and forth over the trees?’', pt: 'Mas a oliveira lhes respondeu: Deixaria eu a minha gordura, que Deus e os homens em mim prezam, para ir balouçar sobre as árvores?' },
      { v: 10, en: '“The trees said to the fig tree, ‘Come and reign over us.’', pt: 'Então disseram as árvores à figueira: Vem tu, e reina sobre nós.' },
      { v: 11, en: '“But the fig tree said to them, ‘Should I leave my sweetness, and my good fruit, and go to wave back and forth over the trees?’', pt: 'Mas a figueira lhes respondeu: Deixaria eu a minha doçura, o meu bom fruto, para ir balouçar sobre as árvores?' },
      { v: 12, en: '“The trees said to the vine, ‘Come and reign over us.’', pt: 'Disseram então as árvores à videira: Vem tu, e reina sobre nós.' },
      { v: 13, en: '“The vine said to them, ‘Should I leave my new wine, which cheers God and man, and go to wave back and forth over the trees?’', pt: 'Mas a videira lhes respondeu: Deixaria eu o meu mosto, que alegra a Deus e aos homens, para ir balouçar sobre as árvores?' },
      { v: 14, en: '“Then all the trees said to the bramble, ‘Come and reign over us.’', pt: 'Então todas as árvores disseram ao espinheiro: Vem tu, e reina sobre nós.' },
      { v: 15, en: '“The bramble said to the trees, ‘If in truth you anoint me king over you, then come and take refuge in my shade; and if not, let fire come out of the bramble, and devour the cedars of Lebanon.’', pt: 'O espinheiro, porém, respondeu às árvores: Se de boa fé me ungis por vosso rei, vinde refugiar-vos debaixo da minha sombra; mas, se não, saia fogo do espinheiro, e devore os cedros do Líbano.' },
      { v: 16, en: '“Now therefore, if you have dealt truly and righteously, in that you have made Abimelech king, and if you have dealt well with Jerubbaal and his house, and have done to him according to the deserving of his hands', pt: 'Agora, pois, se de boa fé e com retidão procedestes, constituindo rei a Abimeleque, e se bem fizestes para com Jerubaal e para com a sua casa, e se com ele usastes conforme o merecimento das suas mãos' },
      { v: 17, en: '(for my father fought for you, and risked his life, and delivered you out of the hand of Midian;', pt: '(porque meu pai pelejou por vós, desprezando a própria vida, e vos livrou da mão de Midiã;' },
      { v: 18, en: 'and you have risen up against my father’s house today, and have slain his sons, seventy persons, on one stone, and have made Abimelech, the son of his female servant, king over the men of Shechem, because he is your brother);', pt: 'porém vós hoje vos levantastes contra a casa de meu pai, e matastes a seus filhos, setenta homens, sobre uma só pedra; e a Abimeleque, filho da sua serva, fizestes reinar sobre os cidadãos de Siquém, porque é vosso irmão);' },
      { v: 19, en: 'if you then have dealt truly and righteously with Jerubbaal and with his house today, then rejoice in Abimelech, and let him also rejoice in you;', pt: 'se de boa fé e com retidão procedestes hoje para com Jerubaal e para com a sua casa, alegrai-vos em Abimeleque, e também ele se alegre em vós;' },
      { v: 20, en: 'but if not, let fire come out from Abimelech, and devour the men of Shechem, and the house of Millo; and let fire come out from the men of Shechem, and from the house of Millo, and devour Abimelech.”', pt: 'mas se não, saia fogo de Abimeleque, e devore os cidadãos de Siquém, e a Bete-Milo; e saia fogo dos cidadãos de Siquém e de Bete-Milo, e devore Abimeleque.' },
      { v: 21, en: 'Jotham ran away, and fled, and went to Beer, and lived there, for fear of Abimelech his brother.', pt: 'E partindo Jotão, fugiu e foi para Beer, e ali habitou, por medo de Abimeleque, seu irmão.' },
      { v: 22, en: 'Abimelech was prince over Israel three years.', pt: 'Havendo Abimeleque reinado três anos sobre Israel,' },
      { v: 23, en: 'Then God sent an evil spirit between Abimelech and the men of Shechem; and the men of Shechem dealt treacherously with Abimelech,', pt: 'Deus suscitou um espírito mau entre Abimeleque e os cidadãos de Siquém; e estes procederam aleivosamente para com Abimeleque;' },
      { v: 24, en: 'that the violence done to the seventy sons of Jerubbaal might come, and that their blood might be laid on Abimelech their brother, who killed them, and on the men of Shechem, who strengthened his hands to kill his brothers.', pt: 'para que a violência praticada contra os setenta filhos de Jerubaal, como também o sangue deles, recaíssem sobre Abimeleque, seu irmão, que os matara, e sobre os cidadãos de Siquém, que fortaleceram as mãos dele para matar a seus irmãos.' },
      { v: 25, en: 'The men of Shechem set an ambush for him on the tops of the mountains, and they robbed all who came along that way by them, and Abimelech was told about it.', pt: 'E os cidadãos de Siquém puseram de emboscada contra ele, sobre os cumes dos montes, homens que roubavam a todo aquele que passava por eles no caminho. E contou-se isto a Abimeleque.' },
      { v: 26, en: 'Gaal the son of Ebed came with his brothers, and went over to Shechem; and the men of Shechem put their trust in him.', pt: 'Também veio Gaal, filho de Ebede, com seus irmãos, e estabeleceu-se em Siquém; e confiaram nele os cidadãos de Siquém.' },
      { v: 27, en: 'They went out into the field, harvested their vineyards, trod the grapes, held festival, and went into the house of their god, and ate and drank, and cursed Abimelech.', pt: 'Saindo ao campo, vindimaram as suas vinhas, pisaram as uvas e fizeram uma festa; e, entrando na casa de seu deus, comeram e beberam, e amaldiçoaram a Abimeleque.' },
      { v: 28, en: 'Gaal the son of Ebed said, “Who is Abimelech, and who is Shechem, that we should serve him? Isn’t he the son of Jerubbaal? Isn’t Zebul his officer? Serve the men of Hamor the father of Shechem, but why should we serve him?', pt: 'E disse Gaal, filho de Ebede: Quem é Abimeleque, e quem é Siquém, para que sirvamos a Abimeleque? não é, porventura, filho de Jerubaal? e não é Zebul o seu mordomo? Servi antes aos homens de Hamor, pai de Siquém; pois, por que razão serviríamos nós a Abimeleque?' },
      { v: 29, en: 'I wish that this people were under my hand! Then I would remove Abimelech.” He said to Abimelech, “Increase your army, and come out!”', pt: 'Ah! se este povo estivesse sob a minha mão, eu transtornaria a Abimeleque. Eu lhe diria: Multiplica o teu exército, e vem.' },
      { v: 30, en: 'When Zebul the ruler of the city heard the words of Gaal the son of Ebed, his anger burned.', pt: 'Quando Zebul, o governador da cidade, ouviu as palavras de Gaal, filho de Ebede, acendeu-se em ira.' },
      { v: 31, en: 'He sent messengers to Abimelech craftily, saying, “Behold, Gaal the son of Ebed and his brothers have come to Shechem; and behold, they incite the city against you.', pt: 'E enviou secretamente mensageiros a Abimeleque, para lhe dizerem: Eis que Gaal, filho de Ebede, e seus irmãos vieram a Siquém, e estão sublevando a cidade contra ti.' },
      { v: 32, en: 'Now therefore, go up by night, you and the people who are with you, and lie in wait in the field.', pt: 'Levanta-te, pois, de noite, tu e o povo que tiveres contigo, e põe-te de emboscada no campo.' },
      { v: 33, en: 'It shall be that in the morning, as soon as the sun is up, you shall rise early, and rush on the city. Behold, when he and the people who are with him come out against you, then may you do to them as you shall find occasion.”', pt: 'E pela manhã, ao nascer do sol, levanta-te, e dá de golpe sobre a cidade; e, saindo contra ti Gaal e o povo que tiver com ele, faze-lhe como te permitirem as circunstâncias.' },
      { v: 34, en: 'Abimelech rose up, and all the people who were with him, by night, and they laid wait against Shechem in four companies.', pt: 'Levantou-se, pois, de noite Abimeleque, e todo o povo que com ele havia, e puseram emboscadas a Siquém, em quatro bandos.' },
      { v: 35, en: 'Gaal the son of Ebed went out, and stood in the entrance of the gate of the city. Abimelech rose up, and the people who were with him, from the ambush.', pt: 'E Gaal, filho de Ebede, saiu e pôs-se à entrada da porta da cidade; e das emboscadas se levantou Abimeleque, e todo o povo que estava com ele.' },
      { v: 36, en: 'When Gaal saw the people, he said to Zebul, “Behold, people are coming down from the tops of the mountains.” Zebul said to him, “You see the shadow of the mountains as if they were men.”', pt: 'Quando Gaal viu aquele povo, disse a Zebul: Eis que desce gente dos cumes dos montes. Respondeu-lhe Zebul: Tu vês as sombras dos montes como se fossem homens.' },
      { v: 37, en: 'Gaal spoke again and said, “Behold, people are coming down by the middle of the land, and one company comes by the way of the oak of Meonenim.”', pt: 'Gaal, porém, tornou a falar, e disse: Eis que desce gente do meio da terra; também vem uma tropa do caminho do carvalho de Meonenim.' },
      { v: 38, en: 'Then Zebul said to him, “Now where is your mouth, that you said, ‘Who is Abimelech, that we should serve him?’ Isn’t this the people that you have despised? Please go out now and fight with them.”', pt: 'Então lhe disse Zebul: Onde está agora a tua boca, com a qual dizias: Quem é Abimeleque, para que o sirvamos? Não é esse, porventura, o povo que desprezaste. Sai agora e peleja contra ele!' },
      { v: 39, en: 'Gaal went out before the men of Shechem, and fought with Abimelech.', pt: 'Assim saiu Gaal, à frente dos cidadãos de Siquém, e pelejou contra Abimeleque.' },
      { v: 40, en: 'Abimelech chased him, and he fled before him, and many fell wounded, even to the entrance of the gate.', pt: 'Mas Abimeleque o perseguiu, pois Gaal fugiu diante dele, e muitos caíram feridos até a entrada da porta.' },
      { v: 41, en: 'Abimelech lived at Arumah; and Zebul drove out Gaal and his brothers, that they should not dwell in Shechem.', pt: 'Abimeleque ficou em Arumá. E Zebul expulsou Gaal e seus irmãos, para que não habitassem em Siquém.' },
      { v: 42, en: 'On the next day, the people went out into the field; and they told Abimelech.', pt: 'No dia seguinte sucedeu que o povo saiu ao campo; disto foi avisado Abimeleque,' },
      { v: 43, en: 'He took the people, and divided them into three companies, and laid wait in the field; and he looked, and behold, the people came out of the city. So, he rose up against them, and struck them.', pt: 'o qual, tomando o seu povo, dividiu-o em três bandos, que pôs de emboscada no campo. Quando viu que o povo saía da cidade, levantou-se contra ele e o feriu.' },
      { v: 44, en: 'Abimelech and the companies that were with him rushed forward, and stood in the entrance of the gate of the city; and the two companies rushed on all who were in the field, and struck them.', pt: 'Abimeleque e os que estavam com ele correram e se puseram à porta da cidade; e os outros dois bandos deram de improviso sobre todos quantos estavam no campo, e os feriram.' },
      { v: 45, en: 'Abimelech fought against the city all that day; and he took the city, and killed the people in it. He beat down the city, and sowed it with salt.', pt: 'Abimeleque pelejou contra a cidade todo aquele dia, tomou-a e matou o povo que nela se achava; e, assolando-a, a semeou de sal.' },
      { v: 46, en: 'When all the men of the tower of Shechem heard of it, they entered into the stronghold of the house of Elberith.', pt: 'Tendo ouvido isso todos os cidadãos de Migdol-Siquém, entraram na fortaleza, na casa de El-Berite.' },
      { v: 47, en: 'Abimelech was told that all the men of the tower of Shechem were gathered together.', pt: 'E contou-se a Abimeleque que todos os cidadãos de Migbol-Siquém se haviam congregado.' },
      { v: 48, en: 'Abimelech went up to Mount Zalmon, he and all the people who were with him; and Abimelech took an ax in his hand, and cut down a bough from the trees, and took it up, and laid it on his shoulder. Then he said to the people who were with him, “What you have seen me do, make haste, and do as I have done!”', pt: 'Então Abimeleque subiu ao monte Zalmom, ele e todo o povo que com ele havia; e, tomando na mão um machado, cortou um ramo de árvore e, levantando-o, pô-lo ao seu ombro, e disse ao povo que estava com ele: O que me vistes fazer, apressai-vos a fazê-lo também.' },
      { v: 49, en: 'All the people likewise each cut down his bough, and followed Abimelech, and put them at the base of the stronghold, and set the stronghold on fire on them; so that all the people of the tower of Shechem died also, about a thousand men and women.', pt: 'Tendo, pois, cada um cortado o seu ramo, seguiram a Abimeleque; e, pondo os ramos junto da fortaleza, queimaram-na a fogo com os que nela estavam; de modo que morreram também todos os de Migdol-Siquém, cerca de mil homens e mulheres.' },
      { v: 50, en: 'Then Abimelech went to Thebez, and encamped against Thebez, and took it.', pt: 'Então Abimeleque foi a Tebez, e a sitiou e tomou.' },
      { v: 51, en: 'But there was a strong tower within the city, and all the men and women of the city fled there, and shut themselves in, and went up to the roof of the tower.', pt: 'Havia, porém, no meio da cidade uma torre forte, na qual se refugiaram todos os habitantes da cidade, homens e mulheres; e fechando após si as portas, subiram ao eirado da torre.' },
      { v: 52, en: 'Abimelech came to the tower, and fought against it, and came near to the door of the tower to burn it with fire.', pt: 'E Abimeleque, tendo chegado até a torre, atacou-a, e chegou-se à porta da torre, para lhe meter fogo.' },
      { v: 53, en: 'A certain woman cast an upper millstone on Abimelech’s head, and broke his skull.', pt: 'Nisso uma mulher lançou a pedra superior de um moinho sobre a cabeça de Abimeleque, e quebrou-lhe o crânio.' },
      { v: 54, en: 'Then he called hastily to the young man his armor bearer, and said to him, “Draw your sword, and kill me, that men not say of me, ‘A woman killed him.’ His young man thrust him through, and he died.”', pt: 'Então ele chamou depressa o moço, seu escudeiro, e disse-lhe: Desembainha a tua espada e mata-me, para que não se diga de mim: uma mulher o matou. E o moço o traspassou e ele morreu.' },
      { v: 55, en: 'When the men of Israel saw that Abimelech was dead, they each departed to his place.', pt: 'Vendo, pois, os homens de Israel que Abimeleque já era morto, foram-se cada um para o seu lugar.' },
      { v: 56, en: 'Thus God repaid the wickedness of Abimelech, which he did to his father, in killing his seventy brothers;', pt: 'Assim Deus fez tornar sobre Abimeleque o mal que tinha feito a seu pai, matando seus setenta irmãos;' },
      { v: 57, en: 'and God repaid all the wickedness of the men of Shechem on their heads; and the curse of Jotham the son of Jerubbaal came on them.', pt: 'como também fez tornar sobre a cabeça dos homens de Siquém todo o mal que fizeram; e veio sobre eles a maldição de Jotão, filho de Jerubaal.' },
    ],
    10: [
      { v: 1, en: 'After Abimelech, Tola the son of Puah, the son of Dodo, a man of Issachar, arose to save Israel. He lived in Shamir in the hill country of Ephraim.', pt: 'Depois de Abimeleque levantou-se, para livrar a Israel, Tola, filho de Puva, filho de Dodó, homem de Issacar, que habitava em Samir, na região montanhosa de Efraim.' },
      { v: 2, en: 'He judged Israel twenty-three years, and died, and was buried in Shamir.', pt: 'Ele julgou a Israel vinte e três anos; e morreu, e foi sepultado em Samir.' },
      { v: 3, en: 'After him Jair, the Gileadite arose, and he judged Israel twenty-two years.', pt: 'Depois dele levantou-se Jair, gileadita, que julgou a Israel vinte e dois anos.' },
      { v: 4, en: 'He had thirty sons who rode on thirty donkey colts, and they had thirty cities, which are called Havvoth Jair to this day, which are in the land of Gilead.', pt: 'Ele tinha trinta filhos, que cavalgavam sobre trinta jumentos; e tinham estes trinta cidades, que se chamam Havote-Jair, até a dia de hoje, as quais estão na terra de Gileade.' },
      { v: 5, en: 'Jair died, and was buried in Kamon.', pt: 'Morreu Jair, e foi sepultado em Camom.' },
      { v: 6, en: 'The children of Israel again did that which was evil in Yahweh’s sight, and served the Baals, the Ashtaroth, the gods of Syria, the gods of Sidon, the gods of Moab, the gods of the children of Ammon, and the gods of the Philistines. They abandoned Yahweh, and didn’t serve him.', pt: 'Então tornaram os filhos de Israel a fazer e que era mau aos olhos do Senhor, e serviram aos baalins, e às astarotes, e aos deuses da Síria, e aos de Sidom, e de Moabe, e dos amonitas, e dos filisteus; e abandonaram o Senhor, e não o serviram.' },
      { v: 7, en: 'Yahweh’s anger burned against Israel, and he sold them into the hand of the Philistines, and into the hand of the children of Ammon.', pt: 'Pelo que a ira do Senhor se acendeu contra Israel, e ele os vendeu na mão dos filisteus e na mão dos amonitas,' },
      { v: 8, en: 'They troubled and oppressed the children of Israel that year. For eighteen years, they oppressed all the children of Israel that were beyond the Jordan in the land of the Amorites, which is in Gilead.', pt: 'os quais naquele mesmo ano começaram a vexá-los e oprimi-los. Por dezoito anos oprimiram a todos os filhos de Israel que estavam dalém do Jordão, na terra dos amorreus, que é em Gileade.' },
      { v: 9, en: 'The children of Ammon passed over the Jordan to fight also against Judah, and against Benjamin, and against the house of Ephraim, so that Israel was very distressed.', pt: 'E os amonitas passaram o Jordão, para pelejar também contra Judá e Benjamim, e contra a casa de Efraim, de maneira que Israel se viu muito angustiado.' },
      { v: 10, en: 'The children of Israel cried to Yahweh, saying, “We have sinned against you, even because we have forsaken our God, and have served the Baals.”', pt: 'Então os filhos de Israel clamaram ao Senhor, dizendo: Pecamos contra ti, pois abandonamos o nosso Deus, e servimos aos baalins.' },
      { v: 11, en: 'Yahweh said to the children of Israel, “Didn’t I save you from the Egyptians, and from the Amorites, from the children of Ammon, and from the Philistines?', pt: 'O Senhor, porém, respondeu aos filhos de Israel: Porventura não vos livrei eu dos egipcios, dos amorreus, dos amonitas e dos filisteus?' },
      { v: 12, en: 'The Sidonians also, and the Amalekites, and the Maonites, oppressed you; and you cried to me, and I saved you out of their hand.', pt: 'Também os sidônios, os amalequitas e os maonitas vos oprimiram; e, quando clamastes a mim, não vos livrei da sua mão?' },
      { v: 13, en: 'Yet you have forsaken me, and served other gods. Therefore I will save you no more.', pt: 'Contudo vós me deixastes a mim e servistes a outros deuses, pelo que não vos livrarei mais.' },
      { v: 14, en: 'Go and cry to the gods which you have chosen. Let them save you in the time of your distress!”', pt: 'Ide e clamai aos deuses que escolhestes; que eles vos livrem no tempo da vossa angústia.' },
      { v: 15, en: 'The children of Israel said to Yahweh, “We have sinned! Do you to us whatever seems good to you; only deliver us, please, today.”', pt: 'Mas os filhos de Israel disseram ao Senhor: Pecamos; fazes-nos conforme tudo quanto te parecer bem; tão-somente te rogamos que nos livres hoje.' },
      { v: 16, en: 'They put away the foreign gods from among them, and served Yahweh; and his soul was grieved for the misery of Israel.', pt: 'E tiraram os deuses alheios do meio de si, e serviram ao Senhor, que se moveu de compaixão por causa da desgraça de Israel.' },
      { v: 17, en: 'Then the children of Ammon were gathered together and encamped in Gilead. The children of Israel assembled themselves together and encamped in Mizpah.', pt: 'Depois os amonitas se reuniram e acamparam em Gileade; também os filhos de Israel, reunindo-se, acamparam em Mizpá.' },
      { v: 18, en: 'The people, the princes of Gilead, said to one another, “Who is the man who will begin to fight against the children of Ammon? He shall be head over all the inhabitants of Gilead.”', pt: 'Então o povo, isto é, os príncipes de Gileade disseram uns aos outros: Quem será o varão que começará a peleja contra os amonitas? esse será o chefe de todos os habitantes de Gileade.' },
    ],
    11: [
      { v: 1, en: 'Now Jephthah the Gileadite was a mighty man of valor, and he was the son of a prostitute. Gilead became the father of Jephthah.', pt: 'Era então Jefté, o gileadita, homem valoroso, porém filho duma prostituta; Gileade era o pai dele.' },
      { v: 2, en: 'Gilead’s wife bore him sons. When his wife’s sons grew up, they drove Jephthah out, and said to him, “You will not inherit in our father’s house, for you are the son of another woman.”', pt: 'Também a mulher de Gileade lhe deu filhos; quando os filhos desta eram já grandes, expulsaram a Jefté, e lhe disseram: Não herdarás na casa de nosso pai, porque és filho de outra mulher.' },
      { v: 3, en: 'Then Jephthah fled from his brothers, and lived in the land of Tob. Outlaws joined up with Jephthah, and they went out with him.', pt: 'Então Jefté fugiu de diante de seus irmãos, e habitou na terra de Tobe; e homens levianos juntaram-se a Jefté, e saiam com ele.' },
      { v: 4, en: 'After a while, the children of Ammon made war against Israel.', pt: 'Passado algum tempo, os amonitas fizeram guerra a Israel.' },
      { v: 5, en: 'When the children of Ammon made war against Israel, the elders of Gilead went to get Jephthah out of the land of Tob.', pt: 'E, estando eles a guerrear contra Israel, foram os anciãos de Gileade para trazer Jefté da terra de Tobe,' },
      { v: 6, en: 'They said to Jephthah, “Come and be our chief, that we may fight with the children of Ammon.”', pt: 'e lhe disseram: Vem, sê o nosso chefe, para que combatamos contra os amonitas.' },
      { v: 7, en: 'Jephthah said to the elders of Gilead, “Didn’t you hate me, and drive me out of my father’s house? Why have you come to me now when you are in distress?”', pt: 'Jefté, porém, perguntou aos anciãos de Gileade: Porventura não me odiastes, e não me expulsastes da casa de meu pai? por que, pois, agora viestes a mim, quando estais em aperto?' },
      { v: 8, en: 'The elders of Gilead said to Jephthah, “Therefore we have turned again to you now, that you may go with us, and fight with the children of Ammon. You will be our head over all the inhabitants of Gilead.”', pt: 'Responderam-lhe os anciãos de Gileade: É por isso que tornamos a ti agora, para que venhas conosco, e combatas contra os amonitas, e nos sejas por chefe sobre todos os habitantes de Gileade.' },
      { v: 9, en: 'Jephthah said to the elders of Gilead, “If you bring me home again to fight with the children of Ammon, and Yahweh delivers them before me, will I be your head?”', pt: 'Então Jefté disse aos anciãos de Gileade: Se me fizerdes voltar para combater contra os amonitas, e o Senhor mos entregar diante de mim, então serei eu o vosso chefe.' },
      { v: 10, en: 'The elders of Gilead said to Jephthah, “Yahweh will be witness between us. Surely we will do what you say.”', pt: 'Responderam os anciãos de Gileade a Jefté: O Senhor será testemunha entre nós de que faremos conforme a tua palavra.' },
      { v: 11, en: 'Then Jephthah went with the elders of Gilead, and the people made him head and chief over them. Jephthah spoke all his words before Yahweh in Mizpah.', pt: 'Assim Jefté foi com os anciãos de Gileade, e o povo o pôs por cabeça e chefe sobre si; e Jefté falou todas as suas palavras perante o Senhor em Mizpá.' },
      { v: 12, en: 'Jephthah sent messengers to the king of the children of Ammon, saying, “What have you to do with me, that you have come to me to fight against my land?”', pt: 'Depois Jefté enviou mensageiros ao rei dos amonitas, para lhe dizerem: Que há entre mim e ti, que vieste a mim para guerrear contra a minha terra?' },
      { v: 13, en: 'The king of the children of Ammon answered to the messengers of Jephthah, “Because Israel took away my land, when he came up out of Egypt, from the Arnon even to the Jabbok, and to the Jordan. Now therefore restore that territory again peaceably.”', pt: 'Respondeu o rei dos amonitas aos mensageiros de Jefté: É porque Israel, quando subiu do Egito, tomou a minha terra, desde o Arnom até o Jaboque e o Jordão; restitui-me, pois, agora essas terras em paz.' },
      { v: 14, en: 'Jephthah sent messengers again to the king of the children of Ammon;', pt: 'Jefté, porém, tornou a enviar mensageiros ao rei dos amonitas,' },
      { v: 15, en: 'and he said to him, “Thus says Jephthah: Israel didn’t take away the land of Moab, nor the land of the children of Ammon,', pt: 'dizendo-lhe: Assim diz Jefté: Israel não tomou a terra de Moabe, nem a terra dos amonitas;' },
      { v: 16, en: 'but when they came up from Egypt, and Israel went through the wilderness to the Red Sea, and came to Kadesh;', pt: 'mas quando Israel subiu do Egito, andou pelo deserto até o Mar Vermelho, e depois chegou a Cades;' },
      { v: 17, en: 'then Israel sent messengers to the king of Edom, saying, ‘Please let me pass through your land;’ but the king of Edom didn’t listen. In the same way, he sent to the king of Moab; but he would not: and Israel stayed in Kadesh.', pt: 'dali enviou mensageiros ao rei de Edom, a dizer-lhe: Rogo-te que me deixes passar pela tua terra. Mas o rei de Edom não lhe deu ouvidos. Então enviou ao rei de Moabe, o qual também não consentiu; e assim Israel ficou em Cades.' },
      { v: 18, en: 'Then they went through the wilderness, and went around the land of Edom, and the land of Moab, and came by the east side of the land of Moab, and they encamped on the other side of the Arnon; but they didn’t come within the border of Moab, for the Arnon was the border of Moab.', pt: 'Depois andou pelo deserto e rodeou a terra de Edom e a terra de Moabe, e veio pelo lado oriental da terra de Moabe, e acampou além do Arnom; porém não entrou no território de Moabe, pois o Arnom era o limite de Moabe.' },
      { v: 19, en: 'Israel sent messengers to Sihon king of the Amorites, the king of Heshbon; and Israel said to him, ‘Please let us pass through your land to my place.’', pt: 'E Israel enviou mensageiros a Siom, rei dos amorreus, rei de Hesbom, e disse-lhe: Rogo-te que nos deixes passar pela tua terra até o meu lugar.' },
      { v: 20, en: 'But Sihon didn’t trust Israel to pass through his border; but Sihon gathered all his people together, and encamped in Jahaz, and fought against Israel.', pt: 'Siom, porém, não se fiou de Israel para o deixar passar pelo seu território; pelo contrário, ajuntando todo o seu povo, acampou em Jaza e combateu contra Israel.' },
      { v: 21, en: 'Yahweh, the God of Israel, delivered Sihon and all his people into the hand of Israel, and they struck them. So Israel possessed all the land of the Amorites, the inhabitants of that country.', pt: 'E o Senhor Deus de Israel entregou Siom com todo o seu povo na mão de Israel, que os feriu e se apoderou de toda a terra dos amorreus que habitavam naquela região.' },
      { v: 22, en: 'They possessed all the border of the Amorites, from the Arnon even to the Jabbok, and from the wilderness even to the Jordan.', pt: 'Apoderou-se de todo o território dos amorreus, desde o Arnom até o Jaboque, e desde o deserto até o Jordão.' },
      { v: 23, en: 'So now Yahweh, the God of Israel, has dispossessed the Amorites from before his people Israel, and should you possess them?', pt: 'Assim o Senhor Deus de Israel desapossou os amorreus de diante do seu povo de Israel; e possuirias tu esse território?' },
      { v: 24, en: 'Won’t you possess that which Chemosh your god gives you to possess? So whoever Yahweh our God has dispossessed from before us, them will we possess.', pt: 'Não possuirias tu o território daquele que Quemós, teu deus, desapossasse de diante de ti? assim possuiremos nós o território de todos quantos o Senhor nosso Deus desapossar de diante de nós.' },
      { v: 25, en: 'Now are you anything better than Balak the son of Zippor, king of Moab? Did he ever strive against Israel, or did he ever fight against them?', pt: 'Agora, és tu melhor do que Balaque, filho de Zipor, rei de Moabe? ousou ele jamais contender com Israel, ou lhe mover guerra?' },
      { v: 26, en: 'While Israel lived in Heshbon and its towns, and in Aroer and its towns, and in all the cities that are along by the side of the Arnon, three hundred years; why didn’t you recover them within that time?', pt: 'Enquanto Israel habitou trezentos anos em Hesbom e nas suas vilas, em Aroer e nas suas vilas em todas as cidades que estão ao longo do Arnom, por que não as recuperaste naquele tempo?' },
      { v: 27, en: 'I therefore have not sinned against you, but you do me wrong to war against me. May Yahweh the Judge be judge today between the children of Israel and the children of Ammon.”', pt: 'Não fui eu que pequei contra ti; és tu, porém, que usas de injustiça para comigo, fazendo-me guerra. O Senhor, que é juiz, julgue hoje entre os filhos de Israel e os amonitas.' },
      { v: 28, en: 'However the king of the children of Ammon didn’t listen to the words of Jephthah which he sent him.', pt: 'Contudo o rei dos amonitas não deu ouvidos à mensagem que Jefté lhe enviou.' },
      { v: 29, en: 'Then Yahweh’s Spirit came on Jephthah, and he passed over Gilead and Manasseh, and passed over Mizpah of Gilead, and from Mizpah of Gilead he passed over to the children of Ammon.', pt: 'Então o Espírito do Senhor veio sobre Jefté, de modo que ele passou por Gileade e Manassés, e chegando a Mizpá de Gileade, dali foi ao encontro dos amonitas.' },
      { v: 30, en: 'Jephthah vowed a vow to Yahweh, and said, “If you will indeed deliver the children of Ammon into my hand,', pt: 'E Jefté fez um voto ao Senhor, dizendo: Se tu me entregares na mão os amonitas,' },
      { v: 31, en: 'then it shall be, that whatever comes out of the doors of my house to meet me, when I return in peace from the children of Ammon, it shall be Yahweh’s, and I will offer it up for a burnt offering.”', pt: 'qualquer que, saindo da porta de minha casa, me vier ao encontro, quando eu, vitorioso, voltar dos amonitas, esse será do Senhor; eu o oferecerei em holocausto.' },
      { v: 32, en: 'So Jephthah passed over to the children of Ammon to fight against them; and Yahweh delivered them into his hand.', pt: 'Assim Jefté foi ao encontro dos amonitas, a combater contra eles; e o Senhor lhos entregou na mão.' },
      { v: 33, en: 'He struck them from Aroer until you come to Minnith, even twenty cities, and to Abelcheramim, with a very great slaughter. So the children of Ammon were subdued before the children of Israel.', pt: 'E Jefté os feriu com grande mortandade, desde Aroer até chegar a Minite, vinte cidades, e até Abel-Queramim. Assim foram subjugados os amonitas pelos filhos de Israel.' },
      { v: 34, en: 'Jephthah came to Mizpah to his house; and behold, his daughter came out to meet him with tambourines and with dances. She was his only child. Besides her he had neither son nor daughter.', pt: 'Quando Jefté chegou a Mizpá, à sua casa, eis que a sua filha lhe saiu ao encontro com adufes e com danças; e era ela a filha única; além dela não tinha outro filho nem filha.' },
      { v: 35, en: 'When he saw her, he tore his clothes, and said, “Alas, my daughter! You have brought me very low, and you are one of those who trouble me; for I have opened my mouth to Yahweh, and I can’t go back.”', pt: 'Logo que ele a viu, rasgou as suas vestes, e disse: Ai de mim, filha minha! muito me abateste; és tu a causa da minha desgraça! pois eu fiz, um voto ao Senhor, e não posso voltar atrás.' },
      { v: 36, en: 'She said to him, “My father, you have opened your mouth to Yahweh; do to me according to that which has proceeded out of your mouth, because Yahweh has taken vengeance for you on your enemies, even on the children of Ammon.”', pt: 'Ela lhe respondeu: Meu pai, se fizeste um voto ao Senhor, faze de mim conforme o teu voto, pois o Senhor te vingou dos teus inimigos, os filhos de Amom.' },
      { v: 37, en: 'She said to her father, “Let this thing be done for me. Leave me alone two months, that I may depart and go down on the mountains, and bewail my virginity, I and my companions.”', pt: 'Disse mais a seu pai: Concede-me somente isto: deixa-me por dois meses para que eu vá, e desça pelos montes, chorando a minha virgindade com as minhas companheiras.' },
      { v: 38, en: 'He said, “Go.” He sent her away for two months: and she departed, she and her companions, and mourned her virginity on the mountains.', pt: 'Disse ele: Vai. E deixou-a ir por dois meses; então ela se foi com as suas companheiras, e chorou a sua virgindade pelos montes.' },
      { v: 39, en: 'At the end of two months, she returned to her father, who did with her according to his vow which he had vowed. She was a virgin. It was a custom in Israel', pt: 'E sucedeu que, ao fim dos dois meses, tornou ela para seu pai, o qual cumpriu nela o voto que tinha feito; e ela não tinha conhecido varão. Daí veio o costume em Israel,' },
      { v: 40, en: 'that the daughters of Israel went yearly to celebrate the daughter of Jephthah the Gileadite four days in a year.', pt: 'de irem as filhas de Israel de ano em ano lamentar por quatro dias a filha de Jefté, o gileadita. Isso não é' },
    ],
    12: [
      { v: 1, en: 'The men of Ephraim were gathered together, and passed northward; and they said to Jephthah, “Why did you pass over to fight against the children of Ammon, and didn’t call us to go with you? We will burn your house around you with fire!”', pt: 'Então os homens de Efraim se congregaram, passaram para Zafom e disseram a Jefté: Por que passaste a combater contra os amonitas, e não nos chamaste para irmos contigo? Queimaremos a fogo a tua casa contigo.' },
      { v: 2, en: 'Jephthah said to them, “I and my people were at great strife with the children of Ammon; and when I called you, you didn’t save me out of their hand.', pt: 'Disse-lhes Jefté: Eu e o meu povo tivemos grande contenda com os amonitas; e quando vos chamei, não me livrastes da sua mão.' },
      { v: 3, en: 'When I saw that you didn’t save me, I put my life in my hand, and passed over against the children of Ammon, and Yahweh delivered them into my hand. Why then have you come up to me today, to fight against me?”', pt: 'Vendo eu que não me livráveis, arrisquei a minha vida e fui de encontro aos amonitas, e o Senhor mos entregou nas mãos; por que, pois, subistes vós hoje para combater contra mim?' },
      { v: 4, en: 'Then Jephthah gathered together all the men of Gilead, and fought with Ephraim. The men of Gilead struck Ephraim, because they said, “You are fugitives of Ephraim, you Gileadites, in the middle of Ephraim, and in the middle of Manasseh.”', pt: 'Depois ajuntou Jefté todos os homens de Gileade, e combateu contra Efraim, e os homens de Gileade feriram a Efraim; porque este lhes dissera: Fugitivos sois de Efraim, vós gileaditas que habitais entre Efraim e Manassés.' },
      { v: 5, en: 'The Gileadites took the fords of the Jordan against the Ephraimites. When the fugitives of Ephraim said, “Let me go over,” the men of Gilead said to him, “Are you an Ephraimite?” If he said, “No”;', pt: 'E tomaram os gileaditas aos efraimitas os vaus do Jordão; e quando algum dos fugitivos de Efraim diza: Deixai-me passar; então os homens de Gileade lhe perguntavam: És tu efraimita? E dizendo ele: Não;' },
      { v: 6, en: 'then they said to him, “Now say ‘Shibboleth;’” and he said “Sibboleth”; for he couldn’t manage to pronounce it right: then they seized him, and killed him at the fords of the Jordan. At that time, forty-two thousand of Ephraim fell.', pt: 'então lhe diziam: Dize, pois, Chibolete; porém ele dizia: Sibolete, porque não o podia pronunciar bem. Então pegavam dele, e o degolavam nos vaus do Jordão. Cairam de Efraim naquele tempo quarenta e dois mil.' },
      { v: 7, en: 'Jephthah judged Israel six years. Then Jephthah the Gileadite died, and was buried in the cities of Gilead.', pt: 'Jefté julgou a Israel seis anos; e morreu Jefté, o gileadita, e foi sepultado numa das cidades de Gileade.' },
      { v: 8, en: 'After him Ibzan of Bethlehem judged Israel.', pt: 'Depois dele julgou a Israel Ibzã de Belém.' },
      { v: 9, en: 'He had thirty sons; and thirty daughters he sent outside his clan, and thirty daughters he brought in from outside his clan for his sons. He judged Israel seven years.', pt: 'Tinha este trinta filhos, e trinta filhas que casou fora; e trinta filhas trouxe de fora para seus filhos. E julgou a Israel sete anos.' },
      { v: 10, en: 'Ibzan died, and was buried at Bethlehem.', pt: 'Morreu Ibzã, e foi sepultado em Belém.' },
      { v: 11, en: 'After him Elon the Zebulunite judged Israel; and he judged Israel ten years.', pt: 'Depois dele Elom, o zebulonita, julgou a Israel dez anos.' },
      { v: 12, en: 'Elon the Zebulunite died, and was buried in Aijalon in the land of Zebulun.', pt: 'Morreu Elom, o zebulonita, e foi sepultado em Aijalom, na terra de Zebulom.' },
      { v: 13, en: 'After him Abdon the son of Hillel the Pirathonite judged Israel.', pt: 'Depois dele julgou a Israel Abdom, filho de Hilel, o piratonita.' },
      { v: 14, en: 'He had forty sons and thirty sons’ sons, who rode on seventy donkey colts. He judged Israel eight years.', pt: 'Tinha este quarenta filhos e trinta netos, que cavalgavam sobre setenta jumentos. E julgou a Israel oito anos.' },
      { v: 15, en: 'Abdon the son of Hillel the Pirathonite died, and was buried in Pirathon in the land of Ephraim, in the hill country of the Amalekites.', pt: 'Morreu Abdom, filho de Hilel, o piratonita, e foi sepultado em Piratom, na terra de Efraim, na região montanhosa dos amalequitas.' },
    ],
    13: [
      { v: 1, en: 'The children of Israel again did that which was evil in Yahweh’s sight; and Yahweh delivered them into the hand of the Philistines forty years.', pt: 'Os filhos de Israel tornaram a fazer o que era mau aos olhos do Senhor, e ele os entregou na mão dos filisteus por quarenta anos.' },
      { v: 2, en: 'There was a certain man of Zorah, of the family of the Danites, whose name was Manoah; and his wife was barren, and childless.', pt: 'Havia um homem de Zorá, da tribo de Dã, cujo nome era Manoá; e sua mulher, sendo estéril, não lhe dera filhos.' },
      { v: 3, en: 'Yahweh’s angel appeared to the woman, and said to her, “See now, you are barren and childless; but you shall conceive, and bear a son.', pt: 'Mas o anjo do Senhor apareceu à mulher e lhe disse: Eis que és estéril, e nunca deste à luz; porém conceberás, e terás um filho.' },
      { v: 4, en: 'Now therefore please beware and drink no wine nor strong drink, and don’t eat any unclean thing:', pt: 'Agora pois, toma cuidado, e não bebas vinho nem bebida forte, e não comas coisa alguma impura;' },
      { v: 5, en: 'for, behold, you shall conceive, and give birth to a son. No razor shall come on his head; for the child shall be a Nazirite to God from the womb. He shall begin to save Israel out of the hand of the Philistines.”', pt: 'porque tu conceberás e terás um filho, sobre cuja cabeça não passará navalha, porquanto o menino será nazireu de Deus desde o ventre de sua mãe; e ele começara a livrar a Israel da mão dos filisteus.' },
      { v: 6, en: 'Then the woman came and told her husband, saying, “A man of God came to me, and his face was like the face of the angel of God, very awesome. I didn’t ask him where he was from, neither did he tell me his name;', pt: 'Então a mulher entrou, e falou a seu marido, dizendo: Veio a mim um homem de Deus, cujo semblante era como o de um anjo de Deus, em extremo terrível; e não lhe perguntei de onde era, nem ele me disse o seu nome;' },
      { v: 7, en: 'but he said to me, ‘Behold, you shall conceive, and bear a son; and now drink no wine nor strong drink. Don’t eat any unclean thing; for the child shall be a Nazirite to God from the womb to the day of his death.’”', pt: 'porém disse-me: Eis que tu conceberás e terás um filho. Agora pois, não bebas vinho nem bebida forte, e não comas coisa impura; porque o menino sera nazireu de Deus, desde o ventre de sua mãe até o dia da sua morte.' },
      { v: 8, en: 'Then Manoah entreated Yahweh, and said, “Oh, Lord, please let the man of God whom you sent come again to us, and teach us what we should do to the child who shall be born.”', pt: 'Então Manoá suplicou ao Senhor, dizendo: Ah! Senhor meu, rogo-te que o homem de Deus, que enviaste, venha ter conosco outra vez e nos ensine o que devemos fazer ao menino que há de nascer.' },
      { v: 9, en: 'God listened to the voice of Manoah, and the angel of God came again to the woman as she sat in the field, but Manoah, her husband, wasn’t with her.', pt: 'Deus ouviu a voz de Manoá; e o anjo de Deus veio outra vez ter com a mulher, estando ela sentada no campo, porém não estava com ela seu marido, Manoá.' },
      { v: 10, en: 'The woman hurried and ran, and told her husband, and said to him, “Behold, the man who came to me that day has appeared to me,”', pt: 'Apressou-se, pois, a mulher e correu para dar a notícia a seu marido, e disse-lhe: Eis que me apareceu aquele homem que veio ter comigo o outro dia.' },
      { v: 11, en: 'Manoah arose, and followed his wife, and came to the man, and said to him, “Are you the man who spoke to my wife?” He said, “I am.”', pt: 'Então Manoá se levantou, seguiu a sua mulher e, chegando à presença do homem, perguntou-lhe: És tu o homem que falou a esta mulher? Ele respondeu: Sou eu.' },
      { v: 12, en: 'Manoah said, “Now let your words happen. What shall the child’s way of life and mission be?”', pt: 'Então disse Manoá: Quando se cumprirem as tuas palavras, como se há de criar o menino e que fará ele?' },
      { v: 13, en: 'Yahweh’s angel said to Manoah, “Of all that I said to the woman let her beware.', pt: 'Respondeu o anjo do Senhor a Manoá: De tudo quanto eu disse à mulher se guardará ela;' },
      { v: 14, en: 'She may not eat of anything that comes of the vine, neither let her drink wine or strong drink, nor eat any unclean thing. Let her observe all that I commanded her.”', pt: 'de nenhum produto da vinha comerá; não beberá vinho nem bebida forte, nem comerá coisa impura; tudo quanto lhe ordenei cumprirá.' },
      { v: 15, en: 'Manoah said to Yahweh’s angel, “Please stay with us, that we may make a young goat ready for you.”', pt: 'Então Manoá disse ao anjo do Senhor: Deixa que te detenhamos, para que te preparemos um cabrito.' },
      { v: 16, en: 'Yahweh’s angel said to Manoah, “Though you detain me, I won’t eat your bread. If you will prepare a burnt offering, you must offer it to Yahweh.” For Manoah didn’t know that he was Yahweh’s angel.', pt: 'Disse, porém, o anjo do Senhor a Manoá: Ainda que me detenhas, não comerei de teu pão; e se fizeres holocausto, é ao Senhor que o oferecerás. (Pois Manoá não sabia que era o anjo do Senhor).' },
      { v: 17, en: 'Manoah said to Yahweh’s angel, “What is your name, that when your words happen, we may honor you?”', pt: 'Ainda perguntou Manoá ao anjo do Senhor: Qual é o teu nome? - para que, quando se cumprir a tua palavra, te honremos.' },
      { v: 18, en: 'Yahweh’s angel said to him, “Why do you ask about my name, since it is incomprehensible ?”', pt: 'Ao que o anjo do Senhor lhe respondeu: Por que perguntas pelo meu nome, visto que é maravilhoso?' },
      { v: 19, en: 'So Manoah took the young goat with the meal offering, and offered it on the rock to Yahweh. Then the angel did an amazing thing as Manoah and his wife watched.', pt: 'Então Manoá tomou um cabrito com a oferta de cereais, e o ofereceu sobre a pedra ao Senhor; e fez o anjo maravilhas, enquanto Manoá e sua mulher o observavam.' },
      { v: 20, en: 'For when the flame went up toward the sky from off the altar, Yahweh’s angel ascended in the flame of the altar. Manoah and his wife watched; and they fell on their faces to the ground.', pt: 'Ao subir a chama do altar para o céu, subiu com ela o anjo do Senhor; o que vendo Manoá e sua mulher, caíram com o rosto em terra.' },
      { v: 21, en: 'But Yahweh’s angel didn’t appear to Manoah or to his wife any more. Then Manoah knew that he was Yahweh’s angel.', pt: 'E não mais apareceu o anjo do Senhor a Manoá, nem à sua mulher; então compreendeu Manoá que era o anjo do Senhor.' },
      { v: 22, en: 'Manoah said to his wife, “We shall surely die, because we have seen God.”', pt: 'Disse Manoá a sua mulher: Certamente morreremos, porquanto temos visto a Deus.' },
      { v: 23, en: 'But his wife said to him, “If Yahweh were pleased to kill us, he wouldn’t have received a burnt offering and a meal offering at our hand, and he wouldn’t have shown us all these things, nor would he have told us such things as these at this time.”', pt: 'Sua mulher, porém, lhe respondeu: Se o Senhor nos quisera matar, não teria recebido da nossa mão o holocausto e a oferta de cereais, nem nos teria mostrado todas estas coisas, nem agora nos teria dito semelhantes coisas.' },
      { v: 24, en: 'The woman bore a son, and named him Samson. The child grew, and Yahweh blessed him.', pt: 'Depois teve esta mulher um filho, a quem pôs o nome de Sansão; e o menino cresceu, e o Senhor o abençoou.' },
      { v: 25, en: 'Yahweh’s Spirit began to move him in Mahaneh Dan, between Zorah and Eshtaol.', pt: 'E o Espírito do Senhor começou a incitá-lo em Maané-Dã, entre Zorá e Estaol.' },
    ],
    14: [
      { v: 1, en: 'Samson went down to Timnah, and saw a woman in Timnah of the daughters of the Philistines.', pt: 'Desceu Sansão a Timnate; e vendo em Timnate uma mulher das filhas dos filisteus,' },
      { v: 2, en: 'He came up, and told his father and his mother, and said, “I have seen a woman in Timnah of the daughters of the Philistines. Now therefore get her for me as my wife.”', pt: 'subiu, e declarou-o a seu pai e a sua mãe, dizendo: Vi uma mulher em Timnate, das filhas dos filisteus; agora pois, tomai-ma por mulher.' },
      { v: 3, en: 'Then his father and his mother said to him, “Isn’t there a woman among your brothers’ daughters, or among all my people, that you go to take a wife of the uncircumcised Philistines?” Samson said to his father, “Get her for me, for she pleases me well.”', pt: 'Responderam-lhe, porém, seu pai e sua mãe: Não há, porventura, mulher entre as filhas de teus irmãos, nem entre todo o nosso povo, para que tu vás tomar mulher dos filisteus, daqueles incircuncisos? Disse, porém, Sansão a seu pai: Toma esta para mim, porque ela muito me agrada.' },
      { v: 4, en: 'But his father and his mother didn’t know that it was of Yahweh; for he sought an occasion against the Philistines. Now at that time the Philistines ruled over Israel.', pt: 'Mas seu pai e sua mãe não sabiam que isto vinha do Senhor, que buscava ocasião contra os filisteus; porquanto naquele tempo os filisteus dominavam sobre Israel.' },
      { v: 5, en: 'Then went Samson down with his father and his mother to Timnah, and came to the vineyards of Timnah; and behold, a young lion roared against him.', pt: 'Desceu, pois, Sansão com seu pai e com sua mãe a Timnate. E, chegando ele às vinhas de Timnate, um leão novo, rugindo, saiu-lhe ao encontro.' },
      { v: 6, en: 'Yahweh’s Spirit came mightily on him, and he tore him as he would have torn a young goat; and he had nothing in his hand, but he didn’t tell his father or his mother what he had done.', pt: 'Então o Espírito do Senhor se apossou dele, de modo que ele, sem ter coisa alguma na mão, despedaçou o leão como se fosse um cabrito. E não disse nem a seu pai nem a sua mãe o que tinha feito.' },
      { v: 7, en: 'He went down, and talked with the woman, and she pleased Samson well.', pt: 'Depois desceu e falou àquela mulher; e ela muito lhe agradou.' },
      { v: 8, en: 'After a while he returned to take her; and he went over to see the carcass of the lion; and behold, there was a swarm of bees in the body of the lion, and honey.', pt: 'Passado algum tempo, Sansão voltou para recebê-la; e apartando-se de caminho para ver o cadáver do leão, eis que nele havia um enxame de abelhas, e mel.' },
      { v: 9, en: 'He took it into his hands, and went on, eating as he went. He came to his father and mother, and gave to them, and they ate, but he didn’t tell them that he had taken the honey out of the lion’s body.', pt: 'E tirando-o nas mãos, foi andando e comendo dele; chegando aonde estavam seu pai e sua mãe, deu-lhes do mel, e eles comeram; porém não lhes disse que havia tirado o mel do corpo do leão.' },
      { v: 10, en: 'His father went down to the woman; and Samson made a feast there, for the young men used to do so.', pt: 'Desceu, pois, seu pai à casa da mulher; e Sansão fez ali um banquete, porque assim os mancebos costumavam fazer.' },
      { v: 11, en: 'When they saw him, they brought thirty companions to be with him.', pt: 'E sucedeu que, quando os habitantes do lugar o viram, trouxeram trinta companheiros para estarem com ele.' },
      { v: 12, en: 'Samson said to them, “Let me tell you a riddle now. If you can declare it to me within the seven days of the feast, and find it out, then I will give you thirty linen garments and thirty changes of clothing;', pt: 'Disse-lhes, pois, Sansão: Permiti-me propor-vos um enigma; se nos sete dias das bodas o decifrardes e mo descobrirdes, eu vos darei trinta túnicas de linho e trinta mantos;' },
      { v: 13, en: 'but if you can’t declare it to me, then you shall give me thirty linen garments and thirty changes of clothing.” They said to him, “Tell us your riddle, that we may hear it.”', pt: 'mas se não puderdes decifrar, vós me dareis a mim as trinta túnicas de linho e os trinta mantos. Ao que lhe responderam eles: Propõe o teu enigma, para que o ouçamos.' },
      { v: 14, en: 'He said to them, “Out of the eater came out food. Out of the strong came out sweetness.” They couldn’t in three days declare the riddle.', pt: 'Então lhes disse: Do que come saiu comida, e do forte saiu doçura. E em três dias não puderam decifrar o enigma.' },
      { v: 15, en: 'On the seventh day, they said to Samson’s wife, “Entice your husband, that he may declare to us the riddle, lest we burn you and your father’s house with fire. Have you called us to impoverish us? Isn’t that so?”', pt: 'Ao quarto dia, pois, disseram à mulher de Sansão: Persuade teu marido a que declare o enigma, para que não queimemos a fogo a ti e à casa de teu pai. Acaso nos convidastes para nos despojardes?' },
      { v: 16, en: 'Samson’s wife wept before him, and said, “You just hate me, and don’t love me. You’ve told a riddle to the children of my people, and haven’t told it to me.” He said to her, “Behold, I haven’t told my father or my mother, so why should I tell you?”', pt: 'E a mulher de Sansão chorou diante dele, e disse: Tão-somente me aborreces, e não me amas; pois propuseste aos filhos do meu povo um enigma, e não mo declaraste a mim. Respondeu-lhe ele: Eis que nem a meu pai nem a minha mãe o declarei, e to declararei a ti.' },
      { v: 17, en: 'She wept before him the seven days, while their feast lasted; and on the seventh day, he told her, because she pressed him severely; and she told the riddle to the children of her people.', pt: 'Assim ela chorava diante dele os sete dias em que celebravam as bodas. Sucedeu, pois, que ao sétimo dia lho declarou, porquanto o importunava; então ela declarou o enigma aos filhos do seu povo.' },
      { v: 18, en: 'The men of the city said to him on the seventh day before the sun went down, “What is sweeter than honey? What is stronger than a lion?” He said to them, “If you hadn’t plowed with my heifer, you wouldn’t have found out my riddle.”', pt: 'Os homens da cidade, pois, ainda no sétimo dia, antes de se pôr o sol, disseram a Sansão: Que coisa há mais doce do que o mel? e que coisa há mais forte do que o leão? Respondeu-lhes ele: Se vós não tivésseis lavrado com a minha novilha, não teríeis descoberto o meu enigma.' },
      { v: 19, en: 'Yahweh’s Spirit came mightily on him, and he went down to Ashkelon, and struck thirty men of them, and took their plunder, then gave the changes of clothing to those who declared the riddle. His anger burned, and he went up to his father’s house.', pt: 'Então o Espírito do Senhor se apossou dele, de modo que desceu a Asquelom, matou trinta dos seus homens e, tomando as suas vestes, deu-as aos que declararam o enigma; e, ardendo em ira, subiu à casa de seu pai.' },
      { v: 20, en: 'But Samson’s wife was given to his companion who had been his friend.', pt: 'E a mulher de Sansão foi dada ao seu companheiro, que lhe servira de paraninfo.:' },
    ],
    15: [
      { v: 1, en: 'But after a while, in the time of wheat harvest, Samson visited his wife with a young goat. He said, “I will go in to my wife’s room.” But her father wouldn’t allow him to go in.', pt: 'Alguns dias depois disso, durante a ceifa do trigo, Sansão, levando um cabrito, foi visitar a sua mulher, e disse: Entrarei na câmara de minha mulher. Mas o pai dela não o deixou entrar,' },
      { v: 2, en: 'Her father said, “I most certainly thought that you utterly hated her; therefore I gave her to your companion. Isn’t her younger sister more beautiful than she? Please take her, instead.”', pt: 'dizendo-lhe: Na verdade, pensava eu que de todo a aborrecias; por isso a dei ao teu companheiro. Não é, porém, mais formosa do que ela a sua irmã mais nova? Toma-a, pois, em seu lugar.' },
      { v: 3, en: 'Samson said to them, “This time I will be blameless in the case of the Philistines, when I harm them.”', pt: 'Então Sansão lhes disse: De agora em diante estarei sem culpa para com os filisteus, quando lhes fizer algum mal.' },
      { v: 4, en: 'Samson went and caught three hundred foxes, and took torches, and turned tail to tail, and put a torch in the middle between every two tails.', pt: 'E Sansão foi, apanhou trezentas raposas, tomou fachos e, juntando as raposas cauda a cauda, pôs-lhes um facho entre cada par de caudas.' },
      { v: 5, en: 'When he had set the torches on fire, he let them go into the standing grain of the Philistines, and burned up both the shocks and the standing grain, and also the olive groves.', pt: 'E tendo chegado fogo aos fachos, largou as raposas nas searas dos filisteus:, e assim abrasou tanto as medas como o trigo ainda em pé as vinhas e os olivais.' },
      { v: 6, en: 'Then the Philistines said, “Who has done this?” They said, “Samson, the son-in-law of the Timnite, because he has taken his wife, and given her to his companion.” The Philistines came up, and burned her and her father with fire.', pt: 'Perguntaram os filisteus: Quem fez isto? Respondeu-se-lhes: Sansão, o genro do timnita, porque este lhe tomou a sua mulher, e a deu ao seu companheiro. Subiram, pois, os filisteus, e queimaram a fogo a ela e a seu pai.' },
      { v: 7, en: 'Samson said to them, “If you behave like this, surely I will take revenge on you, and after that I will cease.”', pt: 'Disse-lhes Sansão: É assim que fazeis? pois só cessarei quando me houver vingado de vós.' },
      { v: 8, en: 'He struck them hip and thigh with a great slaughter; and he went down and lived in the cave in Etam’s rock.', pt: 'E de todo os desbaratou, infligindo-lhes grande mortandade. Então desceu, e habitou na fenda do penhasco de Etã.' },
      { v: 9, en: 'Then the Philistines went up, encamped in Judah, and spread themselves in Lehi.', pt: 'Então os filisteus subiram, acamparam-se em Judá, e estenderam-se por Leí.' },
      { v: 10, en: 'The men of Judah said, “Why have you come up against us?” They said, “We have come up to bind Samson, to do to him as he has done to us.”', pt: 'Perguntaram-lhes os homens de Judá: Por que subistes contra nós. E eles responderam: Subimos para amarrar a Sansão, para lhe fazer como ele nos fez.' },
      { v: 11, en: 'Then three thousand men of Judah went down to the cave in Etam’s rock, and said to Samson, “Don’t you know that the Philistines are rulers over us? What then is this that you have done to us?” He said to them, “As they did to me, so I have done to them.”', pt: 'Então três mil homens de Judá desceram até a fenda do penhasco de Etã, e disseram a Sansão: Não sabias tu que os filisteus dominam sobre nós? por que, pois, nos fizeste isto? E ele lhes disse: Assim como eles me fizeram a mim, eu lhes fiz a eles.' },
      { v: 12, en: 'They said to him, “We have come down to bind you, that we may deliver you into the hand of the Philistines.” Samson said to them, “Swear to me that you will not attack me yourselves.”', pt: 'Tornaram-lhe eles: Descemos para amarrar-te, a fim de te entregar nas mãos dos filisteus. Disse-lhes Sansão: Jurai-me que vós mesmos não me acometereis.' },
      { v: 13, en: 'They spoke to him, saying, “No; but we will bind you securely, and deliver you into their hands; but surely we will not kill you.” They bound him with two new ropes, and brought him up from the rock.', pt: 'Eles lhe responderam: Não, não te mataremos, mas apenas te amarraremos, e te entregaremos nas mãos deles. E amarrando-o com duas cordas novas, tiraram-no do penhasco.' },
      { v: 14, en: 'When he came to Lehi, the Philistines shouted as they met him. Then Yahweh’s Spirit came mightily on him, and the ropes that were on his arms became as flax that was burned with fire, and his bands dropped from off his hands.', pt: 'Quando ele chegou a Leí, os filisteus lhe saíram ao encontro, jubilando. Então o Espírito do Senhor se apossou dele, e as cordas que lhe ligavam os braços se tornaram como fios de linho que estão queimados do fogo, e as suas amarraduras se desfizeram das suas mãos.' },
      { v: 15, en: 'He found a fresh jawbone of a donkey, put out his hand, took it, and struck a thousand men with it.', pt: 'E achou uma queixada fresca de jumento e, estendendo a mão, tomou-a e com ela matou mil homens.' },
      { v: 16, en: 'Samson said, “With the jawbone of a donkey, heaps on heaps; with the jawbone of a donkey I have struck a thousand men.”', pt: 'Disse Sansão: Com a queixada de um jumento montões e mais montões! Sim, com a queixada de um jumento matei mil homens.' },
      { v: 17, en: 'When he had finished speaking, he threw the jawbone out of his hand; and that place was called Ramath Lehi.', pt: 'E acabando ele de falar, lançou da sua mão a queixada; e chamou-se aquele lugar Ramá-Leí.' },
      { v: 18, en: 'He was very thirsty, and called on Yahweh, and said, “You have given this great deliverance by the hand of your servant; and now shall I die of thirst, and fall into the hands of the uncircumcised?”', pt: 'Depois, como tivesse grande sede, clamou ao Senhor, e disse: Pela mão do teu servo tu deste este grande livramento; e agora morrerei eu de sede, e cairei nas mãos destes incircuncisos?' },
      { v: 19, en: 'But God split the hollow place that is in Lehi, and water came out of it. When he had drunk, his spirit came again, and he revived. Therefore its name was called En Hakkore, which is in Lehi, to this day.', pt: 'Então o Senhor abriu a fonte que está em Leí, e dela saiu água; e Sansão, tendo bebido, recobrou alento, e reviveu; pelo que a fonte ficou sendo chamada En-Hacore, a qual está em Leí até o dia de hoje.' },
      { v: 20, en: 'He judged Israel twenty years in the days of the Philistines.', pt: 'E julgou a Israel, nos dias dos filisteus, vinte anos.' },
    ],
    16: [
      { v: 1, en: 'Samson went to Gaza, and saw there a prostitute, and went in to her.', pt: 'Sansão foi a Gaza, e viu ali uma prostituta, e entrou a ela.' },
      { v: 2, en: 'The Gazites were told, “Samson is here!” They surrounded him, and laid wait for him all night in the gate of the city, and were quiet all the night, saying, “Wait until morning light, then we will kill him.”', pt: 'E foi dito aos gazitas: Sansão entrou aqui. Cercaram-no, pois, e de emboscada à porta da cidade o esperaram toda a noite; assim ficaram quietos a noite toda, dizendo: Quando raiar o dia, matá-lo-emos.' },
      { v: 3, en: 'Samson lay until midnight, and arose at midnight, and laid hold of the doors of the gate of the city, and the two posts, and plucked them up, bar and all, and put them on his shoulders, and carried them up to the top of the mountain that is before Hebron.', pt: 'Mas Sansão deitou-se até a meia-noite; então, levantando-se, pegou nas portas da entrada da cidade, com ambos os umbrais, arrancou-as juntamente com a tranca e, pondo-as sobre os ombros, levou-as até o cume do monte que está defronte de Hebrom.' },
      { v: 4, en: 'It came to pass afterward, that he loved a woman in the valley of Sorek, whose name was Delilah.', pt: 'Depois disto se afeiçoou a uma mulher do vale de Soreque, cujo nome era Dalila.' },
      { v: 5, en: 'The lords of the Philistines came up to her, and said to her, “Entice him, and see in which his great strength lies, and by what means we may prevail against him, that we may bind him to afflict him; and we will each give you eleven hundred pieces of silver.”', pt: 'Então os chefes dos filisteus subiram a ter com ela, e lhe disseram: Persuade-o, e vê em que consiste a sua grande força, e como poderemos prevalecer contra ele e amarrá-lo, para assim o afligirmos; e te daremos, cada um de nós, mil e cem moedas de prata.' },
      { v: 6, en: 'Delilah said to Samson, “Please tell me where your great strength lies, and what you might be bound to afflict you.”', pt: 'Disse, pois, Dalila a Sansão: Declara-me, peço-te, em que consiste a tua grande força, e com que poderias ser amarrado para te poderem afligir.' },
      { v: 7, en: 'Samson said to her, “If they bind me with seven green cords that were never dried, then shall I become weak, and be as another man.”', pt: 'Respondeu-lhe Sansão: Se me amarrassem com sete cordas de nervos, ainda não secados, então me tornaria fraco, e seria como qualquer outro homem.' },
      { v: 8, en: 'Then the lords of the Philistines brought up to her seven green cords which had not been dried, and she bound him with them.', pt: 'Então os chefes dos filisteus trouxeram a Dalila sete cordas de nervos, ainda não secados, com as quais ela o amarrou.' },
      { v: 9, en: 'Now she had an ambush waiting in the inner room. She said to him, “The Philistines are on you, Samson!” He broke the cords, as a string of tow is broken when it touches the fire. So his strength was not known.', pt: 'Ora, tinha ela em casa uns espias sentados na câmara interior. Então ela disse: Os filisteus vêm sobre ti, Sansão! E ele quebrou as cordas de nervos, como se quebra o fio da estopa ao lhe chegar o fogo. Assim não se soube em que consistia a sua força.' },
      { v: 10, en: 'Delilah said to Samson, “Behold, you have mocked me, and told me lies: now please tell me with which you might be bound.”', pt: 'Disse, pois, Dalila a Sansão: Eis que zombaste de mim, e me disseste mentiras; declara-me agora com que poderia ser a amarrado.' },
      { v: 11, en: 'He said to her, “If they only bind me with new ropes with which no work has been done, then shall I become weak, and be as another man.”', pt: 'Respondeu-lhe ele: Se me amarrassem fortemente com cordas novas, que nunca tivessem sido usadas, então me tornaria fraco, e seria como qualquer outro homem.' },
      { v: 12, en: 'So Delilah took new ropes, and bound him therewith, and said to him, “The Philistines are on you, Samson!” The ambush was waiting in the inner room. He broke them off his arms like a thread.', pt: 'Então Dalila tomou cordas novas, e o amarrou com elas, e disse-lhe: Os filisteus vêm sobre ti, Sansão! E os espias estavam sentados na câmara interior. Porém ele as quebrou de seus braços como a um fio.' },
      { v: 13, en: 'Delilah said to Samson, “Until now, you have mocked me and told me lies. Tell me with what you might be bound.” He said to her, “If you weave the seven locks of my head with the web.”', pt: 'Disse Dalila a Sansão: Até agora zombaste de mim, e me disseste mentiras; declara-me pois, agora, com que poderia ser amarrado. E ele lhe disse: Se teceres as sete tranças da minha cabeça com os liços da teia.' },
      { v: 14, en: 'She fastened it with the pin, and said to him, “The Philistines are on you, Samson!” He awakened out of his sleep, and plucked away the pin of the beam, and the web.', pt: 'Assim ela as fixou com o torno de tear, e disse-lhe: Os filisteus vêm sobre ti, Sansão! Então ele despertou do seu sono, e arrancou o torno do tear, juntamente com os liços da teia.' },
      { v: 15, en: 'She said to him, “How can you say, ‘I love you,’ when your heart is not with me? You have mocked me these three times, and have not told me where your great strength lies.”', pt: 'Disse-lhe ela: como podes dizer: Eu te amo! não estando comigo o teu coração? Já três vezes zombaste de mim, e ainda não me declaraste em que consiste a tua força.' },
      { v: 16, en: 'When she pressed him daily with her words, and urged him, his soul was troubled to death.', pt: 'E sucedeu que, importunando-o ela todos os dias com as suas palavras, e molestando-o, a alma dele se angustiou até a morte.' },
      { v: 17, en: 'He told her all his heart, and said to her, “No razor has ever come on my head; for I have been a Nazirite to God from my mother’s womb. If I am shaved, then my strength will go from me, and I will become weak, and be like any other man.”', pt: 'E descobriu-lhe todo o seu coração, e disse-lhe: Nunca passou navalha pela ninha cabeça, porque sou nazireu de Deus desde o ventre de minha mãe; se viesse a ser rapado, ir-se-ia de mim a minha força, e me tornaria fraco, e seria como qualquer outro homem.' },
      { v: 18, en: 'When Delilah saw that he had told her all his heart, she sent and called for the lords of the Philistines, saying, “Come up this once, for he has told me all his heart.” Then the lords of the Philistines came up to her, and brought the money in their hand.', pt: 'Vendo Dalila que ele lhe descobrira todo o seu coração, mandou chamar os chefes dos filisteus, dizendo: Subi ainda esta vez, porque agora me descobriu ele todo o seu coração. E os chefes dos filisteus subiram a ter com ela, trazendo o dinheiro nas maos.' },
      { v: 19, en: 'She made him sleep on her knees; and she called for a man, and shaved off the seven locks of his head; and she began to afflict him, and his strength went from him.', pt: 'Então ela o fez dormir sobre os seus joelhos, e mandou chamar um homem para lhe rapar as sete tranças de sua cabeça. Depois começou a afligi-lo, e a sua força se lhe foi.' },
      { v: 20, en: 'She said, “The Philistines are upon you, Samson!” He awoke out of his sleep, and said, “I will go out as at other times, and shake myself free.” But he didn’t know that Yahweh had departed from him.', pt: 'E disse ela: Os filisteus vêm sobre ti, Sansão! Despertando ele do seu sono, disse: Sairei, como das outras vezes, e me livrarei. Pois ele não sabia que o Senhor se tinha retirado dele.' },
      { v: 21, en: 'The Philistines laid hold on him, and put out his eyes; and they brought him down to Gaza, and bound him with fetters of brass; and he ground at the mill in the prison.', pt: 'Então os filisteus pegaram nele, arrancaram-lhe os olhos e, tendo-o levado a Gaza, amarraram-no com duas cadeias de bronze; e girava moinho no cárcere.' },
      { v: 22, en: 'However the hair of his head began to grow again after he was shaved.', pt: 'Todavia o cabelo da sua cabeça, logo que foi rapado, começou a crescer de novo:' },
      { v: 23, en: 'The lords of the Philistines gathered them together to offer a great sacrifice to Dagon their god, and to rejoice; for they said, “Our god has delivered Samson our enemy into our hand.”', pt: 'Então os chefes dos filisteus se ajuntaram para oferecer um grande sacrifício ao seu deus Dagom, e para se regozijar; pois diziam: Nosso deus nos entregou nas mãos a Sansão, nosso inimigo.' },
      { v: 24, en: 'When the people saw him, they praised their god; for they said, “Our god has delivered our enemy and the destroyer of our country, who has slain many of us, into our hand.”', pt: 'semelhantemente o povo, vendo-o, louvava ao seu deus, dizendo: Nosso Deus nos entregou nas mãos o nosso inimigo, aquele que destruía a nossa terra, e multiplicava os nossos mortos.' },
      { v: 25, en: 'When their hearts were merry, they said, “Call for Samson, that he may entertain us.” They called for Samson out of the prison; and he performed before them. They set him between the pillars;', pt: 'E sucedeu que, alegrando-se o seu coração, disseram: Mandai vir Sansão, para que brinque diante de nós. Mandaram, pois, vir do cárcere Sansão, que brincava diante deles; e fizeram-no estar em pé entre as colunas.' },
      { v: 26, en: 'and Samson said to the boy who held him by the hand, “Allow me to feel the pillars whereupon the house rests, that I may lean on them.”', pt: 'Disse Sansão ao moço que lhe segurava a mão: Deixa-me apalpar as colunas em que se sustém a casa, para que me encoste a elas.' },
      { v: 27, en: 'Now the house was full of men and women; and all the lords of the Philistines were there; and there were on the roof about three thousand men and women, who saw while Samson performed.', pt: 'Ora, a casa estava cheia de homens e mulheres; e também ali estavam todos os chefes dos filisteus, e sobre o telhado havia cerca de três mil homens e mulheres, que estavam vendo Sansão brincar.' },
      { v: 28, en: 'Samson called to Yahweh, and said, “Lord Yahweh, remember me, please, and strengthen me, please, only this once, God, that I may be at once avenged of the Philistines for my two eyes.”', pt: 'Então Sansão clamou ao Senhor, e disse: Ó Senhor Deus! lembra-te de mim, e fortalece-me agora só esta vez, ó Deus, para que duma só vez me vingue dos filisteus pelos meus dois olhos.' },
      { v: 29, en: 'Samson took hold of the two middle pillars on which the house rested, and leaned on them, the one with his right hand, and the other with his left.', pt: 'Abraçou-se, pois, Sansão com as duas colunas do meio, em que se sustinha a casa, arrimando-se numa com a mão direita, e na outra com a esquerda.' },
      { v: 30, en: 'Samson said, “Let me die with the Philistines!” He bowed himself with all his might; and the house fell on the lords, and on all the people who were therein. So the dead that he killed at his death were more than those who he killed in his life.', pt: 'E bradando: Morra eu com os filisteus! inclinou-se com toda a sua força, e a casa caiu sobre os chefes e sobre todo o povo que nela havia. Assim foram mais os que matou ao morrer, do que os que matara em vida.' },
      { v: 31, en: 'Then his brothers and all the house of his father came down, and took him, and brought him up, and buried him between Zorah and Eshtaol in the burial site of Manoah his father. He judged Israel twenty years.', pt: 'Então desceram os seus irmãos e toda a casa de seu pai e, tomando-o, o levaram e o sepultaram, entre Zorá e Estaol, no sepulcro de Manoá, seu pai. Ele havia julgado a Israel vinte anos.' },
    ],
    17: [
      { v: 1, en: 'There was a man of the hill country of Ephraim, whose name was Micah.', pt: 'Havia um homem da região montanhosa de Efraim, cujo nome era Mica.' },
      { v: 2, en: 'He said to his mother, “The eleven hundred pieces of silver that were taken from you, about which you uttered a curse, and also spoke it in my ears, behold, the silver is with me. I took it.” His mother said, “May Yahweh bless my son!”', pt: 'Disse este a sua mãe: As mil e cem moedas de prata que te foram tiradas, por cuja causa lançaste maldições, e acerca das quais também me falaste, eis que esse dinheiro está comigo, eu o tomei. Então disse sua mãe: Bendito do Senhor seja meu filho!' },
      { v: 3, en: 'He restored the eleven hundred pieces of silver to his mother, then his mother said, “I most certainly dedicate the silver to Yahweh from my hand for my son, to make a carved image and a molten image. Now therefore I will restore it to you.”', pt: 'E ele restituiu as mil e cem moedas de prata a sua mãe; porém ela disse: Da minha mão dedico solenemente este dinheiro ao Senhor a favor de meu filho, para fazer uma imagem esculpida e uma de fundição; de sorte que agora to tornarei a dar.' },
      { v: 4, en: 'When he restored the money to his mother, his mother took two hundred pieces of silver, and gave them to a silversmith, who made a carved image and a molten image out of it. It was in the house of Micah.', pt: 'Quando ele restituiu o dinheiro a sua mãe, ela tomou duzentas moedas de prata, e as deu ao ourives, o qual fez delas uma imagem esculpida e uma de fundição, as quais ficaram em casa de Mica.' },
      { v: 5, en: 'The man Micah had a house of gods, and he made an ephod, and teraphim, and consecrated one of his sons, who became his priest.', pt: 'Ora, tinha este homem, Mica, uma casa de deuses; e fez um éfode e terafins, e consagrou um de seus filhos, que lhe serviu de sacerdote.' },
      { v: 6, en: 'In those days there was no king in Israel. Everyone did that which was right in his own eyes.', pt: 'Naquelas dias não havia rei em Israel; cada qual fazia o que parecia bem aos seus olhos.' },
      { v: 7, en: 'There was a young man out of Bethlehem Judah, of the family of Judah, who was a Levite; and he lived there.', pt: 'E havia um mancebo de Belém de Judá, da família de Judá, que era levita, e peregrinava ali.' },
      { v: 8, en: 'The man departed out of the city, out of Bethlehem Judah, to live where he could find a place, and he came to the hill country of Ephraim, to the house of Micah, as he traveled.', pt: 'Este homem partiu da cidade de Belém de Judá para peregrinar onde quer que achasse conveniente. Seguindo ele o seu caminho, chegou à região montanhosa de Efraim, à casa de Mica,' },
      { v: 9, en: 'Micah said to him, “Where did you come from?” He said to him, “I am a Levite of Bethlehem Judah, and I am looking for a place to live.”', pt: 'o qual lhe perguntou: Donde vens? E ele lhe respondeu: Sou levita de Belém de Judá, e vou peregrinar onde achar conveniente.' },
      { v: 10, en: 'Micah said to him, “Dwell with me, and be to me a father and a priest, and I will give you ten pieces of silver per year, a suit of clothing, and your food.” So the Levite went in.', pt: 'Então lhe disse Mica: Fica comigo, e sê-me por pai e sacerdote; e cada ano te darei dez moedas de prata, o vestuário e o sustento. E o levita entrou.' },
      { v: 11, en: 'The Levite was content to dwell with the man; and the young man was to him as one of his sons.', pt: 'Consentiu, pois, o levita em ficar com aquele homem, e lhe foi como um de seus filhos.' },
      { v: 12, en: 'Micah consecrated the Levite, and the young man became his priest, and was in the house of Micah.', pt: 'E Mica consagrou o levita, e o mancebo lhe serviu de sacerdote, e ficou em sua casa.' },
      { v: 13, en: 'Then Micah said, “Now know I that Yahweh will do good to me, since I have a Levite as my priest.”', pt: 'Então disse Mica: Agora sei que o Senhor me fará bem, porquanto tenho um levita por sacerdote.' },
    ],
    18: [
      { v: 1, en: 'In those days there was no king in Israel. In those days the tribe of the Danites sought an inheritance to dwell in; for to that day, their inheritance had not fallen to them among the tribes of Israel.', pt: 'Naqueles dias não havia rei em Israel; a tribo dos danitas buscava para si herança em que habitar; porque até então não lhe havia caído a sua herança entre as tribos de Israel.' },
      { v: 2, en: 'The children of Dan sent five men of their family from their whole number, men of valor, from Zorah, and from Eshtaol, to spy out the land, and to search it. They said to them, “Go, explore the land!” They came to the hill country of Ephraim, to the house of Micah, and lodged there.', pt: 'E de Zorá e Estaol os filhos de Dã enviaram cinco homens da sua tribo, escolhidos dentre todo o povo, homens valorosos, para espiar e reconhecer a terra; e lhes disseram: Ide, reconhecei a terra. E chegaram eles à região montanhosa de Efraim, à casa de Mica, e passaram ali a noite.' },
      { v: 3, en: 'When they were by the house of Micah, they knew the voice of the young man the Levite; so they went over there, and said to him, “Who brought you here? What do you do in this place? What do you have here?”', pt: 'Pois, estando eles perto da casa de Mica, reconheceram a voz do mancebo levita; e, dirigindo-se para lá, lhe perguntaram: Quem te trouxe para cá? que estás fazendo aqui? e que é isto que tens aqui?' },
      { v: 4, en: 'He said to them, “Thus and thus has Micah dealt with me, and he has hired me, and I am become his priest.”', pt: 'E ele lhes respondeu: Assim e assim me tem feito Mica; ele me assalariou, e eu lhe sirvo e sacerdote.' },
      { v: 5, en: 'They said to him, “Please ask counsel of God, that we may know whether our way which we go shall be prosperous.”', pt: 'Então lhe disseram: Consulta a Deus, para que saibamos se será próspero o caminho que seguimos.' },
      { v: 6, en: 'The priest said to them, “Go in peace. Your way in which you go is before Yahweh.”', pt: 'Ao que lhes disse o sacerdote: Ide em paz; perante o Senhor está o caminho que seguis.' },
      { v: 7, en: 'Then the five men departed, and came to Laish, and saw the people who were there, how they lived in safety, in the way of the Sidonians, quiet and secure; for there was no one in the land, possessing authority, that might put them to shame in anything, and they were far from the Sidonians, and had no dealings with anyone else.', pt: 'Então foram-se aqueles cinco homens, e chegando a Laís, viram o povo que havia nela, como vivia em segurança, conforme o costume dos sidônios, quieto e desprecavido; não havia naquela terra falta de coisa alguma; era um povo rico e, estando longe dos sidônios, não tinha relações com ninguém.' },
      { v: 8, en: 'They came to their brothers at Zorah and Eshtaol; and their brothers asked them, “What do you say?”', pt: 'Então voltaram a seus irmãos, em Zorá e Estaol, os quais lhes perguntaram: Que dizeis vós?' },
      { v: 9, en: 'They said, “Arise, and let us go up against them; for we have seen the land, and behold, it is very good. Do you stand still? Don’t be slothful to go and to enter in to possess the land.', pt: 'Eles responderam: Levantai-vos, e subamos contra eles; porque examinamos a terra, e eis que é muito boa. E vós estareis aqui tranqüilos? Não sejais preguiçosos em entrardes para tomar posse desta terra.' },
      { v: 10, en: 'When you go, you will come to an unsuspecting people, and the land is large; for God has given it into your hand, a place where there is no lack of anything that is in the earth.”', pt: 'Quando lá chegardes, achareis um povo desprecavido, e a terra é muito espaçosa; pois Deus vos entregou na mão um lugar em que não há falta de coisa alguma que há na terra.' },
      { v: 11, en: 'The family of the Danites set out from Zorah and Eshtaol, with six hundred men armed with weapons of war.', pt: 'Então seiscentos homens da tribo dos danitas partiram de Zorá e Estaol, munidos de armas de guerra.' },
      { v: 12, en: 'They went up and encamped in Kiriath Jearim, in Judah. Therefore they called that place Mahaneh Dan, to this day. Behold, it is behind Kiriath Jearim.', pt: 'E, tendo subido, acamparam-se em Quiriate-Jearim, em Judá; pelo que esse lugar ficou sendo chamado Maané-Dã, até o dia de hoje; eis que está ao ocidente de Quiriate-Jearim.' },
      { v: 13, en: 'They passed from there to the hill country of Ephraim, and came to the house of Micah.', pt: 'Dali passaram à região montanhosa de Efraim, e chegaram à casa de Mica.' },
      { v: 14, en: 'Then the five men who went to spy out the country of Laish answered, and said to their brothers, “Do you know that there is in these houses an ephod, and teraphim, and a carved image, and a molten image? Now therefore consider what you have to do.”', pt: 'Então os cinco homens que tinham ido espiar a terra de Laís disseram a seus irmãos: Sabeis vós que naquelas casas há um éfode, e terafins, e uma imagem esculpida e uma de fundição? Considerai, pois, agora o que haveis de fazer.' },
      { v: 15, en: 'They went over there, and came to the house of the young Levite man, even to the house of Micah, and asked him how he was doing.', pt: 'Então se dirigiram para lá, e chegaram à casa do mancebo, o levita, à casa de Mica, e o saudaram.' },
      { v: 16, en: 'The six hundred men armed with their weapons of war, who were of the children of Dan, stood by the entrance of the gate.', pt: 'E os seiscentos homens dos danitas, munidos de suas armas de guerra, ficaram à entrada da porta.' },
      { v: 17, en: 'The five men who went to spy out the land went up, and came in there, and took the engraved image, the ephod, the teraphim, and the molten image; and the priest stood by the entrance of the gate with the six hundred men armed with weapons of war.', pt: 'Mas subindo os cinco homens que haviam espiado a terra, entraram ali e tomaram a imagem esculpida, e éfode, os terafins e a imagem de fundição, ficando o sacerdote em pé à entrada da porta, com os seiscentos homens armados.' },
      { v: 18, en: 'When these went into Micah’s house, and took the engraved image, the ephod, the teraphim, and the molten image, the priest said to them, “What are you doing?”', pt: 'Quando eles entraram na casa de Mica, e tomaram a imagem esculpida, o éfode, os terafins e a imagem de fundição, perguntou-lhes o sacerdote: Que estais fazendo?' },
      { v: 19, en: 'They said to him, “Hold your peace, put your hand on your mouth, and go with us, and be to us a father and a priest. Is it better for you to be priest to the house of one man, or to be priest to a tribe and a family in Israel?”', pt: 'E eles lhe responderam: Cala-te, põe a mão sobre a boca, e vem conosco, e sê-nos por pai e sacerdote. Que te é melhor? ser sacerdote da casa dum só homem, ou duma tribo e duma geração em Israel?' },
      { v: 20, en: 'The priest’s heart was glad, and he took the ephod, the teraphim, and the engraved image, and went with the people.', pt: 'Então alegrou-se o coração do sacerdote, o qual tomou o éfode, os terafins e a imagem esculpida, e entrou no meio do povo.' },
      { v: 21, en: 'So they turned and departed, and put the little ones, the livestock, and the goods before them.', pt: 'E, virando-se, partiram, tendo posto diante de si os pequeninos, o gado e a bagagem.' },
      { v: 22, en: 'When they were a good way from the house of Micah, the men who were in the houses near Micah’s house gathered together and overtook the children of Dan.', pt: 'Estando eles já longe da casa de Mica, os homens que estavam nas casas vizinhas à dele se reuniram, e alcançaram os filhos de Dã.' },
      { v: 23, en: 'As they cried to the children of Dan, they turned their faces, and said to Micah, “What ails you, that you come with such a company?”', pt: 'E clamaram após os filhos de Dã, os quais, virando-se, perguntaram a Mica: Que é que tens, visto que vens com tanta gente?' },
      { v: 24, en: 'He said, “You have taken away my gods which I made, and the priest, and have gone away! What more do I have? How can you ask me, ‘What ails you?’”', pt: 'Então ele respondeu: Os meus deuses que eu fiz, vós me tomastes, juntamente com o sarcerdote, e partistes; e agora, que mais me fica? Como, pois, me dizeis: Que é que tens ?' },
      { v: 25, en: 'The children of Dan said to him, “Don’t let your voice be heard among us, lest angry fellows fall on you, and you lose your life, with the lives of your household.”', pt: 'Mas os filhos de Dã lhe disseram: Não faças ouvir a tua voz entre nós, para que porventura homens violentos não se lancem sobre vós, e tu percas a tua vida, e a vida dos da tua casa.' },
      { v: 26, en: 'The children of Dan went their way; and when Micah saw that they were too strong for him, he turned and went back to his house.', pt: 'Assim seguiram o seu caminho os filhos de Dã; e Mica, vendo que eram mais fortes do que ele, virou-se e voltou para sua casa.' },
      { v: 27, en: 'They took that which Micah had made, and the priest whom he had, and came to Laish, to a people quiet and unsuspecting, and struck them with the edge of the sword; then they burned the city with fire.', pt: 'Eles, pois, levaram os objetos que Mica havia feito, e o sacerdote que estava com ele e, chegando a Laís, a um povo quieto e desprecavido, passaram-no ao fio da espada, e puseram fogo à cidade.' },
      { v: 28, en: 'There was no deliverer, because it was far from Sidon, and they had no dealings with anyone else; and it was in the valley that lies by Beth Rehob. They built the city, and lived in it.', pt: 'E ninguém houve que o livrasse, porquanto estava longe de Sidom, e não tinha relações com ninguém; a cidade estava no vale que está junto a Bete-Reobe. Depois, reedificando-a, habitaram nela,' },
      { v: 29, en: 'They called the name of the city Dan, after the name of Dan their father, who was born to Israel; however the name of the city used to be Laish.', pt: 'e chamaram-lhe Dã, segundo o nome de Dã, seu pai, que nascera a Israel; era, porém, dantes o nome desta cidade Laís.' },
      { v: 30, en: 'The children of Dan set up for themselves the engraved image; and Jonathan, the son of Gershom, the son of Moses, and his sons were priests to the tribe of the Danites until the day of the captivity of the land.', pt: 'Depois os filhos de Dã levantaram para si aquela imagem esculpida; e Jônatas, filho de Gérsom, o filho de Moisés, ele e seus filhos foram sacerdotes da tribo dos danitas, até o dia do cativeiro da terra.' },
      { v: 31, en: 'So they set up for themselves Micah’s engraved image which he made, and it remained all the time that God’s house was in Shiloh.', pt: 'Assim, pois, estabeleceram para si a imagem esculpida que Mica fizera, por todo o tempo em que a casa de Deus esteve em Siló.' },
    ],
    19: [
      { v: 1, en: 'In those days, when there was no king in Israel, there was a certain Levite living on the farther side of the hill country of Ephraim, who took for himself a concubine out of Bethlehem Judah.', pt: 'Aconteceu também naqueles dias, quando não havia rei em Israel, que certo levita, habitante das partes remotas da região montanhosa de Efraim, tomou para si uma concubina, de Belém de Judá.' },
      { v: 2, en: 'His concubine played the prostitute against him, and went away from him to her father’s house to Bethlehem Judah, and was there for four months.', pt: 'Ora, a sua concubina adulterou contra ele e, deixando-o, foi para casa de seu pai em Belém de Judá, e ali ficou uns quatro meses.' },
      { v: 3, en: 'Her husband arose, and went after her, to speak kindly to her, to bring her again, having his servant with him, and a couple of donkeys. She brought him into her father’s house; and when the father of the young lady saw him, he rejoiced to meet him.', pt: 'Seu marido, levantando-se, foi atrás dela para lhe falar bondosamente, a fim de tornar a trazê-la; e levava consigo o seu moço e um par de jumentos. Ela o levou à casa de seu pai, o qual, vendo-o, saiu alegremente a encontrar-se com ele.' },
      { v: 4, en: 'His father-in-law, the young lady’s father, kept him there; and he stayed with him three days. So they ate and drank, and stayed there.', pt: 'E seu sogro, o pai da moça, o deteve consigo três dias; assim comeram e beberam, e se alojaram ali.' },
      { v: 5, en: 'On the fourth day, they got up early in the morning, and he rose up to depart. The young lady’s father said to his son-in-law, “Strengthen your heart with a morsel of bread, and afterward you shall go your way.”', pt: 'Ao quarto dia madrugaram, e ele se levantou para partir. Então o pai da moça disse a seu genro: Fortalece-te com um bocado de pão, e depois partireis:' },
      { v: 6, en: 'So they sat down, ate, and drank, both of them together. Then the young lady’s father said to the man, “Please be pleased to stay all night, and let your heart be merry.”', pt: 'Sentando-se, pois, ambos juntos, comeram e beberam; e disse o pai da moça ao homem: Peço-te que fiques ainda esta noite aqui, e alegre-se o teu coração.' },
      { v: 7, en: 'The man rose up to depart; but his father-in-law urged him, and he stayed there again.', pt: 'O homem, porém, levantou-se para partir; mas, como seu sogro insistisse, tornou a passar a noite ali.' },
      { v: 8, en: 'He arose early in the morning on the fifth day to depart; and the young lady’s father said, “Please strengthen your heart and stay until the day declines”; and they both ate.', pt: 'Também ao quinto dia madrugaram para partir; e disse o pai da moça: Ora, conforta o teu coração, e detém-te até o declinar do dia. E ambos juntos comeram.' },
      { v: 9, en: 'When the man rose up to depart, he, and his concubine, and his servant, his father-in-law, the young lady’s father, said to him, “Behold, now the day draws toward evening, please stay all night. Behold, the day is ending. Stay here, that your heart may be merry; and tomorrow go on your way early, that you may go home.”', pt: 'Então o homem se levantou para partir, ele, a sua concubina, e o seu moço; e disse-lhe seu sogro, o pai da moça: Eis que já o dia declina para a tarde; peço-te que aqui passes a noite. O dia já vai acabando; passa aqui a noite, e alegre-se o teu coração: Amanhã de madrugada levanta-te para encetares viagem, e irás para a tua tenda.' },
      { v: 10, en: 'But the man wouldn’t stay that night, but he rose up and departed, and toward Jebus (also called Jerusalem). With him were a couple of saddled donkeys. His concubine also was with him.', pt: 'Entretanto, o homem não quis passar a noite ali, mas, levantando-se, partiu e chegou à altura de Jebus (que é Jerusalém), e com ele o par de jumentos albardados, como também a sua concubina.' },
      { v: 11, en: 'When they were by Jebus, the day was far spent; and the servant said to his master, “Please come and let us enter into this city of the Jebusites, and stay in it.”', pt: 'Quando estavam perto de Jebus, já o dia tinha declinado muito; e disse o moço a seu senhor: Vem, peço-te, retiremo-nos a esta cidade dos jebuseus, e passemos nela a noite.' },
      { v: 12, en: 'His master said to him, “We won’t enter into the city of a foreigner that is not of the children of Israel; but we will pass over to Gibeah.”', pt: 'Respondeu-lhe, porém, o seu senhor: Não nos retiraremos a nenhuma cidade estrangeira, que não seja dos filhos de Israel, mas passaremos até Gibeá.' },
      { v: 13, en: 'He said to his servant, “Come and let us draw near to one of these places; and we will lodge in Gibeah, or in Ramah.”', pt: 'Disse mais a seu moço: Vem, cheguemos a um destes lugares, Gibeá ou Ramá, e passemos ali a noite.' },
      { v: 14, en: 'So they passed on and went their way; and the sun went down on them near Gibeah, which belongs to Benjamin.', pt: 'Passaram, pois, continuando o seu caminho; e o sol se pôs quando estavam perto de Gibeá, que pertence a Benjamim.' },
      { v: 15, en: 'They went over there, to go in to stay in Gibeah. He went in, and sat down in the street of the city; for there was no one who took them into his house to stay.', pt: 'Pelo que se dirigiram para lá, a fim de passarem ali a noite; e o levita, entrando, sentou-se na praça da cidade, porque não houve quem os recolhesse em casa para ali passarem a noite.' },
      { v: 16, en: 'Behold, an old man came from his work out of the field at evening. Now the man was from the hill country of Ephraim, and he lived in Gibeah; but the men of the place were Benjamites.', pt: 'Eis que ao anoitecer vinha do seu trabalho no campo um ancião; era ele da região montanhosa de Efraim, mas habitava em Gibeá; os homens deste lugar, porém, eram benjamitas.' },
      { v: 17, en: 'He lifted up his eyes, and saw the wayfaring man in the street of the city; and the old man said, “Where are you going? Where did you come from?”', pt: 'Levantando ele os olhos, viu na praça da cidade o viajante, e perguntou-lhe: Para onde vais, e donde vens?' },
      { v: 18, en: 'He said to him, “We are passing from Bethlehem Judah to the farther side of the hill country of Ephraim. I am from there, and I went to Bethlehem Judah. I am going to Yahweh’s house; and there is no one who has taken me into his house.', pt: 'Respondeu-lhe ele: Estamos de viagem de Belém de Judá para as partes remotas da região montanhosa de Efraim, donde sou. Fui a Belém de Judá, porém agora vou à casa do Senhor; e ninguem há que me recolha em casa.' },
      { v: 19, en: 'Yet there is both straw and feed for our donkeys; and there is bread and wine also for me, and for your servant, and for the young man who is with your servants. There is no lack of anything.”', pt: 'Todavia temos palha e forragem para os nossos jumentos; também há pão e vinho para mim, para a tua serva, e para o moço que vem com os teus servos; de coisa nenhuma há falta.' },
      { v: 20, en: 'The old man said, “Peace be to you; how ever let me supply all your needs. Just don’t sleep in the street.”', pt: 'Disse-lhe o ancião: Paz seja contigo; tudo quanto te faltar fique ao meu cargo; tão-somente não passes a noite na praça.' },
      { v: 21, en: 'So he brought him into his house, and gave the donkeys fodder. Then they washed their feet, and ate and drank.', pt: 'Assim o fez entrar em sua casa, e deu ração aos jumentos; e, depois de lavarem os pés, comeram e beberam.' },
      { v: 22, en: 'As they were making their hearts merry, behold, the men of the city, certain wicked fellows, surrounded the house, beating at the door; and they spoke to the master of the house, the old man, saying, “Bring out the man who came into your house, that we can have sex with him!”', pt: 'Enquanto eles alegravam o seu coração, eis que os homens daquela cidade, filhos de Belial, cercaram a casa, bateram à porta, e disseram ao ancião, dono da casa: Traze cá para fora o homem que entrou em tua casa, para que o conheçamos.' },
      { v: 23, en: 'The man, the master of the house, went out to them, and said to them, “No, my brothers, please don’t act so wickedly; since this man has come into my house, don’t do this folly.', pt: 'O dono da casa saiu a ter com eles, e disse-lhes: Não, irmãos meus, não façais semelhante mal; já que este homem entrou em minha casa, não façais essa loucura.' },
      { v: 24, en: 'Behold, here is my virgin daughter and his concubine. I will bring them out now. Humble them, and do with them what seems good to you; but to this man don’t do any such folly.”', pt: 'Aqui estão a minha filha virgem e a concubina do homem; fá-las-ei sair; humilhai-as a elas, e fazei delas o que parecer bem aos vossos olhos; porém a este homem não façais tal loucura.' },
      { v: 25, en: 'But the men wouldn’t listen to him: so the man laid hold of his concubine, and brought her out to them; and they had sex with her, and abused her all night until the morning. When the day began to dawn, they let her go.', pt: 'Mas esses homens não o quiseram ouvir; então aquele homem pegou da sua concubina, e lha tirou para fora. Eles a conheceram e abusaram dela a noite toda até pela manhã; e ao subir da alva deixaram-na:' },
      { v: 26, en: 'Then the woman came in the dawning of the day, and fell down at the door of the man’s house where her lord was, until it was light.', pt: 'Ao romper do dia veio a mulher e caiu à porta da casa do homem, onde estava seu senhor, e ficou ali até que se fez claro.' },
      { v: 27, en: 'Her lord rose up in the morning, and opened the doors of the house, and went out to go his way; and behold, the woman his concubine had fallen down at the door of the house, with her hands on the threshold.', pt: 'Levantando-se pela manhã seu senhor, abriu as portas da casa, e ia sair para seguir o seu caminho; e eis que a mulher, sua concubina, jazia à porta da casa, com as mãos sobre o limiar.' },
      { v: 28, en: 'He said to her, “Get up, and let us be going!” but no one answered. Then he took her up on the donkey; and the man rose up, and went to his place.', pt: 'Ele lhe disse: Levanta-te, e vamo-nos; porém ela não respondeu. Então a pôs sobre o jumento e, partindo dali, foi para o seu lugar.' },
      { v: 29, en: 'When he had come into his house, he took a knife, and cut up his concubine, and divided her, limb by limb, into twelve pieces, and sent her throughout all the borders of Israel.', pt: 'Quando chegou em casa, tomou um cutelo e, pegando na sua concubina, a dividiu, membro por membro, em doze pedaços, que ele enviou por todo o território de Israel.' },
      { v: 30, en: 'It was so, that all who saw it said, “Such a deed has not been done or seen from the day that the children of Israel came up out of the land of Egypt to this day! Consider it, take counsel, and speak.”', pt: 'E sucedeu que cada um que via aquilo dizia: Nunca tal coisa se fez, nem se viu, desde o dia em que os filhos de Israel subiram da terra do Egito até o dia de hoje; ponderai isto, consultai, e dai o vosso parecer.' },
    ],
    20: [
      { v: 1, en: 'Then all the children of Israel went out, and the congregation was assembled as one man, from Dan even to Beersheba, with the land of Gilead, to Yahweh at Mizpah.', pt: 'Então saíram todos os filhos de Israel, desde Dã até Berseba, e desde a terra de Gileade, e a congregação, como se fora um só homem, se ajuntou diante do senhor em Mizpá.' },
      { v: 2, en: 'The chiefs of all the people, even of all the tribes of Israel, presented themselves in the assembly of the people of God, four hundred thousand footmen who drew sword.', pt: 'Os homens principais de todo o povo, de todas as tribos de Israel, apresentaram-se na assembléia do povo de Deus; eram quatrocentos mil homens de infantaria que arrancavam da espada.' },
      { v: 3, en: '(Now the children of Benjamin heard that the children of Israel had gone up to Mizpah.) The children of Israel said, “Tell us, how did this wickedness happen?”', pt: '(Ora, ouviram os filhos de Benjamim que os filhos de Israel haviam subido a Mizpá). E disseram os filhos de Israel: Dizei-nos, de que modo se cometeu essa maldade?' },
      { v: 4, en: 'The Levite, the husband of the woman who was murdered, answered, “I came into Gibeah that belongs to Benjamin, I and my concubine, to spend the night.', pt: 'Então respondeu o levita, marido da mulher que fora morta, e disse: Cheguei com a minha concubina a Gibeá, que pertence a Benjamim, para ali passar a noite;' },
      { v: 5, en: 'The men of Gibeah rose against me, and surrounded the house by night. They intended to kill me, and they raped my concubine, and she is dead.', pt: 'e os cidadãos de Gibeá se levantaram contra mim, e cercaram e noite a casa em que eu estava; a mim intentaram matar, e violaram a minha concubina, de maneira que morreu.' },
      { v: 6, en: 'I took my concubine, and cut her in pieces, and sent her throughout all the country of the inheritance of Israel; for they have committed lewdness and folly in Israel.', pt: 'Então peguei na minha concubina, dividi-a em pedaços e os enviei por todo o país da herança de Israel, porquanto cometeram tal abominação e loucura em Israel:' },
      { v: 7, en: 'Behold, you children of Israel, all of you, give here your advice and counsel.”', pt: 'Eis aqui estais todos vós, ó filhos de Israel; dai a vossa palavra e conselho neste caso.' },
      { v: 8, en: 'All the people arose as one man, saying, “None of us will go to his tent, neither will any of us turn to his house.', pt: 'Então todo o povo se levantou como um só homem, dizendo: Nenhum de nós irá à sua tenda, e nenhum de nós voltará a sua casa.' },
      { v: 9, en: 'But now this is the thing which we will do to Gibeah: we will go up against it by lot;', pt: 'Mas isto é o que faremos a Gibeá: subiremos contra ela por sorte;' },
      { v: 10, en: 'and we will take ten men of one hundred throughout all the tribes of Israel, and one hundred of one thousand, and a thousand out of ten thousand, to get food for the people, that they may do, when they come to Gibeah of Benjamin, according to all the folly that they have worked in Israel.”', pt: 'tomaremos, de todas as tribos de Israel, dez homens de cada cem, cem de cada mil, e mil de cada dez mil, para trazerem mantimento para o povo, a fim de que, vindo ele a Gibeá de Benjamim, lhe faça conforme toda a loucura que ela fez em Israel.' },
      { v: 11, en: 'So all the men of Israel were gathered against the city, knit together as one man.', pt: 'Assim se ajuntaram contra essa cidade todos os homens de Israel, unidos como um só homem.' },
      { v: 12, en: 'The tribes of Israel sent men through all the tribe of Benjamin, saying, “What wickedness is this that has happened among you?', pt: 'Então as tribos de Israel enviaram homens por toda a tribo de Benjamim, para lhe dizerem: Que maldade é essa que se fez entre vós?' },
      { v: 13, en: 'Now therefore deliver up the men, the wicked fellows, who are in Gibeah, that we may put them to death, and put away evil from Israel.” But Benjamin would not listen to the voice of their brothers the children of Israel.', pt: 'Entregai-nos, pois, agora aqueles homens, filhos de Belial, que estão em Gibeá, para que os matemos, e extirpemos de Israel este mal. Mas os filhos de Benjamim não quiseram dar ouvidos à voz de seus irmãos, os filhos de Israel;' },
      { v: 14, en: 'The children of Benjamin gathered themselves together out of the cities to Gibeah, to go out to battle against the children of Israel.', pt: 'pelo contrário, das suas cidades se ajuntaram em Gibeá, para saírem a pelejar contra os filhos de Israel:' },
      { v: 15, en: 'The children of Benjamin were counted on that day out of the cities twenty-six thousand men who drew the sword, besides the inhabitants of Gibeah, who were counted seven hundred chosen men.', pt: 'Ora, contaram-se naquele dia dos filhos de Benjamim, vindos das suas cidades, vinte e seis mil homens que arrancavam da espada, afora os moradores de Gibeá, de que se sentaram setecentos homens escolhidos.' },
      { v: 16, en: 'Among all these soldiers there were seven hundred chosen men who were left-handed. Every one of them could sling a stone at a hair and not miss.', pt: 'Entre todo esse povo havia setecentos homens escolhidos, canhotos, cada um dos quais podia, com a funda, atirar uma pedra a um fio de cabelo, sem errar.' },
      { v: 17, en: 'The men of Israel, besides Benjamin, were counted four hundred thousand men who drew sword. All these were men of war.', pt: 'Contaram-se também dos homens de Israel, afora os de Benjamim, quatrocentos mil homens que arrancavam da espada, e todos eles homens de guerra.' },
      { v: 18, en: 'The children of Israel arose, went up to Bethel, and asked counsel of God. They asked, “Who shall go up for us first to battle against the children of Benjamin?” Yahweh said, “Judah first.”', pt: 'Então, levantando-se os filhos de Israel, subiram a Betel, e consultaram a Deus, perguntando: Quem dentre nós subirá primeiro a pelejar contra Benjamim ? Respondeu o Senhor: Judá subirá primeiro.' },
      { v: 19, en: 'The children of Israel rose up in the morning, and encamped against Gibeah.', pt: 'Levantaram-se, pois, os filhos de Israel pela manhã, e acamparam contra Gibeá.' },
      { v: 20, en: 'The men of Israel went out to battle against Benjamin; and the men of Israel set the battle in array against them at Gibeah.', pt: 'E os homens de Israel saíram a pelejar contra os benjamitas, e ordenaram a batalha contra eles ao pé de Gibeá.' },
      { v: 21, en: 'The children of Benjamin came out of Gibeah, and on that day destroyed twenty-two thousand of the Israelite men down to the ground.', pt: 'Então os filhos de Benjamim saíram de Gibeá, e derrubaram por terra naquele dia vinte e dois mil homens de Israel.' },
      { v: 22, en: 'The people, the men of Israel, encouraged themselves, and set the battle again in array in the place where they set themselves in array the first day.', pt: 'Mas esforçou-se o povo, isto é, os homens de Israel, e tornaram a ordenar a batalha no lugar onde no primeiro dia a tinham ordenado.' },
      { v: 23, en: 'The children of Israel went up and wept before Yahweh until evening; and they asked of Yahweh, saying, “Shall I again draw near to battle against the children of Benjamin my brother?” Yahweh said, “Go up against him.”', pt: 'E subiram os filhos de Israel, e choraram perante o Senhor até a tarde, e perguntaram-lhe: Tornaremos a pelejar contra os filhos de Benjamim, nosso irmão? E disse o Senhor: Subi contra eles.' },
      { v: 24, en: 'The children of Israel came near against the children of Benjamin the second day.', pt: 'Avançaram, pois, os filhos de Israel contra os filhos de Benjamim, no dia seguinte.' },
      { v: 25, en: 'Benjamin went out against them out of Gibeah the second day, and destroyed down to the ground of the children of Israel again eighteen thousand men. All these drew the sword.', pt: 'Também os de Benjamim, nesse mesmo dia, saíram de Gibeá ao seu encontro e derrubaram por terra mais dezoito mil homens, sendo todos estes dos que arrancavam da espada.' },
      { v: 26, en: 'Then all the children of Israel, and all the people, went up, and came to Bethel, and wept, and sat there before Yahweh, and fasted that day until evening; then they offered burnt offerings and peace offerings before Yahweh.', pt: 'Então todos os filhos de Israel, o exército todo, subiram e, vindo a Betel, choraram; estiveram ali sentados perante o Senhor, e jejuaram aquele dia até a tarde; e ofereceram holocaustos e ofertas pacíficas perante ao Senhor.' },
      { v: 27, en: 'The children of Israel asked Yahweh (for the ark of the covenant of God was there in those days,', pt: 'Consultaram, pois, os filhos de Israel ao Senhor (porquanto a arca do pacto de Deus estava ali naqueles dias;' },
      { v: 28, en: 'and Phinehas, the son of Eleazar, the son of Aaron, stood before it in those days), saying, “Shall I yet again go out to battle against the children of Benjamin my brother, or shall I cease?” Yahweh said, “Go up; for tomorrow I will deliver him into your hand.”', pt: 'e Finéias, filho de Eleazar, filho de Arão, lhe assistia), e perguntaram: Tornaremos ainda a sair à pelejar contra os filhos de Benjamim, nosso irmão, eu desistiremos? Respondeu o Senhor: Subi, porque amanhã vo-los entregarei nas mãos.' },
      { v: 29, en: 'Israel set ambushes all around Gibeah.', pt: 'Então Israel pôs emboscadas ao redor de Gibeá.' },
      { v: 30, en: 'The children of Israel went up against the children of Benjamin on the third day, and set themselves in array against Gibeah, as at other times.', pt: 'E ao terceiro dia subiram os filhos de Israel contra os filhos de Benjamim e, como das outras vezes, ordenaram a batalha junto a Gibeá.' },
      { v: 31, en: 'The children of Benjamin went out against the people, and were drawn away from the city; and they began to strike and kill of the people, as at other times, in the highways, of which one goes up to Bethel, and the other to Gibeah, in the field, about thirty men of Israel.', pt: 'Então os filhos de Benjamim saíram ao encontro do povo, e foram atraídos da cidade. e começaram a ferir o povo como das outras vezes, matando uns trinta homens de Israel, pelos caminhos, um dos quais sobe para Betel, e o outro para Gibeá pelo campo.' },
      { v: 32, en: 'The children of Benjamin said, “They are struck down before us, as at the first.” But the children of Israel said, “Let us flee, and draw them away from the city to the highways.”', pt: 'Pelo que disseram os filhos de Benjamim: Vão sendo derrotados diante de nós como dantes. Mas os filhos de Israel disseram: Fujamos, e atraiamo-los da cidade para os caminhos.' },
      { v: 33, en: 'All the men of Israel rose up out of their place, and set themselves in array at Baal Tamar. Then the ambushers of Israel broke out of their place, even out of Maareh Geba.', pt: 'Então todos os homens de Israel se levantaram do seu lugar, e ordenaram a batalha em Baal-Tamar; e a emboscada de Israel irrompeu do seu lugar, a oeste de Geba.' },
      { v: 34, en: 'Ten thousand chosen men out of all Israel came over against Gibeah, and the battle was severe; but they didn’t know that disaster was close to them.', pt: 'Vieram contra Gibeá dez mil homens escolhidos de todo o Israel, e a batalha tornou-se rude; porém os de Gibeá não sabiam que o mal lhes sobrevinha.' },
      { v: 35, en: 'Yahweh struck Benjamin before Israel; and the children of Israel destroyed of Benjamin that day twenty-five thousand one hundred men. All these drew the sword.', pt: 'Então o Senhor derrotou a Benjamim diante dos filhos de Israel, que destruíram naquele dia vinte e cinco mil e cem homens de Benjamim, todos estes dos que arrancavam da espada.' },
      { v: 36, en: 'So the children of Benjamin saw that they were struck; for the men of Israel yielded to Benjamin, because they trusted the ambushers whom they had set against Gibeah.', pt: 'Assim os filhos de Benjamim viram que estavam derrotados; pois os homens de Israel haviam cedido terreno aos benjamitas, porquanto estavam confiados na emboscada que haviam posto contra Gibea;' },
      { v: 37, en: 'The ambushers hurried, and rushed on Gibeah; then the ambushers spread out, and struck all the city with the edge of the sword.', pt: 'e a emboscada, apressando-se, acometeu a Gibeá, e prosseguiu contra ela, ferindo ao fio da espada toda a cidade:' },
      { v: 38, en: 'Now the appointed sign between the men of Israel and the ambushers was that they should make a great cloud of smoke rise up out of the city.', pt: 'Ora, os homens de Israel tinham determinado com a emboscada um sinal, que era fazer levantar da cidade uma grande nuvem de fumaça.' },
      { v: 39, en: 'The men of Israel turned in the battle, and Benjamin began to strike and kill of the men of Israel about thirty persons; for they said, “Surely they are struck down before us, as in the first battle.”', pt: 'Viraram-se, pois, os homens de Israel na peleja; e já Benjamim cemeçara a atacar es homens de Israel, havendo morto uns trinta deles; pelo que diziam: Certamente vão sendo derrotados diante de nós, como na primeira batalha.' },
      { v: 40, en: 'But when the cloud began to arise up out of the city in a pillar of smoke, the Benjamites looked behind them; and behold, the whole city went up in smoke to the sky.', pt: 'Mas quando o sinal começou a levantar-se da cidade, numa coluna de fumaça, os benjamitas olharam para trás de si, e eis que toda a cidade subia em fumaça ao céu.' },
      { v: 41, en: 'The men of Israel turned, and the men of Benjamin were dismayed; for they saw that disaster had come on them.', pt: 'Nisso os homens de Israel se viraram contra os de Benjamim, os quais pasmaram, pois viram que o mal lhes sobreviera.' },
      { v: 42, en: 'Therefore they turned their backs before the men of Israel to the way of the wilderness; but the battle followed hard after them; and those who came out of the cities destroyed them in the middle of it.', pt: 'Portanto, virando as costas diante dos homens de Israel, fugiram para o caminho do deserto; porém a peleja os apertou; e os que saíam das cidades os destruíam no meio deles.' },
      { v: 43, en: 'They surrounded the Benjamites, chased them, and trod them down at their resting place, as far as near Gibeah toward the sunrise.', pt: 'Cercaram os benjamitas e os perseguiram, pisando-os desde Noá até a altura de Gibeá para o nascente do sol.' },
      { v: 44, en: 'Eighteen thousand men of Benjamin fell; all these were men of valor.', pt: 'Assim caíram de Benjamim dezoito mil homens, sendo todos estes homens valorosos.' },
      { v: 45, en: 'They turned and fled toward the wilderness to the rock of Rimmon; and they gleaned five thousand men of them in the highways, and followed hard after them to Gidom, and struck two thousand men of them.', pt: 'Então os restantes, virando as costas fugiram para deserto, até a penha de Rimom; mas os filhos de Israel colheram deles pelos caminhos ainda cinco mil homens; e, seguindo-os de perto até Gidom, mataram deles mais dois mil.' },
      { v: 46, en: 'So that all who fell that day of Benjamin were twenty-five thousand men who drew the sword. All these were men of valor.', pt: 'E, todos, os de Benjamim que caíram naquele dia oram vinte e cinco mil homens que arrancavam da espada, todos eles homens valorosos.' },
      { v: 47, en: 'But six hundred men turned and fled toward the wilderness to the rock of Rimmon, and stayed in the rock of Rimmon four months.', pt: 'Mas seiscentos homens viraram as costas e, fugindo para o deserto, para a penha de Rimom, ficaram ali quatro meses.' },
      { v: 48, en: 'The men of Israel turned again on the children of Benjamin, and struck them with the edge of the sword, both the entire city, and the livestock, and all that they found. Moreover all the cities which they found they set on fire.', pt: 'E os homens de Israel voltaram para os filhos de Benjamim, e os passaram ao fio da espada, tanto os homens da cidade como os animais, tudo quanto encontraram; e a todas as cidades que acharam puseram fogo.' },
    ],
    21: [
      { v: 1, en: 'Now the men of Israel had sworn in Mizpah, saying, “None of us will give his daughter to Benjamin as a wife.”', pt: 'Ora, os homens de Israel tinham jurado em Mizpá dizendo: Nenhum de nós dará sua filha por mulher aos benjamitas.' },
      { v: 2, en: 'The people came to Bethel, and sat there until evening before God, and lifted up their voices, and wept severely.', pt: 'Veio, pois, o povo a Betel, e ali ficou sentado até a tarde, diante de Deus; e todos, levantando a voz, fizeram grande pranto,' },
      { v: 3, en: 'They said, “Yahweh, the God of Israel, why has this happened in Israel, that there should be one tribe lacking in Israel today?”', pt: 'e disseram: Ah! Senhor Deus de Israel, por que sucedeu isto, que falte uma tribo em Israel?' },
      { v: 4, en: 'On the next day, the people rose early, and built an altar there, and offered burnt offerings and peace offerings.', pt: 'No dia seguinte o povo levantou-se de manhã cedo, edificou ali um altar e ofereceu holocaustos e ofertas pacíficas.' },
      { v: 5, en: 'The children of Israel said, “Who is there among all the tribes of Israel who didn’t come up in the assembly to Yahweh?” For they had made a great oath concerning him who didn’t come up to Yahweh to Mizpah, saying, “He shall surely be put to death.”', pt: 'E disseram os filhos de Israel: Quem dentre todas as tribos de Israel não subiu à assembléia diante do Senhor? Porque se tinha feito um juramento solene acerca daquele que não subisse ao Senhor em Mizpá, dizendo: Certamente será morto.' },
      { v: 6, en: 'The children of Israel grieved for Benjamin their brother, and said, “There is one tribe cut off from Israel today.', pt: 'E os filhos de Israel tiveram pena de Benjamim, seu irmão, e disseram: Hoje é cortada de Israel uma tribo.' },
      { v: 7, en: 'How shall we provide wives for those who remain, since we have sworn by Yahweh that we will not give them of our daughters to wives?”', pt: 'Como havemos de conseguir mulheres para os que restam deles, desde que juramos pelo Senhor que nenhuma de nossas filhas lhes daríamos por mulher?' },
      { v: 8, en: 'They said, “What one is there of the tribes of Israel who didn’t come up to Yahweh to Mizpah?” Behold, no one came from Jabesh Gilead to the camp to the assembly.', pt: 'Então disseram: Quem é que dentre as tribos de Israel não subiu ao Senhor em Mizpá? E eis que ninguém de Jabes-Gileade viera ao arraial, à assembléia.' },
      { v: 9, en: 'For when the people were counted, behold, there were none of the inhabitants of Jabesh Gilead there.', pt: 'Porquanto, ao contar-se o povo, nenhum dos habitantes de Jabes-Gileade estava ali.' },
      { v: 10, en: 'The congregation sent twelve thousand of the most valiant men there, and commanded them, saying, “Go and strike the inhabitants of Jabesh Gilead with the edge of the sword, with the women and the little ones.', pt: 'Pelo que a congregação enviou para lá doze mil homens dos mais valorosos e lhes ordenou, dizendo: Ide, e passai ao fio da espada os habitantes de Jabes-Gileade, juntamente com as mulheres e os pequeninos.' },
      { v: 11, en: 'This is the thing that you shall do: you shall utterly destroy every male, and every woman who has lain with a man.”', pt: 'Mas isto é o que haveis de fazer: A todo homem e a toda mulher que tiver conhecido homem, totalmente destruireis.' },
      { v: 12, en: 'They found among the inhabitants of Jabesh Gilead four hundred young virgins, who had not known man by lying with him; and they brought them to the camp to Shiloh, which is in the land of Canaan.', pt: 'E acharam entre os moradores de Jabes-Gileade quatrocentas moças virgens, que não tinham conhecido homem, e as trouxeram ao arraial em Siló, que está na terra de Canaã.' },
      { v: 13, en: 'The whole congregation sent and spoke to the children of Benjamin who were in the rock of Rimmon, and proclaimed peace to them.', pt: 'Toda a congregação enviou mensageiros aos filhos de Benjamim, que estavam na penha de Rimom, e lhes proclamou a paz.' },
      { v: 14, en: 'Benjamin returned at that time; and they gave them the women whom they had saved alive of the women of Jabesh Gilead. There still weren’t enough for them.', pt: 'Então voltaram os benjamitas, e os de Israel lhes deram as mulheres que haviam guardado com vida, das mulheres de Jabes-Gileade; porém estas ainda não lhes bastaram.' },
      { v: 15, en: 'The people grieved for Benjamin, because Yahweh had made a breach in the tribes of Israel.', pt: 'E o povo teve pena de Benjamim, porquanto o Senhor tinha aberto uma brecha nas tribos de Israel.' },
      { v: 16, en: 'Then the elders of the congregation said, “How shall we provide wives for those who remain, since the women are destroyed out of Benjamin?”', pt: 'Disseram, pois os anciãos da congregação: Como havemos de conseguir mulheres para os que restam, pois que foram destruídas as mulheres de Benjamim?' },
      { v: 17, en: 'They said, “There must be an inheritance for those who are escaped of Benjamin, that a tribe not be blotted out from Israel.', pt: 'Disseram mais: Deve haver uma herança para os que restam de Benjamim, para que uma tribo não seja apagada de Israel.' },
      { v: 18, en: 'However we may not give them wives of our daughters, for the children of Israel had sworn, saying, ‘Cursed is he who gives a wife to Benjamin.’”', pt: 'Contudo nós não lhes poderemos dar mulheres dentre nossas filhas. Pois os filhos de Israel tinham jurado, dizendo: Maldito aquele que der mulher aos benjamitas.' },
      { v: 19, en: 'They said, “Behold, there is a feast of Yahweh from year to year in Shiloh, which is on the north of Bethel, on the east side of the highway that goes up from Bethel to Shechem, and on the south of Lebonah.”', pt: 'Disseram então: Eis que de ano em ano se realiza a festa do Senhor em Siló que está ao norte de Betel, a leste do caminho que sobe de Betel a Siquém, e ao sul de Lebona.' },
      { v: 20, en: 'They commanded the children of Benjamin, saying, “Go and lie in wait in the vineyards,', pt: 'Ordenaram, pois, aos filhos de Benjamim, dizendo: Ide, ponde-vos de emboscada nas vinhas,' },
      { v: 21, en: 'and see, and behold, if the daughters of Shiloh come out to dance in the dances, then come out of the vineyards, and each man catch his wife of the daughters of Shiloh, and go to the land of Benjamin.', pt: 'e vigiai; ao saírem as filhas de Siló a dançar nos coros, saí vós das vinhas, arrebatai cada um sua mulher, das filhas de Siló, e ide-vos para a terra de Benjamim.' },
      { v: 22, en: 'It shall be, when their fathers or their brothers come to complain to us, that we will say to them, ‘Grant them graciously to us, because we didn’t take for each man his wife in battle, neither did you give them to them, otherwise you would now be guilty.’”', pt: 'Então quando seus pais e seus irmãos vierem queixar-se a nós, nós lhes diremos: Dignai-vos de no-las conceder; pois nesta guerra não tomamos mulheres para cada um deles, nem vós lhas destes; de outro modo seríeis agora culpados.' },
      { v: 23, en: 'The children of Benjamin did so, and took wives for themselves, according to their number, of those who danced, whom they carried off. They went and returned to their inheritance, built the cities, and lived in them.', pt: 'Assim fizeram os filhos de Benjamim; e conforme o seu número tomaram para si mulheres, arrebatando-as dentre as que dançavam; e, retirando-se, voltaram à sua herança, reedificaram as cidades e habitaram nelas.' },
      { v: 24, en: 'The children of Israel departed from there at that time, every man to his tribe and to his family, and they each went out from there to his own inheritance.', pt: 'Nesse mesmo tempo os filhos de Israel partiram dali, cada um para a sua tribo e para a sua família; assim voltaram cada um para a sua herança.' },
      { v: 25, en: 'In those days there was no king in Israel. Everyone did that which was right in his own eyes.', pt: 'Naqueles dias não havia rei em Israel; cada um fazia o que parecia bem aos seus olhos.' },
    ],
  },
};

export default book;
